"use client";

import React, { useState, useRef } from 'react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from '@/components/ui/card';
import { Settings, Brush, Database, AlertTriangle, Loader2, Trash2, ShieldOff, Boxes, Factory, LogOut, History, Download, Upload } from 'lucide-react';
import { Separator } from '@/components/ui/separator';
import { ThemeToggler } from '@/components/ThemeToggler';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { db } from '@/lib/firebase';
import { initialOperators, initialDepartmentMap, initialWorkPhaseTemplates, initialWorkstations } from '@/lib/mock-data';
import { collection, writeBatch, getDocs, doc } from 'firebase/firestore';
import { resetAllJobOrders, resetAllRawMaterials, resetRawMaterialHistory, resetAllPrivacySignatures, resetAllWithdrawals, resetAllWorkInProgress, resetAllActiveSessions, backupAllData, restoreDataFromBackup } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';


// Helper function to trigger a global logout for all clients
function triggerGlobalLogout() {
  const timestamp = Date.now().toString();
  
  // Clear all session keys from localStorage
  Object.keys(localStorage).forEach(key => {
    if (key.startsWith('prodtime_tracker_active_material_sessions_') || key.startsWith('prodtime_tracker_active_job_id_')) {
      localStorage.removeItem(key);
    }
  });
  
  // Use a BroadcastChannel to notify other tabs of the same origin
  const channel = new BroadcastChannel('auth_channel');
  channel.postMessage({ type: 'FORCE_LOGOUT', timestamp });
  channel.close();
}


export default function AdminAppSettingsPage() {
  const { user } = useAuth();
  const [isSeeding, setIsSeeding] = useState(false);
  const [isResettingJobs, setIsResettingJobs] = useState(false);
  const [isResettingMaterials, setIsResettingMaterials] = useState(false);
  const [isResettingMaterialHistory, setIsResettingMaterialHistory] = useState(false);
  const [isResettingPrivacy, setIsResettingPrivacy] = useState(false);
  const [isResettingWithdrawals, setIsResettingWithdrawals] = useState(false);
  const [isResettingWork, setIsResettingWork] = useState(false);
  const [isResettingSessions, setIsResettingSessions] = useState(false);
  const [isBackingUp, setIsBackingUp] = useState(false);
  const [isRestoring, setIsRestoring] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const { toast } = useToast();

  const handleSeedDatabase = async () => {
    setIsSeeding(true);
    const seedDatabaseClientSide = async (): Promise<{ success: boolean; message: string; }> => {
      try {
        const operatorsRef = collection(db, "operators");
        const operatorsSnap = await getDocs(operatorsRef);
        
        if (!operatorsSnap.empty) {
            return { success: false, message: 'Il database sembra essere gi├á popolato. Nessuna operazione eseguita.' };
        }
        
        const batch = writeBatch(db);
        let totalOperations = 0;

        initialOperators.forEach(op => {
            const docRef = doc(db, "operators", op.id);
            batch.set(docRef, op);
            totalOperations++;
        });

        const departmentMapDocRef = doc(db, "configuration", "departmentMap");
        batch.set(departmentMapDocRef, initialDepartmentMap);
        totalOperations++;

        initialWorkPhaseTemplates.forEach(phase => {
            const docRef = doc(db, "workPhaseTemplates", phase.id);
            batch.set(docRef, phase);
            totalOperations++;
        });

        initialWorkstations.forEach(ws => {
            const docRef = doc(db, "workstations", ws.id);
            batch.set(docRef, ws);
            totalOperations++;
        });
        
        await batch.commit();
        return { success: true, message: `Database popolato con successo con ${totalOperations} documenti.` };

      } catch (error) {
        const errorMessage = error instanceof Error ? error.message : String(error);
        console.error("Errore nel seeding del database:", error);
        let userFriendlyMessage = `Si ├¿ verificato un errore: ${errorMessage}`;
        if (errorMessage.toLowerCase().includes('permission-denied') || errorMessage.toLowerCase().includes('insufficient permissions')) {
          userFriendlyMessage = "Errore di permessi. Assicurati che le regole di sicurezza di Firestore permettano la scrittura. Per lo sviluppo, puoi impostarle temporaneamente su 'allow read, write: if true;' nella console di Firebase.";
        }
        return { success: false, message: userFriendlyMessage };
      }
    };
    
    const result = await seedDatabaseClientSide();
      toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
        duration: result.success ? 5000 : 9000,
      });
    setIsSeeding(false);
  }

  const handleBackup = async () => {
    setIsBackingUp(true);
    toast({ title: "Avvio del Backup", description: "Preparazione dei dati in corso..." });
    const result = await backupAllData();

    if (result.success && result.data) {
        try {
            const jsonString = `data:text/json;charset=utf-8,${encodeURIComponent(JSON.stringify(result.data, null, 2))}`;
            const link = document.createElement("a");
            link.href = jsonString;
            link.download = `pfxcan_backup_${new Date().toISOString().split('T')[0]}.json`;
            link.click();
            toast({ title: "Backup Completato", description: "Il file di backup ├¿ stato scaricato." });
        } catch (e) {
            toast({ variant: "destructive", title: "Errore Download", description: "Impossibile creare il file di backup da scaricare." });
        }
    } else {
        toast({ variant: "destructive", title: "Backup Fallito", description: result.message });
    }
    setIsBackingUp(false);
  };

  const handleRestoreTrigger = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (e) => {
        const content = e.target?.result;
        if (typeof content === 'string') {
            setIsRestoring(true);
            if (!user) {
              setIsRestoring(false);
              return;
            };
            toast({ title: 'Ripristino in corso', description: 'Cancellazione dei dati attuali...' });
            const result = await restoreDataFromBackup(content, user.uid);
            toast({
                title: result.success ? "Ripristino Completato" : "Ripristino Fallito",
                description: result.message,
                variant: result.success ? "default" : "destructive",
            });
            if (result.success) {
                triggerGlobalLogout();
                toast({ title: 'Logout Forzato', description: 'Tutti gli utenti verranno disconnessi per applicare le modifiche.', variant: 'default' });
            }
            setIsRestoring(false);
        }
    };
    reader.readAsText(file);
    event.target.value = ''; // Reset input
  };

  const handleResetJobOrders = async () => {
    if (!user) return;
    setIsResettingJobs(true);
    const result = await resetAllJobOrders(user.uid);
    toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      triggerGlobalLogout();
      toast({ title: 'Logout Forzato', description: 'Tutti gli utenti verranno disconnessi per applicare le modifiche.', variant: 'default' });
    }
    setIsResettingJobs(false);
  };

  const handleResetRawMaterials = async () => {
    if (!user) return;
    setIsResettingMaterials(true);
    const result = await resetAllRawMaterials(user.uid);
    toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
      if (result.success) {
      triggerGlobalLogout();
      toast({ title: 'Logout Forzato', description: 'Tutti gli utenti verranno disconnessi per applicare le modifiche.', variant: 'default' });
    }
    setIsResettingMaterials(false);
  };
  
  const handleResetMaterialHistory = async () => {
    if (!user) return;
    setIsResettingMaterialHistory(true);
    const result = await resetRawMaterialHistory(user.uid);
    toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    setIsResettingMaterialHistory(false);
  };

  const handleResetWithdrawals = async () => {
    if (!user) return;
    setIsResettingWithdrawals(true);
    const result = await resetAllWithdrawals(user.uid);
    toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    setIsResettingWithdrawals(false);
  };

  const handleResetPrivacy = async () => {
    if (!user) return;
    setIsResettingPrivacy(true);
    const result = await resetAllPrivacySignatures(user.uid);
    toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    setIsResettingPrivacy(false);
  };

  const handleResetWork = async () => {
    if (!user) return;
    setIsResettingWork(true);
    const result = await resetAllWorkInProgress(user.uid);
    toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      triggerGlobalLogout();
      toast({ title: 'Logout Forzato', description: 'Tutti gli utenti verranno disconnessi per applicare le modifiche.', variant: 'default' });
    }
    setIsResettingWork(false);
  };
  
  const handleResetSessions = async () => {
    if (!user) return;
    setIsResettingSessions(true);
    const result = await resetAllActiveSessions(user.uid);
    toast({
        title: result.success ? "Operazione Completata" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      triggerGlobalLogout();
      toast({ title: 'Logout Forzato', description: 'Tutti gli operatori (escluso l\'admin) verranno disconnessi per resettare le loro sessioni attive.', variant: 'default' });
    }
    setIsResettingSessions(false);
  };

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-8">
            <header className="space-y-2">
                <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                    <Settings className="h-8 w-8 text-primary" />
                    Gestione App
                </h1>
                <p className="text-muted-foreground">
                    Personalizzazione dell'aspetto, del tema e dei dati iniziali dell'applicazione.
                </p>
            </header>
            
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
              <Card className="lg:col-span-1">
                  <CardHeader>
                          <CardTitle className="flex items-center gap-2">
                          <Brush className="h-6 w-6 text-primary" />
                          Personalizzazione Tema
                      </CardTitle>
                      <CardDescription>
                          Scegli il tema dell'applicazione. Puoi cambiarlo in qualsiasi momento usando il pulsante in basso a destra.
                      </CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-6">
                      <div>
                              <Label>Tema Attuale</Label>
                              <p className="text-sm text-muted-foreground">
                              L'applicazione supporta un tema chiaro e uno scuro. Usa il selettore per cambiare l'aspetto.
                              </p>
                              <div className="mt-4">
                              <ThemeToggler />
                              </div>
                      </div>
                      <Separator />
                      <div>
                          <Label>Anteprima Colori Principali</Label>
                          <div className="flex space-x-4 mt-2">
                              <div className="flex flex-col items-center">
                                  <div className="w-10 h-10 rounded-full bg-primary border-2 border-border"></div>
                                  <span className="text-xs mt-1">Primary</span>
                              </div>
                                  <div className="flex flex-col items-center">
                                  <div className="w-10 h-10 rounded-full bg-secondary border-2 border-border"></div>
                                  <span className="text-xs mt-1">Secondary</span>
                              </div>
                              <div className="flex flex-col items-center">
                                  <div className="w-10 h-10 rounded-full bg-accent border-2 border-border"></div>
                                  <span className="text-xs mt-1">Accent</span>
                              </div>
                              <div className="flex flex-col items-center">
                                  <div className="w-10 h-10 rounded-full bg-destructive border-2 border-border"></div>
                                  <span className="text-xs mt-1">Destructive</span>
                              </div>
                          </div>
                      </div>
                  </CardContent>
              </Card>

              <div className="lg:col-span-2 space-y-8">
                <Card>
                    <CardHeader>
                        <CardTitle className="flex items-center gap-2">
                            <Database className="h-6 w-6 text-primary" />
                            Gestione Dati Applicazione
                        </CardTitle>
                        <CardDescription>
                            Azioni di popolamento, backup e ripristino del database.
                        </CardDescription>
                    </CardHeader>
                    <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-2 p-4 rounded-lg border">
                         <h4 className="font-semibold flex items-center gap-2"><Database className="h-5 w-5"/> Popolamento Iniziale</h4>
                         <p className="text-sm text-muted-foreground">Aggiunge dati di esempio solo se il database ├¿ vuoto.</p>
                        <AlertDialog>
                          <AlertDialogTrigger asChild>
                             <Button variant="outline" className="w-full" disabled={isSeeding}>
                              {isSeeding ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                              Popola Database Iniziale
                            </Button>
                          </AlertDialogTrigger>
                          <AlertDialogContent>
                            <AlertDialogHeader>
                              <AlertDialogTitle>Confermi di voler procedere?</AlertDialogTitle>
                              <AlertDialogDescription>
                                Verranno aggiunti i dati di esempio al tuo database Firestore. Questa operazione ├¿ consigliata solo al primo avvio o dopo un reset completo del database.
                              </AlertDialogDescription>
                            </AlertDialogHeader>
                            <AlertDialogFooter>
                              <AlertDialogCancel>Annulla</AlertDialogCancel>
                              <AlertDialogAction onClick={handleSeedDatabase} disabled={isSeeding}>
                                {isSeeding ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                                S├¼, popola il database
                              </AlertDialogAction>
                            </AlertDialogFooter>
                          </AlertDialogContent>
                        </AlertDialog>
                      </div>

                      <div className="space-y-2 p-4 rounded-lg border">
                          <h4 className="font-semibold flex items-center gap-2"><Download className="h-5 w-5"/> Backup Completo</h4>
                          <p className="text-sm text-muted-foreground">Scarica un file JSON con tutti i dati principali dell'app.</p>
                          <Button onClick={handleBackup} disabled={isBackingUp} className="w-full">
                           {isBackingUp ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                            Esegui Backup
                          </Button>
                      </div>
                       <div className="space-y-2 p-4 rounded-lg border md:col-span-2 border-yellow-500/50 bg-yellow-500/10">
                          <h4 className="font-semibold flex items-center gap-2 text-yellow-700 dark:text-yellow-400"><Upload className="h-5 w-5"/> Ripristino da Backup</h4>
                          <p className="text-sm text-yellow-600 dark:text-yellow-300">Carica un file JSON di backup. <span className="font-bold">Attenzione:</span> tutti i dati attuali verranno eliminati e sostituiti.</p>
                           <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button variant="outline" className="w-full border-yellow-500/50 hover:bg-yellow-500/20 text-yellow-700 dark:text-yellow-400" disabled={isRestoring}>
                                {isRestoring ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                                Ripristina da Backup
                              </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                                <AlertDialogHeader>
                                    <AlertDialogTitle>Sei assolutamente sicuro?</AlertDialogTitle>
                                    <AlertDialogDescription>
                                        Questa azione ├¿ irreversibile. Tutti i dati correnti verranno eliminati e sostituiti con i dati del file di backup. Vuoi procedere?
                                    </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                    <AlertDialogCancel>Annulla</AlertDialogCancel>
                                    <AlertDialogAction onClick={handleRestoreTrigger} disabled={isRestoring}>
                                        {isRestoring ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                                        S├¼, procedi al ripristino
                                    </AlertDialogAction>
                                </AlertDialogFooter>
                            </AlertDialogContent>
                           </AlertDialog>
                          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
                      </div>
                    </CardContent>
                </Card>
              </div>

            </div>
            
            <div className="mt-8">
              <Card className="border-destructive">
                  <CardHeader>
                      <CardTitle className="flex items-center gap-2 text-destructive">
                          <AlertTriangle className="h-6 w-6" />
                          Zona Pericolosa
                      </CardTitle>
                      <CardDescription>
                          Queste operazioni sono irreversibili. Procedere con la massima cautela.
                      </CardDescription>
                  </CardHeader>
                  <CardContent>
                      <Tabs defaultValue="reset-state" className="w-full">
                          <TabsList className="grid w-full grid-cols-3">
                              <TabsTrigger value="reset-state">Reset Stato</TabsTrigger>
                              <TabsTrigger value="reset-data">Reset Dati</TabsTrigger>
                              <TabsTrigger value="reset-total">Reset Totale</TabsTrigger>
                          </TabsList>
                          <TabsContent value="reset-state" className="pt-6 space-y-4">
                              {/* Reset Sessioni Attive */}
                              <div className="flex justify-between items-center p-4 border rounded-md">
                                  <div>
                                      <h4 className="font-semibold">Reset Sessioni Attive</h4>
                                      <p className="text-sm text-muted-foreground">Forza un logout per tutti gli operatori per pulire le loro sessioni locali.</p>
                                  </div>
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild><Button variant="destructive" disabled={isResettingSessions}>{isResettingSessions ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <LogOut className="mr-2 h-4 w-4" />}Resetta Sessioni</Button></AlertDialogTrigger>
                                      <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>Questa azione disconnetter├á tutti gli operatori. Utile per risolvere sessioni bloccate.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleResetSessions} className="bg-destructive hover:bg-destructive/90">S├¼, resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                  </AlertDialog>
                              </div>
                              {/* Reset Tutte le Lavorazioni */}
                              <div className="flex justify-between items-center p-4 border rounded-md">
                                  <div>
                                      <h4 className="font-semibold">Reset Lavorazioni in Corso</h4>
                                      <p className="text-sm text-muted-foreground">Riporta tutte le commesse in produzione allo stato di "pianificata".</p>
                                  </div>
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild><Button variant="destructive" disabled={isResettingWork}>{isResettingWork ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Factory className="mr-2 h-4 w-4" />}Resetta Lavorazioni</Button></AlertDialogTrigger>
                                      <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>L'avanzamento delle commesse in produzione verr├á azzerato.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleResetWork} className="bg-destructive hover:bg-destructive/90">S├¼, resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                  </AlertDialog>
                              </div>
                              {/* Reset Firme Privacy */}
                              <div className="flex justify-between items-center p-4 border rounded-md">
                                  <div>
                                      <h4 className="font-semibold">Reset Firme Privacy</h4>
                                      <p className="text-sm text-muted-foreground">Annulla l'accettazione della privacy per tutti gli operatori.</p>
                                  </div>
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild><Button variant="destructive" disabled={isResettingPrivacy}>{isResettingPrivacy ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <ShieldOff className="mr-2 h-4 w-4" />}Resetta Firme</Button></AlertDialogTrigger>
                                      <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>Tutti gli operatori dovranno ri-accettare l'informativa al prossimo accesso.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleResetPrivacy} className="bg-destructive hover:bg-destructive/90">S├¼, resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                  </AlertDialog>
                              </div>
                          </TabsContent>
                          <TabsContent value="reset-data" className="pt-6 space-y-4">
                              {/* Reset Prelievi da Magazzino */}
                              <div className="flex justify-between items-center p-4 border rounded-md">
                                  <div>
                                      <h4 className="font-semibold">Reset Prelievi da Magazzino</h4>
                                      <p className="text-sm text-muted-foreground">Elimina tutti i report dei prelievi di materiale e ripristina lo stock.</p>
                                  </div>
                                   <AlertDialog>
                                      <AlertDialogTrigger asChild><Button variant="destructive" disabled={isResettingWithdrawals}>{isResettingWithdrawals ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Boxes className="mr-2 h-4 w-4" />}Resetta Prelievi</Button></AlertDialogTrigger>
                                      <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>TUTTI i report di prelievo verranno eliminati e lo stock ripristinato.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleResetWithdrawals} className="bg-destructive hover:bg-destructive/90">S├¼, resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                  </AlertDialog>
                              </div>
                              {/* Reset Storico Materiali */}
                              <div className="flex justify-between items-center p-4 border rounded-md">
                                  <div>
                                      <h4 className="font-semibold">Reset Storico Materiali</h4>
                                      <p className="text-sm text-muted-foreground">Elimina lotti e prelievi, azzerando lo stock ma mantenendo l'anagrafica.</p>
                                  </div>
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild><Button variant="destructive" disabled={isResettingMaterialHistory}>{isResettingMaterialHistory ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <History className="mr-2 h-4 w-4" />}Resetta Storico</Button></AlertDialogTrigger>
                                      <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>Verranno eliminati TUTTI i lotti e i prelievi. Lo stock verr├á azzerato.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleResetMaterialHistory} className="bg-destructive hover:bg-destructive/90">S├¼, resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                  </AlertDialog>
                              </div>
                          </TabsContent>
                          <TabsContent value="reset-total" className="pt-6 space-y-4">
                              {/* Reset Tutte le Commesse */}
                              <div className="flex justify-between items-center p-4 border rounded-md">
                                  <div>
                                      <h4 className="font-semibold">Reset Tutte le Commesse</h4>
                                      <p className="text-sm text-muted-foreground">Elimina TUTTE le commesse (pianificate, produzione, sospese) e i prelievi associati.</p>
                                  </div>
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild><Button variant="destructive" disabled={isResettingJobs}>{isResettingJobs ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Trash2 className="mr-2 h-4 w-4" />}Resetta Commesse</Button></AlertDialogTrigger>
                                      <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>Verranno eliminate TUTTE le commesse (escluse quelle gi├á completate) e i prelievi.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleResetJobOrders} className="bg-destructive hover:bg-destructive/90">S├¼, elimina</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                  </AlertDialog>
                              </div>
                              {/* Reset Anagrafica Materie Prime */}
                              <div className="flex justify-between items-center p-4 border rounded-md">
                                  <div>
                                      <h4 className="font-semibold">Reset Anagrafica Materie Prime</h4>
                                      <p className="text-sm text-muted-foreground">Elimina TUTTA l'anagrafica delle materie prime, i lotti e i prelievi.</p>
                                  </div>
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild><Button variant="destructive" disabled={isResettingMaterials}>{isResettingMaterials ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Trash2 className="mr-2 h-4 w-4" />}Resetta Anagrafica</Button></AlertDialogTrigger>
                                      <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>Azione irreversibile. Verranno eliminate TUTTE le materie prime.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleResetRawMaterials} className="bg-destructive hover:bg-destructive/90">S├¼, elimina tutto</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                  </AlertDialog>
                              </div>
                          </TabsContent>
                      </Tabs>
                  </CardContent>
              </Card>
            </div>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useMemo, useEffect, useRef } from 'react';
import * as XLSX from 'xlsx';
import { useToast } from '@/hooks/use-toast';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { ClipboardList, PlusCircle, Search, Trash2, Edit, Upload, Loader2, BarChart3, Copy, XCircle, RefreshCcw, Timer, FileEdit, Save, FileSpreadsheet } from 'lucide-react';
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter
} from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import type { Article, RawMaterial, WorkPhaseTemplate } from '@/lib/mock-data';
import ArticleFormDialog from './ArticleFormDialog';
import ArticleTimesDialog from './ArticleTimesDialog';
import { deleteArticle, validateArticlesImport, bulkSaveArticles, validateArticleSettingsImport, bulkUpdateArticleSettings } from './actions';
import { useRouter, useSearchParams } from 'next/navigation';
import { getWorkPhaseTemplates } from '../work-phase-management/actions';

interface ArticleManagementClientPageProps {
  initialArticles: Article[];
  rawMaterials: RawMaterial[];
}

export default function ArticleManagementClientPage({ initialArticles, rawMaterials }: ArticleManagementClientPageProps) {
  const router = useRouter();
  const searchParams = useSearchParams();
  const articleCodeFromUrl = searchParams.get('code');

  const [searchTerm, setSearchTerm] = useState(articleCodeFromUrl || '');
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isTimesOpen, setIsTimesOpen] = useState(false);
  const [editingArticle, setEditingArticle] = useState<Article | null>(null);
  const [phaseTemplates, setPhaseTemplates] = useState<WorkPhaseTemplate[]>([]);
  const [isImporting, setIsImporting] = useState(false);
  const [isImportingSettings, setIsImportingSettings] = useState(false);
  const [isSavingBulk, setIsSavingBulk] = useState(false);

  const [importReport, setImportReport] = useState<{
    newArticles: Omit<Article, 'id'>[];
    updatedArticles: Omit<Article, 'id'>[];
    invalidArticles: { code: string; errors: string[] }[];
  } | null>(null);

  const [settingsReport, setSettingsReport] = useState<{
    validUpdates: Partial<Article>[];
    invalidRows: { code: string; reason: string }[];
  } | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const settingsInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();

  useEffect(() => {
    if (articleCodeFromUrl) {
      setSearchTerm(articleCodeFromUrl);
    }
    getWorkPhaseTemplates().then(setPhaseTemplates);
  }, [articleCodeFromUrl]);

  const filteredArticles = useMemo(() => {
    if (!searchTerm) {
      return initialArticles;
    }
    const lowercasedFilter = searchTerm.toLowerCase();
    return initialArticles.filter(article =>
      article.code.toLowerCase().includes(lowercasedFilter)
    );
  }, [initialArticles, searchTerm]);

  const handleOpenForm = (article: Article | null) => {
    setEditingArticle(article);
    setIsFormOpen(true);
  };

  const handleOpenTimes = (article: Article) => {
    setEditingArticle(article);
    setIsTimesOpen(true);
  };

  const handleFormClose = (refresh: boolean = false) => {
    setIsFormOpen(false);
    setEditingArticle(null);
    if (refresh) router.refresh();
  }

  const handleTimesClose = (refresh: boolean = false) => {
    setIsTimesOpen(false);
    setEditingArticle(null);
    if (refresh) router.refresh();
  };

  const handleDelete = async (articleId: string) => {
    const result = await deleteArticle(articleId);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      router.refresh();
    }
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    toast({ title: 'Analisi File...', description: 'Lettura dei dati in corso.' });

    try {
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data, { type: 'array' });
      const worksheet = workbook.Sheets[workbook.SheetNames[0]];
      const json: any[] = XLSX.utils.sheet_to_json(worksheet);

      const articlesMap: { [code: string]: Omit<Article, 'id'> } = {};

      for (const row of json) {
        const articleCode = String(row['Codice Articolo'] || row['codice articolo'] || '').trim();
        const component = String(row['Componente'] || row['componente'] || '').trim();
        const quantity = Number(row['Quantit├á per Pz'] || row['Quantit├á'] || row['quantit├á'] || 0);

        if (!articleCode || !component) continue;

        if (!articlesMap[articleCode]) {
          articlesMap[articleCode] = { code: articleCode, billOfMaterials: [] };
        }

        const unit = String(row['Unit├á di Misura'] || row['unit├á di misura'] || 'n').toLowerCase() as 'n' | 'mt' | 'kg';
        const lunghezzaTaglio = row['Lunghezza Taglio (mm)'] || row['lunghezza taglio (mm)'] || row['Numero/Misura'];

        const bomItem: any = { component: component.split(' ')[0], unit, quantity: quantity };

        if (lunghezzaTaglio) {
          const parsedLength = parseFloat(String(lunghezzaTaglio));
          if (!isNaN(parsedLength) && parsedLength > 0) bomItem.lunghezzaTaglioMm = parsedLength;
          else if (typeof lunghezzaTaglio === 'string' && lunghezzaTaglio.trim() !== '') bomItem.note = String(lunghezzaTaglio);
        }

        articlesMap[articleCode].billOfMaterials.push(bomItem);
      }

      const report = await validateArticlesImport(Object.values(articlesMap));
      setImportReport(report);

    } catch (error) {
      toast({ variant: "destructive", title: "Errore File", description: "Impossibile leggere il file Excel." });
    } finally {
      setIsImporting(false);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  const handleSettingsFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsImportingSettings(true);
    toast({ title: 'Analisi Impostazioni...', description: 'Verifica cicli e tempi.' });

    try {
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data, { type: 'array' });
      const worksheet = workbook.Sheets[workbook.SheetNames[0]];
      const json: any[] = XLSX.utils.sheet_to_json(worksheet, { raw: true });

      const report = await validateArticleSettingsImport(json);
      setSettingsReport(report);
    } catch (error) {
      toast({ variant: "destructive", title: "Errore File", description: "Impossibile processare il file." });
    } finally {
      setIsImportingSettings(false);
      if (settingsInputRef.current) settingsInputRef.current.value = "";
    }
  };

  const handleDownloadSettingsTemplate = () => {
    const templateData = [
      {
        "CODICE ARTICOLO": "ESEMPIO-01",
        "CICLO PREDEFINITO": "Ciclo Standard",
        "TEMPO PREVISTO CICLO PREDEFINITO": 10.5,
        "CICLO SECONDARIO": "Ciclo Alternativo",
        "TEMPO PREVISTO CICLO SECONDARIO": 12.0
      }
    ];

    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Template Cicli e Tempi");
    XLSX.writeFile(wb, "template_cicli_tempi.xlsx");
    toast({ title: "Template Scaricato" });
  };

  const handleConfirmImport = async () => {
    if (!importReport) return;
    const allValid = [...importReport.newArticles, ...importReport.updatedArticles];
    if (allValid.length === 0) return;

    setIsSavingBulk(true);
    const result = await bulkSaveArticles(allValid);
    toast({ title: result.success ? "Importazione Completata" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) {
      setImportReport(null);
      router.refresh();
    }
    setIsSavingBulk(false);
  };

  const handleConfirmSettingsUpdate = async () => {
    if (!settingsReport) return;
    setIsSavingBulk(true);
    const result = await bulkUpdateArticleSettings(settingsReport.validUpdates);
    toast({ title: result.success ? "Impostazioni Aggiornate" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) {
      setSettingsReport(null);
      router.refresh();
    }
    setIsSavingBulk(false);
  };

  return (
    <>
      <div className="space-y-6">
        <header className="flex flex-col sm:flex-row justify-between items-start gap-4">
          <div>
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <ClipboardList className="h-8 w-8 text-primary" />
              Anagrafica Articoli
            </h1>
            <p className="text-muted-foreground mt-1">Gestisci la distinta base e i tempi standard per ogni articolo.</p>
          </div>
          <div className="flex items-center gap-2 pt-2 w-full sm:w-auto flex-wrap justify-end">
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" className="hidden" />
            <input type="file" ref={settingsInputRef} onChange={handleSettingsFileChange} accept=".xlsx, .xls" className="hidden" />

            <Button onClick={handleDownloadSettingsTemplate} variant="outline" size="sm" className="bg-amber-500/10 border-amber-500/50 text-amber-700 dark:text-amber-400 h-9 px-3">
              <FileSpreadsheet className="mr-2 h-4 w-4" /> Template Impostazioni
            </Button>

            <Button onClick={() => settingsInputRef.current?.click()} variant="outline" size="sm" disabled={isImportingSettings} className="bg-amber-500/10 hover:bg-amber-500/20 border-amber-500/50 text-amber-700 dark:text-amber-400 h-9 px-3">
              {isImportingSettings ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <FileEdit className="mr-2 h-4 w-4" />}
              Importa Cicli/tempi
            </Button>

            <Button onClick={() => fileInputRef.current?.click()} variant="outline" size="sm" disabled={isImporting} className="h-9 px-3">
              {isImporting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Upload className="mr-2 h-4 w-4" />}
              Importa BOM
            </Button>
            <div className="relative w-full sm:w-48 lg:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input placeholder="Cerca..." className="pl-9 h-9" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            </div>
            <Button onClick={() => handleOpenForm(null)} className="bg-primary hover:bg-primary/90 text-primary-foreground h-9 px-4"><PlusCircle className="mr-2 h-4 w-4" />Aggiungi</Button>
          </div>
        </header>

        <Card>
          <CardHeader><CardTitle>Elenco Articoli</CardTitle></CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <Table>
                <TableHeader>
                  <TableRow>
                    <TableHead>Codice Articolo</TableHead>
                    <TableHead>N┬░ Componenti</TableHead>
                    <TableHead>Ciclo Predefinito</TableHead>
                    <TableHead className="text-right">Azioni</TableHead>
                  </TableRow>
                </TableHeader>
                <TableBody>
                  {filteredArticles.length > 0 ? (
                    filteredArticles.map((article) => (
                      <TableRow key={article.code}>
                        <TableCell>
                          <ContextMenu>
                            <ContextMenuTrigger className="font-medium hover:text-primary hover:underline cursor-pointer">{article.code}</ContextMenuTrigger>
                            <ContextMenuContent>
                              <ContextMenuItem onSelect={() => router.push(`/admin/production-time-analysis?articleCode=${encodeURIComponent(article.code)}`)}><BarChart3 className="mr-2 h-4 w-4" />Analisi Tempi</ContextMenuItem>
                              <ContextMenuItem onSelect={() => navigator.clipboard.writeText(article.code).then(() => toast({ title: "Copiato!" }))}><Copy className="mr-2 h-4 w-4" />Copia Codice</ContextMenuItem>
                            </ContextMenuContent>
                          </ContextMenu>
                        </TableCell>
                        <TableCell>{article.billOfMaterials?.length || 0}</TableCell>
                        <TableCell>
                          <Badge variant="outline" className="font-mono text-[10px] uppercase">
                            {article.workCycleId ? "Assegnato" : "Non impostato"}
                          </Badge>
                        </TableCell>
                        <TableCell className="text-right space-x-2">
                          <Button variant="outline" size="sm" onClick={() => handleOpenTimes(article)}>
                            <Timer className="mr-2 h-4 w-4 text-amber-500" /> Cicli/Tempi
                          </Button>
                          <Button variant="outline" size="sm" onClick={() => handleOpenForm(article)}>
                            <Edit className="mr-2 h-4 w-4" /> BOM
                          </Button>
                          <AlertDialog>
                            <AlertDialogTrigger asChild><Button variant="destructive" size="sm"><Trash2 className="mr-2 h-4 w-4" /> Elimina</Button></AlertDialogTrigger>
                            <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Eliminare l'articolo?</AlertDialogTitle><AlertDialogDescription>L'azione ├¿ irreversibile.</AlertDialogDescription></AlertDialogHeader>
                              <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => handleDelete(article.id)}>S├¼, elimina</AlertDialogAction></AlertDialogFooter>
                            </AlertDialogContent>
                          </AlertDialog>
                        </TableCell>
                      </TableRow>
                    ))
                  ) : (
                    <TableRow><TableCell colSpan={4} className="h-24 text-center">Nessun articolo trovato.</TableCell></TableRow>
                  )}
                </TableBody>
              </Table>
            </div>
          </CardContent>
        </Card>
      </div>

      <ArticleFormDialog isOpen={isFormOpen} onClose={handleFormClose} article={editingArticle} rawMaterials={rawMaterials} />

      {editingArticle && (
        <ArticleTimesDialog
          isOpen={isTimesOpen}
          onClose={handleTimesClose}
          article={editingArticle}
          phaseTemplates={phaseTemplates}
        />
      )}

      <Dialog open={!!importReport} onOpenChange={(o) => !o && setImportReport(null)}>
        <DialogContent className="max-w-4xl max-h-[90vh] flex flex-col">
          <DialogHeader><DialogTitle className="flex items-center gap-2"><ClipboardList className="h-6 w-6 text-primary" /> Analisi Importazione Distinte</DialogTitle></DialogHeader>
          <Tabs defaultValue="new" className="flex-1 overflow-hidden flex flex-col mt-4">
            <TabsList className="grid w-full grid-cols-3">
              <TabsTrigger value="new"><PlusCircle className="h-4 w-4 text-green-500 mr-2" /> Nuovi ({importReport?.newArticles.length || 0})</TabsTrigger>
              <TabsTrigger value="update"><RefreshCcw className="h-4 w-4 text-blue-500 mr-2" /> Aggiorna ({importReport?.updatedArticles.length || 0})</TabsTrigger>
              <TabsTrigger value="errors"><XCircle className="h-4 w-4 text-destructive mr-2" /> Errori ({importReport?.invalidArticles.length || 0})</TabsTrigger>
            </TabsList>
            <TabsContent value="new" className="flex-1 overflow-hidden pt-4">
              <ScrollArea className="h-[400px] border rounded-md p-2">
                <Table>
                  <TableHeader><TableRow><TableHead>Codice</TableHead><TableHead>Componenti</TableHead></TableRow></TableHeader>
                  <TableBody>
                    {importReport?.newArticles.map((art, idx) => (
                      <TableRow key={idx}>
                        <TableCell className="font-mono">{art.code}</TableCell>
                        <TableCell>{art.billOfMaterials.length}</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </ScrollArea>
            </TabsContent>
            <TabsContent value="update" className="flex-1 overflow-hidden pt-4">
              <ScrollArea className="h-[400px] border rounded-md p-2">
                <Table>
                  <TableHeader><TableRow><TableHead>Codice Esistente</TableHead><TableHead>Nuova Distinta</TableHead></TableRow></TableHeader>
                  <TableBody>
                    {importReport?.updatedArticles.map((art, idx) => (
                      <TableRow key={idx} className="bg-blue-500/5">
                        <TableCell className="font-mono font-bold text-blue-700">{art.code}</TableCell>
                        <TableCell>{art.billOfMaterials.length} comp. (verr├á aggiornata)</TableCell>
                      </TableRow>
                    ))}
                  </TableBody>
                </Table>
              </ScrollArea>
            </TabsContent>
            <TabsContent value="errors" className="flex-1 overflow-hidden pt-4">
              <ScrollArea className="h-[400px] border rounded-md p-2">
                <div className="space-y-4">
                  {importReport?.invalidArticles.map((item, idx) => (
                    <div key={idx} className="p-3 border-l-4 border-destructive bg-destructive/5">
                      <p className="font-bold text-destructive">{item.code}</p>
                      <ul className="text-xs mt-1">
                        {item.errors.map((err, eIdx) => <li key={eIdx}>ÔÇó {err}</li>)}
                      </ul>
                    </div>
                  ))}
                </div>
              </ScrollArea>
            </TabsContent>
          </Tabs>
          <DialogFooter className="mt-6 border-t pt-4">
            <Button variant="outline" onClick={() => setImportReport(null)}>Annulla tutto</Button>
            <Button onClick={handleConfirmImport} disabled={isSavingBulk || (!importReport?.newArticles.length && !importReport?.updatedArticles.length)} className="bg-green-600 hover:bg-green-700 text-white">
              {isSavingBulk ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
              Conferma Caricamento
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog open={!!settingsReport} onOpenChange={(o) => !o && setSettingsReport(null)}>
        <DialogContent className="max-w-4xl max-h-[90vh] flex flex-col">
          <DialogHeader><DialogTitle className="flex items-center gap-2"><FileEdit className="h-6 w-6 text-amber-500" /> Analisi Aggiornamento Cicli/Tempi</DialogTitle></DialogHeader>
          <div className="flex-1 overflow-hidden flex flex-col mt-4 space-y-4">
            <div className="flex gap-4">
              <Card className="flex-1 border-green-500/20 bg-green-500/5">
                <CardHeader className="p-3 pb-0"><CardTitle className="text-sm font-bold text-green-700">Validi per Update</CardTitle></CardHeader>
                <CardContent className="text-2xl font-black text-green-600">{settingsReport?.validUpdates.length || 0}</CardContent>
              </Card>
              <Card className="flex-1 border-destructive/20 bg-destructive/5">
                <CardHeader className="p-3 pb-0"><CardTitle className="text-sm font-bold text-destructive">Errori (Bloccati)</CardTitle></CardHeader>
                <CardContent className="text-2xl font-black text-destructive">{settingsReport?.invalidRows.length || 0}</CardContent>
              </Card>
            </div>

            <Tabs defaultValue="valid" className="flex-1 overflow-hidden flex flex-col">
              <TabsList className="grid w-full grid-cols-2">
                <TabsTrigger value="valid">Dati da Applicare</TabsTrigger>
                <TabsTrigger value="invalid">Errori</TabsTrigger>
              </TabsList>
              <TabsContent value="valid" className="flex-1 overflow-hidden pt-4">
                <ScrollArea className="h-[350px] border rounded-md p-2">
                  <Table>
                    <TableHeader><TableRow><TableHead>Codice</TableHead><TableHead>Ciclo Def.</TableHead><TableHead>Tempo</TableHead></TableRow></TableHeader>
                    <TableBody>
                      {settingsReport?.validUpdates.map((upd, i) => (
                        <TableRow key={i}>
                          <TableCell className="font-mono font-bold">{upd.code}</TableCell>
                          <TableCell className="text-xs">{upd.workCycleId ? "SI" : "-"}</TableCell>
                          <TableCell className="font-mono">{upd.expectedMinutesDefault} min</TableCell>
                        </TableRow>
                      ))}
                    </TableBody>
                  </Table>
                </ScrollArea>
              </TabsContent>
              <TabsContent value="invalid" className="flex-1 overflow-hidden pt-4">
                <ScrollArea className="h-[350px] border rounded-md p-2">
                  <div className="space-y-2">
                    {settingsReport?.invalidRows.map((err, i) => (
                      <div key={i} className="p-2 border-l-4 border-destructive bg-destructive/5 text-xs">
                        <span className="font-bold">{err.code}</span>: {err.reason}
                      </div>
                    ))}
                  </div>
                </ScrollArea>
              </TabsContent>
            </Tabs>
          </div>
          <DialogFooter className="mt-6 border-t pt-4">
            <Button variant="outline" onClick={() => setSettingsReport(null)}>Annulla tutto</Button>
            <Button onClick={handleConfirmSettingsUpdate} disabled={isSavingBulk || !settingsReport?.validUpdates.length} className="bg-amber-600 hover:bg-amber-700 text-white">
              {isSavingBulk ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Save className="mr-2 h-4 w-4" />}
              Conferma e Aggiorna Anagrafiche
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { 
  CalendarDays, 
  PlusCircle, 
  Trash2, 
  Settings2, 
  Stethoscope, 
  Plane, 
  Clock, 
  Loader2, 
  User,
  Settings,
  ChevronLeft,
  ChevronRight,
  TrendingUp
} from 'lucide-react';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/components/auth/AuthProvider';
import { getCalendarExceptions, saveCalendarException, deleteCalendarException, getWeeklyCapacityReport, type OperatorCapacity } from './actions';
import { getOperators } from '../operator-management/actions';
import { getWorkstations } from '../workstation-management/actions';
import { format, parseISO, addWeeks, subWeeks, startOfWeek } from 'date-fns';
import { it } from 'date-fns/locale';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import type { CalendarException, Operator, Workstation } from '@/lib/mock-data';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { cn } from '@/lib/utils';

const exceptionSchema = z.object({
  resourceType: z.enum(['operator', 'machine']),
  targetId: z.string().min(1, "Seleziona una risorsa."),
  exceptionType: z.enum(['sick', 'vacation', 'permit', 'maintenance', 'other']),
  startDate: z.string().min(1, "Data inizio obbligatoria."),
  endDate: z.string().min(1, "Data fine obbligatoria."),
  hoursLost: z.coerce.number().optional(),
  notes: z.string().optional(),
});

type FormValues = z.infer<typeof exceptionSchema>;

export default function AttendanceCalendarPage() {
  const { user } = useAuth();
  const { toast } = useToast();
  const [exceptions, setExceptions] = useState<CalendarException[]>([]);
  const [operators, setOperators] = useState<Operator[]>([]);
  const [workstations, setWorkstations] = useState<Workstation[]>([]);
  const [capacityReport, setCapacityReport] = useState<OperatorCapacity[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isCapacityLoading, setIsCapacityLoading] = useState(false);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [isPending, setIsPending] = useState(false);
  const [referenceDate, setReferenceDate] = useState(new Date());

  const form = useForm<FormValues>({
    resolver: zodResolver(exceptionSchema),
    defaultValues: {
      resourceType: 'operator',
      exceptionType: 'vacation',
      startDate: format(new Date(), 'yyyy-MM-dd'),
      endDate: format(new Date(), 'yyyy-MM-dd'),
    }
  });

  const fetchData = async () => {
    setIsLoading(true);
    try {
      const [exc, ops, ws] = await Promise.all([
        getCalendarExceptions(),
        getOperators(),
        getWorkstations()
      ]);
      setExceptions(exc);
      setOperators(ops);
      setWorkstations(ws);
      await fetchCapacity();
    } catch (e) {
      toast({ variant: 'destructive', title: 'Errore caricamento dati' });
    } finally {
      setIsLoading(false);
    }
  };

  const fetchCapacity = async () => {
    setIsCapacityLoading(true);
    try {
        const report = await getWeeklyCapacityReport(referenceDate.toISOString());
        setCapacityReport(report);
    } catch (e) {
        console.error(e);
    } finally {
        setIsCapacityLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);
  useEffect(() => { fetchCapacity(); }, [referenceDate]);

  const onSubmit = async (values: FormValues) => {
    if (!user) return;
    setIsPending(true);
    
    let targetName = '';
    if (values.resourceType === 'operator') {
      targetName = operators.find(o => o.id === values.targetId)?.nome || 'Sconosciuto';
    } else {
      targetName = workstations.find(w => w.id === values.targetId)?.name || 'Macchina';
    }

    const result = await saveCalendarException({
      ...values,
      targetName,
    }, user.uid);

    if (result.success) {
      toast({ title: 'Successo', description: result.message });
      setIsDialogOpen(false);
      fetchData();
    } else {
      toast({ variant: 'destructive', title: 'Errore', description: result.message });
    }
    setIsPending(false);
  };

  const handleDelete = async (id: string) => {
    if (!user) return;
    const result = await deleteCalendarException(id, user.uid);
    if (result.success) {
      toast({ title: 'Eliminata' });
      fetchData();
    }
  };

  const getTypeBadge = (type: CalendarException['exceptionType']) => {
    switch (type) {
      case 'sick': return <Badge variant="destructive" className="gap-1"><Stethoscope className="h-3 w-3"/> Mutua</Badge>;
      case 'vacation': return <Badge variant="default" className="gap-1"><Plane className="h-3 w-3"/> Ferie</Badge>;
      case 'permit': return <Badge variant="outline" className="border-primary text-primary gap-1"><Clock className="h-3 w-3"/> Permesso</Badge>;
      case 'maintenance': return <Badge variant="secondary" className="gap-1"><Settings2 className="h-3 w-3"/> Manutenzione</Badge>;
      default: return <Badge variant="outline">Altro</Badge>;
    }
  };

  const weekStart = startOfWeek(referenceDate, { weekStartsOn: 1 });

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <header className="flex justify-between items-center flex-wrap gap-4">
            <div>
              <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                <CalendarDays className="h-8 w-8 text-primary" />
                Calendario Presenze ed Eccezioni
              </h1>
              <p className="text-muted-foreground">Gestisci le assenze del personale e i fermi macchina per la pianificazione.</p>
            </div>
            <Button onClick={() => setIsDialogOpen(true)}>
              <PlusCircle className="mr-2 h-4 w-4" /> Nuova Eccezione
            </Button>
          </header>

          <Tabs defaultValue="capacity" className="w-full">
            <TabsList className="grid w-full grid-cols-2 max-w-md">
                <TabsTrigger value="capacity">Vista Capacit├á</TabsTrigger>
                <TabsTrigger value="registry">Registro Eccezioni</TabsTrigger>
            </TabsList>

            <TabsContent value="capacity" className="pt-4">
                <Card>
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-4">
                        <div>
                            <CardTitle className="flex items-center gap-2">
                                <TrendingUp className="h-5 w-5 text-primary" />
                                Capacit├á Operativa Settimanale
                            </CardTitle>
                            <CardDescription>Ore disponibili effettive per operatore.</CardDescription>
                        </div>
                        <div className="flex items-center gap-2">
                            <Button variant="outline" size="icon" onClick={() => setReferenceDate(prev => subWeeks(prev, 1))}><ChevronLeft className="h-4 w-4" /></Button>
                            <span className="text-sm font-bold min-w-[150px] text-center">
                                {format(weekStart, 'dd MMM')} - {format(addWeeks(weekStart, 6), 'dd MMM yyyy')}
                            </span>
                            <Button variant="outline" size="icon" onClick={() => setReferenceDate(prev => addWeeks(prev, 1))}><ChevronRight className="h-4 w-4" /></Button>
                        </div>
                    </CardHeader>
                    <CardContent>
                        {isCapacityLoading ? (
                            <div className="flex justify-center py-12"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>
                        ) : (
                            <div className="overflow-x-auto">
                                <Table className="border rounded-md">
                                    <TableHeader className="bg-muted/50">
                                        <TableRow>
                                            <TableHead className="font-bold border-r">Operatore</TableHead>
                                            {capacityReport[0]?.dailyCapacities.map(day => (
                                                <TableHead key={day.date} className="text-center min-w-[100px]">
                                                    <div className="capitalize font-bold">{day.dayName.slice(0, 3)}</div>
                                                    <div className="text-[10px] text-muted-foreground">{format(parseISO(day.date), 'dd/MM')}</div>
                                                </TableHead>
                                            ))}
                                            <TableHead className="text-right font-bold border-l bg-primary/5">Totale Sett.</TableHead>
                                        </TableRow>
                                    </TableHeader>
                                    <TableBody>
                                        {capacityReport.map(report => (
                                            <TableRow key={report.operatorId}>
                                                <TableCell className="font-semibold border-r">{report.operatorName}</TableCell>
                                                {report.dailyCapacities.map(day => (
                                                    <TableCell key={day.date} className={cn(
                                                        "text-center font-mono py-4",
                                                        !day.isWorkingDay && "bg-muted/30 text-muted-foreground",
                                                        day.effectiveHours === 0 && day.isWorkingDay && "bg-destructive/5 text-destructive",
                                                        day.effectiveHours > 0 && day.effectiveHours < day.standardHours && "bg-amber-500/5 text-amber-600"
                                                    )}>
                                                        <div className="text-sm font-bold">{day.effectiveHours.toFixed(2)}h</div>
                                                    </TableCell>
                                                ))}
                                                <TableCell className="text-right font-bold border-l bg-primary/5 text-primary">
                                                    {report.totalWeeklyHours.toFixed(2)}h
                                                </TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>
                            </div>
                        )}
                    </CardContent>
                </Card>
            </TabsContent>

            <TabsContent value="registry" className="pt-4">
                <Card>
                    <CardHeader>
                    <CardTitle>Registro Eccezioni</CardTitle>
                    <CardDescription>Elenco cronologico degli eventi registrati.</CardDescription>
                    </CardHeader>
                    <CardContent>
                    {isLoading ? (
                        <div className="flex justify-center py-12"><Loader2 className="h-8 w-8 animate-spin text-primary" /></div>
                    ) : (
                        <div className="overflow-x-auto">
                        <Table>
                            <TableHeader>
                            <TableRow>
                                <TableHead>Data Inizio</TableHead>
                                <TableHead>Data Fine</TableHead>
                                <TableHead>Risorsa</TableHead>
                                <TableHead>Tipo</TableHead>
                                <TableHead>Ore Perse</TableHead>
                                <TableHead>Note</TableHead>
                                <TableHead className="text-right">Azioni</TableHead>
                            </TableRow>
                            </TableHeader>
                            <TableBody>
                            {exceptions.length > 0 ? exceptions.map((ex) => (
                                <TableRow key={ex.id}>
                                <TableCell>{format(parseISO(ex.startDate), 'dd/MM/yyyy')}</TableCell>
                                <TableCell>{format(parseISO(ex.endDate), 'dd/MM/yyyy')}</TableCell>
                                <TableCell>
                                    <div className="flex items-center gap-2">
                                    {ex.resourceType === 'operator' ? <User className="h-4 w-4 text-muted-foreground" /> : <Settings className="h-4 w-4 text-muted-foreground" />}
                                    <span className="font-semibold">{ex.targetName}</span>
                                    </div>
                                </TableCell>
                                <TableCell>{getTypeBadge(ex.exceptionType)}</TableCell>
                                <TableCell>{ex.hoursLost ? `${ex.hoursLost} h` : 'Giornata intera'}</TableCell>
                                <TableCell className="max-w-[200px] truncate italic text-xs">{ex.notes || '-'}</TableCell>
                                <TableCell className="text-right">
                                    <Button variant="ghost" size="icon" className="text-destructive" onClick={() => handleDelete(ex.id)}>
                                    <Trash2 className="h-4 w-4" />
                                    </Button>
                                </TableCell>
                                </TableRow>
                            )) : (
                                <TableRow><TableCell colSpan={7} className="text-center h-24">Nessuna eccezione registrata.</TableCell></TableRow>
                            )}
                            </TableBody>
                        </Table>
                        </div>
                    )}
                    </CardContent>
                </Card>
            </TabsContent>
          </Tabs>
        </div>

        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogContent className="sm:max-w-md">
            <DialogHeader>
              <DialogTitle>Registra Nuova Eccezione</DialogTitle>
              <DialogDescription>Inserisci i dettagli dell'assenza o del fermo macchina.</DialogDescription>
            </DialogHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4">
                <div className="grid grid-cols-2 gap-4">
                  <FormField control={form.control} name="resourceType" render={({ field }) => (
                    <FormItem><FormLabel>Tipo Risorsa</FormLabel>
                      <Select onValueChange={v => { field.onChange(v); form.setValue('targetId', ''); }} value={field.value}>
                        <FormControl><SelectTrigger><SelectValue /></SelectTrigger></FormControl>
                        <SelectContent><SelectItem value="operator">Operatore</SelectItem><SelectItem value="machine">Macchina/Postazione</SelectItem></SelectContent>
                      </Select>
                    </FormItem>
                  )} />
                  <FormField control={form.control} name="targetId" render={({ field }) => (
                    <FormItem><FormLabel>Soggetto</FormLabel>
                      <Select onValueChange={field.onChange} value={field.value}>
                        <FormControl><SelectTrigger><SelectValue placeholder="Seleziona..." /></SelectTrigger></FormControl>
                        <SelectContent>
                          {form.watch('resourceType') === 'operator' 
                            ? operators.map(o => <SelectItem key={o.id} value={o.id}>{o.nome}</SelectItem>)
                            : workstations.map(w => <SelectItem key={w.id} value={w.id}>{w.name}</SelectItem>)
                          }
                        </SelectContent>
                      </Select>
                    </FormItem>
                  )} />
                </div>

                <FormField control={form.control} name="exceptionType" render={({ field }) => (
                  <FormItem><FormLabel>Tipo Evento</FormLabel>
                    <Select onValueChange={field.onChange} value={field.value}>
                      <FormControl><SelectTrigger><SelectValue /></SelectTrigger></FormControl>
                      <SelectContent>
                        <SelectItem value="vacation">Ferie / Permesso</SelectItem>
                        <SelectItem value="sick">Malattia / Mutua</SelectItem>
                        <SelectItem value="maintenance">Manutenzione / Fermo</SelectItem>
                        <SelectItem value="other">Altro</SelectItem>
                      </SelectContent>
                    </Select>
                  </FormItem>
                )} />

                <div className="grid grid-cols-2 gap-4">
                  <FormField control={form.control} name="startDate" render={({ field }) => (
                    <FormItem><FormLabel>Dal</FormLabel><FormControl><Input type="date" {...field} /></FormControl></FormItem>
                  )} />
                  <FormField control={form.control} name="endDate" render={({ field }) => (
                    <FormItem><FormLabel>Al</FormLabel><FormControl><Input type="date" {...field} /></FormControl></FormItem>
                  )} />
                </div>

                <FormField control={form.control} name="hoursLost" render={({ field }) => (
                  <FormItem><FormLabel>Ore Perse (lascia vuoto se tutto il giorno)</FormLabel><FormControl><Input type="number" step="0.5" {...field} /></FormControl></FormItem>
                )} />

                <FormField control={form.control} name="notes" render={({ field }) => (
                  <FormItem><FormLabel>Note</FormLabel><FormControl><Input placeholder="Es. Visita medica" {...field} /></FormControl></FormItem>
                )} />

                <DialogFooter>
                  <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>Annulla</Button>
                  <Button type="submit" disabled={isPending}>{isPending ? <Loader2 className="animate-spin h-4 w-4" /> : 'Salva Evento'}</Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { format, parseISO } from 'date-fns';
import { it } from 'date-fns/locale';
import { useToast } from '@/hooks/use-toast';

import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { 
  Package, 
  Search, 
  Edit, 
  History, 
  Trash2, 
  Loader2, 
  ChevronRight, 
  LinkIcon 
} from 'lucide-react';
import { type GroupedBatches, type EnrichedBatch, getMaterialWithdrawalsForMaterial, getAllGroupedBatches } from './actions';
import { Badge } from '@/components/ui/badge';
import Link from 'next/link';
import { 
  AlertDialog, 
  AlertDialogAction, 
  AlertDialogCancel, 
  AlertDialogContent, 
  AlertDialogDescription, 
  AlertDialogFooter, 
  AlertDialogHeader, 
  AlertDialogTitle 
} from '@/components/ui/alert-dialog';
import BatchFormDialog from './BatchFormDialog';
import { 
  Dialog, 
  DialogClose, 
  DialogTitle, 
  DialogHeader, 
  DialogDescription, 
  DialogFooter, 
  DialogContent 
} from '@/components/ui/dialog';
import { ScrollArea } from '@/components/ui/scroll-area';
import { cn } from '@/lib/utils';
import { deleteSingleWithdrawalAndRestoreStock, deleteBatchFromRawMaterial } from '../raw-material-management/actions';
import { formatDisplayStock } from '@/lib/utils';
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/components/ui/collapsible';

type Movement = {
  type: 'Carico' | 'Scarico';
  date: string; 
  description: string;
  quantity: number; 
  unit: string;
  id: string; 
};

interface BatchManagementClientPageProps {
  initialGroupedBatches: GroupedBatches[];
}

export default function BatchManagementClientPage({ initialGroupedBatches }: BatchManagementClientPageProps) {
  const [groupedBatches, setGroupedBatches] = useState<GroupedBatches[]>(initialGroupedBatches);
  const [searchTerm, setSearchTerm] = useState('');
  const [isDataLoading, setIsDataLoading] = useState(false);
  const [editingBatchInfo, setEditingBatchInfo] = useState<{material: GroupedBatches, batch: EnrichedBatch | null} | null>(null);
  const [batchToDelete, setBatchToDelete] = useState<{materialId: string, batchId: string} | null>(null);
  const [isHistoryDialogOpen, setIsHistoryDialogOpen] = useState(false);
  const [historyDialogData, setHistoryDialogData] = useState<{ material: GroupedBatches, lotto: string | null } | null>(null);
  const [materialMovements, setMaterialMovements] = useState<Movement[]>([]);
  const [withdrawalToDelete, setWithdrawalToDelete] = useState<string | null>(null);

  const { toast } = useToast();

  const handleOpenHistoryDialog = useCallback(async (material: GroupedBatches, lotto: string | null, isRefresh: boolean = false) => {
    if (!isRefresh) {
      setHistoryDialogData({ material, lotto });
      setMaterialMovements([]);
      setIsHistoryDialogOpen(true);
    }
    
    try {
      const withdrawals = await getMaterialWithdrawalsForMaterial(material.materialId, lotto);
      const currentMaterialStateResponse = await getAllGroupedBatches(material.materialCode);
      const currentMaterialState = currentMaterialStateResponse.find(g => g.materialId === material.materialId) || material;
      const lotInfo = currentMaterialState.lots.find(l => l.lotto === lotto);
      const lotBatches = lotInfo ? lotInfo.batches : [];
      
      const combinedMovements: Movement[] = [
        ...lotBatches.map((b): Movement => ({ 
          type: 'Carico', 
          date: b.date, 
          description: b.inventoryRecordId ? `Inventario - Lotto: ${b.lotto || 'INV'}` : `Carico Manuale - Lotto: ${b.lotto || 'N/D'} - DDT: ${b.ddt}`, 
          quantity: b.netQuantity, 
          unit: material.unitOfMeasure.toUpperCase(), 
          id: b.id 
        })),
        ...withdrawals.map((w): Movement => {
              const quantity = w.consumedUnits || w.consumedWeight;
              const unit = w.consumedUnits ? material.unitOfMeasure.toUpperCase() : 'KG';
              return { 
                type: 'Scarico', 
                date: w.withdrawalDate.toISOString(), 
                description: `Commesse: ${w.jobOrderPFs.join(', ')}`, 
                quantity: -(quantity || 0), 
                unit: unit, 
                id: w.id 
              };
          }),
      ];
      combinedMovements.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
      setMaterialMovements(combinedMovements);
    } catch (error) {
      toast({ variant: 'destructive', title: 'Errore caricamento storico' });
    }
  }, [toast]);

  const refreshData = useCallback(async () => {
     if (searchTerm.length >= 2) {
        setIsDataLoading(true);
        const results = await getAllGroupedBatches(searchTerm);
        setGroupedBatches(results);
        setIsDataLoading(false);
      } else {
        setGroupedBatches([]);
      }
     if (isHistoryDialogOpen && historyDialogData) {
      await handleOpenHistoryDialog(historyDialogData.material, historyDialogData.lotto, true);
    }
  }, [searchTerm, isHistoryDialogOpen, historyDialogData, handleOpenHistoryDialog]);

  useEffect(() => {
    const delayDebounceFn = setTimeout(() => {
      if (searchTerm.length >= 2) {
        setIsDataLoading(true);
        getAllGroupedBatches(searchTerm).then(results => {
          setGroupedBatches(results);
          setIsDataLoading(false);
        });
      } else {
        setGroupedBatches([]);
      }
    }, 500);
    return () => clearTimeout(delayDebounceFn);
  }, [searchTerm]);

  const handleDeleteBatch = async () => {
    if (!batchToDelete) return;
    const { materialId, batchId } = batchToDelete;
    const result = await deleteBatchFromRawMaterial(materialId, batchId);
    toast({ title: result.success ? "Successo" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) refreshData();
    setBatchToDelete(null);
  };
  
  const handleDeleteWithdrawal = async () => {
    if (!withdrawalToDelete) return;
    const result = await deleteSingleWithdrawalAndRestoreStock(withdrawalToDelete);
    toast({ title: result.success ? "Successo" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) refreshData();
    setWithdrawalToDelete(null);
  };

  return (
    <div className="space-y-6">
      <header className="space-y-2">
        <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
          <Package className="h-8 w-8 text-primary" />
          Gestione Lotti Materie Prime
        </h1>
        <p className="text-muted-foreground">Visualizza e gestisci i lotti caricati a magazzino.</p>
      </header>
      <Card>
        <CardHeader>
          <div className="flex justify-between items-center flex-wrap gap-4">
            <div><CardTitle>Anagrafica Lotti</CardTitle><CardDescription>Ricerca per codice materiale.</CardDescription></div>
            <div className="relative w-full sm:w-auto">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input 
                placeholder="Cerca materiale (min 2 caratteri)..." 
                className="pl-9 w-full sm:w-64" 
                value={searchTerm} 
                onChange={(e) => setSearchTerm(e.target.value)} 
              />
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <Accordion type="multiple" className="w-full space-y-4">
             {isDataLoading ? (
               <div className="flex items-center justify-center h-48 text-muted-foreground gap-2">
                 <Loader2 className="h-5 w-5 animate-spin" />
                 <span>Caricamento lotti...</span>
               </div>
             ) : groupedBatches.length > 0 ? (
              groupedBatches.map((group) => (
                <AccordionItem value={group.materialId} key={group.materialId} className="border rounded-lg bg-card shadow-sm">
                  <AccordionTrigger className="p-4 hover:no-underline">
                    <div className="flex-1 text-left">
                      <div className="flex items-center gap-2">
                        <Link href={`/admin/raw-material-management?code=${encodeURIComponent(group.materialCode)}`} className="font-semibold text-lg hover:text-primary hover:underline">
                          {group.materialCode}
                        </Link>
                        <LinkIcon className="h-4 w-4 text-muted-foreground" />
                        <Badge variant="secondary">{group.lots.length} Lotti</Badge>
                      </div>
                      <p className="text-sm text-muted-foreground">{group.materialDescription}</p>
                    </div>
                    <div className="text-right ml-4">
                      <p className="font-bold text-xl">{formatDisplayStock(group.currentStockUnits, group.unitOfMeasure)} <span className="text-sm font-normal text-muted-foreground">{group.unitOfMeasure.toUpperCase()}</span></p>
                      <p className="text-xs text-muted-foreground">({formatDisplayStock(group.currentWeightKg, 'kg')} KG)</p>
                    </div>
                  </AccordionTrigger>
                  <AccordionContent className="p-0 border-t">
                    <div className="space-y-2 p-4 bg-muted/50">
                      {group.lots.map((lotInfo) => (
                        <Collapsible key={lotInfo.lotto} className="border rounded-md bg-card shadow-sm">
                            <CollapsibleTrigger className="p-3 flex justify-between items-center w-full group hover:bg-accent/50">
                              <div className="flex items-center gap-4">
                                <ChevronRight className="h-4 w-4 transition-transform duration-200 group-data-[state=open]:rotate-90" />
                                <div className="text-left">
                                  <p className="font-semibold font-mono">{lotInfo.lotto}</p>
                                  <p className="text-xs text-muted-foreground">Primo carico: {lotInfo.firstLoadDate ? format(parseISO(lotInfo.firstLoadDate), 'dd/MM/yyyy') : 'N/D'}</p>
                                </div>
                              </div>
                              <div className="text-right">
                                <p className={cn("font-bold", lotInfo.available < 0 && "text-destructive")}>{formatDisplayStock(lotInfo.available, group.unitOfMeasure)} {group.unitOfMeasure.toUpperCase()}</p>
                                <p className="text-xs text-muted-foreground">Carico: {formatDisplayStock(lotInfo.totalLoaded, group.unitOfMeasure)} | Scarico: {formatDisplayStock(lotInfo.totalWithdrawn, group.unitOfMeasure)}</p>
                              </div>
                            </CollapsibleTrigger>
                            <CollapsibleContent>
                              <div className="border-t p-2">
                                <div className="flex justify-end p-2">
                                  <Button variant="outline" size="sm" onClick={() => handleOpenHistoryDialog(group, lotInfo.lotto)}>
                                    <History className="mr-2 h-4 w-4" />Storico Lotto
                                  </Button>
                                </div>
                                <Table>
                                  <TableHeader>
                                    <TableRow>
                                      <TableHead>Data Carico</TableHead>
                                      <TableHead>Origine/DDT</TableHead>
                                      <TableHead>Quantit├á</TableHead>
                                      <TableHead className="text-right">Azioni</TableHead>
                                    </TableRow>
                                  </TableHeader>
                                  <TableBody>
                                    {lotInfo.batches.map(batch => (
                                      <TableRow key={batch.id}>
                                        <TableCell>{format(parseISO(batch.date), 'dd/MM/yyyy HH:mm', { locale: it })}</TableCell>
                                        <TableCell className="text-xs truncate max-w-[150px]">{batch.ddt}</TableCell>
                                        <TableCell className="font-mono">{formatDisplayStock(batch.netQuantity, group.unitOfMeasure)}</TableCell>
                                        <TableCell className="text-right space-x-2">
                                          <Button variant="outline" size="icon" onClick={() => setEditingBatchInfo({material: group, batch: batch})}>
                                            <Edit className="h-4 w-4" />
                                          </Button>
                                          <Button variant="ghost" size="icon" className="text-destructive" onClick={() => setBatchToDelete({ materialId: group.materialId, batchId: batch.id })}>
                                            <Trash2 className="h-4 w-4" />
                                          </Button>
                                        </TableCell>
                                      </TableRow>
                                    ))}
                                  </TableBody>
                                </Table>
                              </div>
                            </CollapsibleContent>
                        </Collapsible>
                      ))}
                    </div>
                  </AccordionContent>
                </AccordionItem>
                ))
            ) : (
              <div className="text-center py-10 text-muted-foreground">
                {searchTerm.length < 2 ? "Digita almeno 2 caratteri per cercare." : "Nessun lotto trovato."}
              </div>
            )}
          </Accordion>
        </CardContent>
      </Card>

      {editingBatchInfo && (
        <BatchFormDialog 
          isOpen={!!editingBatchInfo} 
          onClose={(refresh) => { setEditingBatchInfo(null); if(refresh) refreshData(); }} 
          material={editingBatchInfo.material} 
          batch={editingBatchInfo.batch} 
        />
      )}

      <AlertDialog open={!!batchToDelete} onOpenChange={(open) => !open && setBatchToDelete(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Eliminare questo carico?</AlertDialogTitle>
            <AlertDialogDescription>L'azione ├¿ irreversibile e ridurr├á lo stock attuale.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={() => setBatchToDelete(null)}>Annulla</AlertDialogCancel>
            <AlertDialogAction onClick={handleDeleteBatch} className="bg-destructive hover:bg-destructive/90">S├¼, elimina</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      <Dialog open={isHistoryDialogOpen} onOpenChange={setIsHistoryDialogOpen}>
        <DialogContent className="sm:max-w-4xl">
          <DialogHeader>
            <DialogTitle>Storico: {historyDialogData?.material.materialCode} {historyDialogData?.lotto && <span className="text-primary ml-2">{historyDialogData.lotto}</span>}</DialogTitle>
          </DialogHeader>
          <ScrollArea className="max-h-[60vh]">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Data</TableHead>
                  <TableHead>Tipo</TableHead>
                  <TableHead>Descrizione</TableHead>
                  <TableHead className="text-right">Quantit├á</TableHead>
                  <TableHead className="text-right">Azioni</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {materialMovements.length > 0 ? (
                  materialMovements.map(mov => (
                    <TableRow key={mov.id}>
                      <TableCell>{format(parseISO(mov.date), 'dd/MM/yyyy HH:mm', { locale: it })}</TableCell>
                      <TableCell><Badge variant={mov.type === 'Carico' ? 'default' : 'destructive'}>{mov.type}</Badge></TableCell>
                      <TableCell className="text-xs truncate max-w-xs">{mov.description}</TableCell>
                      <TableCell className={cn("text-right font-mono font-bold", mov.type === 'Carico' ? 'text-green-600' : 'text-destructive')}>
                        {formatDisplayStock(mov.quantity, mov.unit.toLowerCase() as any)} {mov.unit}
                      </TableCell>
                      <TableCell className="text-right">
                        <Button 
                          variant="ghost" 
                          size="icon" 
                          className="text-destructive" 
                          onClick={() => {
                            if(mov.type === 'Carico') {
                              setBatchToDelete({ materialId: historyDialogData!.material.materialId, batchId: mov.id });
                            } else {
                              setWithdrawalToDelete(mov.id);
                            }
                            setIsHistoryDialogOpen(false);
                          }}
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </TableCell>
                    </TableRow>
                  ))
                ) : (
                  <TableRow><TableCell colSpan={5} className="h-24 text-center">Caricamento movimenti...</TableCell></TableRow>
                )}
              </TableBody>
            </Table>
          </ScrollArea>
          <DialogFooter>
            <DialogClose asChild><Button variant="outline">Chiudi</Button></DialogClose>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <AlertDialog open={!!withdrawalToDelete} onOpenChange={(open) => !open && setWithdrawalToDelete(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Eliminare scarico e ripristinare stock?</AlertDialogTitle>
            <AlertDialogDescription>L'operazione ├¿ definitiva.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel onClick={() => setWithdrawalToDelete(null)}>Annulla</AlertDialogCancel>
            <AlertDialogAction onClick={handleDeleteWithdrawal} className="bg-destructive">S├¼, elimina e ripristina</AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

