"use client";

import React, { useState, useEffect, useTransition } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';

import { type Department } from '@/lib/mock-data';
import { getDepartments, saveDepartment, deleteDepartments } from './actions';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Checkbox } from '@/components/ui/checkbox';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from '@/components/ui/input';
import { ListTodo, PlusCircle, Edit, Trash2, Loader2 } from 'lucide-react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';

const departmentSchema = z.object({
  id: z.string().optional(),
  code: z.string().min(1, "Il codice ├¿ obbligatorio.").max(10, "Il codice non pu├▓ superare i 10 caratteri."),
  name: z.string().min(3, "Il nome deve avere almeno 3 caratteri."),
});

type DepartmentFormValues = z.infer<typeof departmentSchema>;

export default function DepartmentManagementPage() {
  const [departments, setDepartments] = useState<Department[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingDepartment, setEditingDepartment] = useState<Department | null>(null);
  const [selectedRows, setSelectedRows] = useState<string[]>([]);
  const [isPending, setIsPending] = useState(false);
  const { toast } = useToast();

  const form = useForm<DepartmentFormValues>({
    resolver: zodResolver(departmentSchema),
    defaultValues: { id: undefined, code: "", name: "" },
  });

  const fetchData = async () => {
    setIsLoading(true);
    const data = await getDepartments();
    setDepartments(data);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleOpenDialog = (department: Department | null = null) => {
    setEditingDepartment(department);
    if (department) {
      form.reset(department);
    } else {
      form.reset({ id: undefined, code: "", name: "" });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingDepartment(null);
    form.reset();
  };

  const onSubmit = async (values: DepartmentFormValues) => {
    const formData = new FormData();
    Object.entries(values).forEach(([key, value]) => {
      if (value) formData.append(key, value);
    });

    setIsPending(true);
    const result = await saveDepartment(formData);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
      await fetchData();
      handleCloseDialog();
    }
    setIsPending(false);
  };

  const handleDeleteSelected = async () => {
    setIsPending(true);
    const result = await deleteDepartments(selectedRows);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      await fetchData();
      setSelectedRows([]);
    }
    setIsPending(false);
  };

  const handleSelectAll = (checked: boolean | 'indeterminate') => {
    setSelectedRows(checked === true ? departments.map(d => d.id) : []);
  };

  const handleSelectRow = (id: string) => {
    setSelectedRows(prev => prev.includes(id) ? prev.filter(rowId => rowId !== id) : [...prev, id]);
  };

  const renderLoading = () => (
      <TableRow>
          <TableCell colSpan={4} className="h-24 text-center">
              <div className="flex items-center justify-center gap-2 text-muted-foreground">
                  <Loader2 className="h-5 w-5 animate-spin" />
                  <span>Caricamento reparti...</span>
              </div>
          </TableCell>
      </TableRow>
  );

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <header>
              <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                <ListTodo className="h-8 w-8 text-primary" />
                Gestione Reparti
              </h1>
              <p className="text-muted-foreground mt-2">
                Aggiungi, modifica o elimina i reparti produttivi e di servizio.
              </p>
            </header>
            <div className="flex items-center gap-2">
                {selectedRows.length > 0 && (
                  <AlertDialog>
                    <AlertDialogTrigger asChild>
                      <Button variant="destructive" disabled={isPending}>
                        {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Trash2 className="mr-2 h-4 w-4" />}
                        Elimina ({selectedRows.length})
                      </Button>
                    </AlertDialogTrigger>
                    <AlertDialogContent>
                      <AlertDialogHeader>
                        <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                        <AlertDialogDescription>
                          L'eliminazione di un reparto potrebbe causare problemi se ├¿ associato a operatori o fasi. Sei sicuro di voler eliminare {selectedRows.length} reparti?
                        </AlertDialogDescription>
                      </AlertDialogHeader>
                      <AlertDialogFooter>
                        <AlertDialogCancel>Annulla</AlertDialogCancel>
                        <AlertDialogAction onClick={handleDeleteSelected}>Continua</AlertDialogAction>
                      </AlertDialogFooter>
                    </AlertDialogContent>
                  </AlertDialog>
                )}
                <Button onClick={() => handleOpenDialog()} disabled={isLoading}>
                    <PlusCircle className="mr-2 h-4 w-4" />
                    Nuovo Reparto
                </Button>
            </div>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Elenco Reparti</CardTitle>
              <CardDescription>Questi reparti saranno selezionabili nella gestione degli operatori e delle fasi.</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead padding="checkbox">
                        <Checkbox
                          checked={!isLoading && selectedRows.length > 0 && selectedRows.length === departments.length ? true : !isLoading && selectedRows.length > 0 ? 'indeterminate' : false}
                          onCheckedChange={handleSelectAll}
                          aria-label="Seleziona tutti"
                          disabled={isLoading || departments.length === 0}
                        />
                      </TableHead>
                      <TableHead>Codice</TableHead>
                      <TableHead>Nome Reparto</TableHead>
                      <TableHead className="text-right">Azioni</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {isLoading ? renderLoading() : departments.length > 0 ? (
                      departments.map((dept) => (
                        <TableRow key={dept.id} data-state={selectedRows.includes(dept.id) && "selected"}>
                          <TableCell padding="checkbox">
                            <Checkbox
                              checked={selectedRows.includes(dept.id)}
                              onCheckedChange={() => handleSelectRow(dept.id)}
                              aria-label={`Seleziona il reparto ${dept.name}`}
                            />
                          </TableCell>
                          <TableCell className="font-mono">{dept.code}</TableCell>
                          <TableCell className="font-medium">{dept.name}</TableCell>
                          <TableCell className="text-right">
                            <Button variant="outline" size="icon" onClick={() => handleOpenDialog(dept)}>
                              <Edit className="h-4 w-4" />
                            </Button>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={4} className="text-center h-24">Nessun reparto trovato.</TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>
        
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogContent className="sm:max-w-md" onInteractOutside={(e) => {if (!isPending) handleCloseDialog();}}>
            <DialogHeader>
              <DialogTitle>{editingDepartment ? "Modifica Reparto" : "Aggiungi Nuovo Reparto"}</DialogTitle>
              <DialogDescription>
                Compila i campi per definire un nuovo reparto aziendale.
              </DialogDescription>
            </DialogHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4">
                <FormField control={form.control} name="code" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Codice</FormLabel>
                    <FormControl><Input placeholder="Es. CP, MAG" {...field} disabled={!!editingDepartment} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="name" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Nome</FormLabel>
                    <FormControl><Input placeholder="Es. Controllo Qualit├á" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <DialogFooter>
                  <Button type="button" variant="outline" onClick={handleCloseDialog} disabled={isPending}>Annulla</Button>
                  <Button type="submit" disabled={isPending}>
                    {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                    {editingDepartment ? "Salva Modifiche" : "Crea Reparto"}
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>
      </div>
    </AppShell>
  </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import * as XLSX from 'xlsx';
import { format, parseISO } from 'date-fns';
import { it } from 'date-fns/locale';
import Link from 'next/link';

import { Card, CardHeader, CardTitle, CardDescription, CardContent, CardFooter } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
  Accordion,
  AccordionContent,
  AccordionItem,
  AccordionTrigger,
} from "@/components/ui/accordion"
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible"
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from '@/components/ui/badge';
import { Warehouse, Download, Check, X, Pencil, Loader2, Package, Undo2, Trash2, LinkIcon, Search, ChevronDown, ShieldCheck, ShieldX, RefreshCw } from 'lucide-react';
import { type InventoryRecord, type RawMaterial } from '@/lib/mock-data';
import { approveInventoryRecord, rejectInventoryRecord, revertInventoryRecordStatus, deleteInventoryRecords, approveMultipleInventoryRecords, rejectMultipleInventoryRecords, getMaterialById } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { useToast } from '@/hooks/use-toast';
import { useRouter } from 'next/navigation';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from '@/components/ui/alert-dialog';
import InventoryRecordSheet from './InventoryRecordSheet';
import { Checkbox } from '@/components/ui/checkbox';
import { Input } from '@/components/ui/input';
import { cn } from '@/lib/utils';
import { Skeleton } from '@/components/ui/skeleton';
import { formatDisplayStock } from '@/lib/utils';



interface InventoryClientPageProps {
  initialRecords: InventoryRecord[];
}

const statusOrder: Record<InventoryRecord['status'], number> = {
  pending: 0,
  approved: 1,
  rejected: 2,
};

export default function InventoryClientPage({ initialRecords }: InventoryClientPageProps) {
  const [records, setRecords] = useState(initialRecords);
  const [selectedRecord, setSelectedRecord] = useState<InventoryRecord | null>(null);
  const [isSheetOpen, setIsSheetOpen] = useState(false);
  const [isPending, setIsPending] = useState<string | null>(null);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const [selectedRecords, setSelectedRecords] = useState<string[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  
  const { user } = useAuth();
  const { toast } = useToast();
  const router = useRouter();

  useEffect(() => {
    setRecords(initialRecords);
    setSelectedRecords([]);
  }, [initialRecords]);


  const filteredRecordsBySearch = useMemo(() => {
    return searchTerm
      ? records.filter(record => 
          record.materialCode.toLowerCase().includes(searchTerm.toLowerCase()) ||
          record.lotto.toLowerCase().includes(searchTerm.toLowerCase()) ||
          (record.operatorName || '').toLowerCase().includes(searchTerm.toLowerCase())
        )
      : records;
  }, [records, searchTerm]);

  const groupedRecords = useMemo(() => {
    return filteredRecordsBySearch.reduce((acc, record) => {
      const date = format(parseISO(record.recordedAt as unknown as string), 'dd.MM.yyyy');
      if (!acc[date]) {
        acc[date] = {};
      }
      const materialCode = record.materialCode;
       if (!acc[date][materialCode]) {
        acc[date][materialCode] = [];
      }
      acc[date][materialCode].push(record);
      return acc;
    }, {} as Record<string, Record<string, InventoryRecord[]>>);
  }, [filteredRecordsBySearch]);

  const sortedDates = useMemo(() => Object.keys(groupedRecords).sort((a, b) => {
    const [dayA, monthA, yearA] = a.split('.').map(Number);
    const [dayB, monthB, yearB] = b.split('.').map(Number);
    return new Date(yearB, monthB - 1, dayB).getTime() - new Date(yearA, monthA - 1, dayA).getTime();
  }), [groupedRecords]);
  
  const refreshData = () => {
    setIsRefreshing(true);
    router.refresh();
    // The useEffect listening to initialRecords will update the state.
    // We can set a timeout to turn off the loading indicator after a bit.
    setTimeout(() => setIsRefreshing(false), 1000);
  };

  const handleApprove = async (recordId: string) => {
    if (!user) return;
    setIsPending(recordId);
    const result = await approveInventoryRecord(recordId, user.uid);
    toast({
        title: result.success ? "Approvato!" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };
  
  const handleReject = async (recordId: string) => {
    if (!user) return;
    setIsPending(recordId);
    const result = await rejectInventoryRecord(recordId, user.uid);
    toast({
        title: result.success ? "Rifiutato" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
     if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleRevertStatus = async (recordId: string) => {
    if (!user) return;
    setIsPending(recordId);
    const result = await revertInventoryRecordStatus(recordId, user.uid);
    toast({
        title: result.success ? "Annullato" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleOpenSheet = (record: InventoryRecord) => {
    setSelectedRecord(record);
    setIsSheetOpen(true);
  };

  const handleExport = (date: string, dailyRecords: Record<string, InventoryRecord[]>) => {
    const dataToExport = Object.values(dailyRecords).flat().map(r => ({
      'Codice': r.materialCode,
      'Lotto': r.lotto,
      'Quantit├á (N)': r.inputUnit === 'n' ? r.inputQuantity : 0,
      'Quantit├á (MT)': r.inputUnit === 'mt' ? r.inputQuantity : 0,
      'Quantit├á (KG)': formatDisplayStock(r.netWeight, 'kg'),
      'Peso Lordo (kg)': formatDisplayStock(r.grossWeight, 'kg'),
      'Peso Tara (kg)': formatDisplayStock(r.tareWeight, 'kg'),
      'Peso Netto (kg)': formatDisplayStock(r.netWeight, 'kg'),
      'Operatore': r.operatorName,
      'Data Registrazione': format(parseISO(r.recordedAt as unknown as string), 'dd/MM/yyyy HH:mm'),
      'Stato': r.status,
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, `Inventario ${date}`);
    XLSX.writeFile(wb, `inventario_${date.replace(/\./g, '-')}.xlsx`);
  };

  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      setSelectedRecords(filteredRecordsBySearch.map(r => r.id));
    } else {
      setSelectedRecords([]);
    }
  };

  const handleSelectRecord = (recordId: string) => {
    setSelectedRecords(prev => 
      prev.includes(recordId) 
        ? prev.filter(id => id !== recordId) 
        : [...prev, recordId]
    );
  };

  const handleDeleteSelected = async () => {
    if (selectedRecords.length === 0 || !user) return;
    setIsPending('delete-selected');
    const result = await deleteInventoryRecords(selectedRecords, user.uid);
    toast({
      title: result.success ? "Eliminazione Completata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleApproveSelected = async () => {
    if (selectedRecords.length === 0 || !user) return;
    setIsPending('approve-selected');
    const result = await approveMultipleInventoryRecords(selectedRecords, user.uid);
     toast({
      title: result.success ? "Operazione Completata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };

  const handleRejectSelected = async () => {
     if (selectedRecords.length === 0 || !user) return;
    setIsPending('reject-selected');
    const result = await rejectMultipleInventoryRecords(selectedRecords, user.uid);
     toast({
      title: result.success ? "Operazione Completata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      refreshData();
    }
    setIsPending(null);
  };


  return (
    <>
      <div className="space-y-8">
        <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
