  const handleDownloadTemplate = () => {
    let templateData: any[];
    let fileName: string;
    let sheetName: string;

    if (operation === 'carico') {
      const packagingExamples = packagingItems.slice(0, 2).map(p => p.name);
      templateData = [
        { 
          "Codice Materiale": "CODICE-ESEMPIO-1", "Lotto": "LOTTO-A1", "DDT": "DDT-123",
          "Quantita Netta": 100.5, "Data": "2024-07-25", "Tara (Imballo)": packagingExamples[0] || "Nome Tara Esistente",
        },
        { 
          "Codice Materiale": "CODICE-ESEMPIO-2", "Lotto": "LOTTO-B2", "DDT": "DDT-124",
          "Quantita Netta": 50, "Data": 45497, "Tara (Imballo)": packagingExamples[1] || "",
        },
      ];
      fileName = "template_carico_magazzino.xlsx";
      sheetName = "Carico Magazzino";
    } else { // scarico
      templateData = [
        {
          "Codice Materiale": "CODICE-ESEMPIO-1", "Lotto": "LOTTO-A1", "Quantita da Scaricare": 10.5,
          "Unita": "kg", "Commessa Associata": "Comm-123/24", "Note": "Scarico per test",
        },
        {
          "Codice Materiale": "CODICE-ESEMPIO-2", "Lotto": "LOTTO-B2", "Quantita da Scaricare": 25,
          "Unita": "n", "Commessa Associata": "", "Note": "",
        },
      ];
      fileName = "template_scarico_magazzino.xlsx";
      sheetName = "Scarico Magazzino";
    }

    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, sheetName);
    XLSX.writeFile(wb, fileName);
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setFileName(file.name);
    setIsProcessing(true);
    toast({ title: 'Lettura file in corso...' });

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const data = e.target?.result;
        const workbook = XLSX.read(data, { type: 'array', cellDates: true });
        const sheetName = workbook.SheetNames[0];
        const worksheet = workbook.Sheets[sheetName];
        
        const headers = operation === 'carico'
          ? ["Codice Materiale", "Lotto", "DDT", "Quantita Netta", "Data", "Tara (Imballo)"]
          : ["Codice Materiale", "Lotto", "Quantita da Scaricare", "Unita", "Commessa Associata", "Note"];
          
        const json: any[] = XLSX.utils.sheet_to_json(worksheet, { header: headers, range: 1 });
        
        const validData = json
            .map((row, index) => {
              const materialCode = row['Codice Materiale']?.toString().trim().toLowerCase();
              const material = materialCode ? materialsMap.get(materialCode) : undefined;

              if (operation === 'carico' && material) {
                row['Unita'] = material.unitOfMeasure;
              }

              return { ...row, __originalIndex: index };
            })
            .filter(row => row['Codice Materiale'] && (row['Quantita Netta'] || row['Quantita da Scaricare']));

        setParsedData(validData);
        toast({ title: 'File analizzato', description: `${validData.length} righe valide trovate.` });
      } catch (error) {
        toast({ variant: 'destructive', title: 'Errore', description: 'Impossibile leggere o analizzare le file.' });
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsArrayBuffer(file);
     if (fileInputRef.current) {
        fileInputRef.current.value = "";
    }
  };

  const handleConfirmImport = async () => {
    if (!user || !operation) {
        toast({ variant: "destructive", title: "Errore", description: "Operazione o utente non validi."});
        return;
    }
    setIsProcessing(true);
    
    const action = operation === 'carico' ? importCaricoFromFile : importScaricoFromFile;
    const result = await action(parsedData, user.uid);

    if (result.success) {
        toast({
            title: 'Importazione Completata',
            description: result.message,
            variant: 'default',
        });
        clearData();
    } else {
        toast({
            title: 'Importazione Parziale/Fallita',
            description: result.message,
            variant: 'destructive',
            duration: 9000,
        });
        setParsedData(result.failedRows || []);
    }
    
    setIsProcessing(false);
  };
  
  const clearData = () => {
    setParsedData([]);
    setFileName('');
  }

  const renderHeaderAndTable = () => {
    const hasReasons = parsedData.some(r => r.reason);
    
    if (operation === 'carico') {
        return (
            <>
                <TableHeader className="sticky top-0 bg-muted"><TableRow>
                    <TableHead>Codice Materiale</TableHead><TableHead>Lotto</TableHead><TableHead>DDT</TableHead>
                    <TableHead>Quantit├á Netta</TableHead>
                    <TableHead>Unit├á</TableHead>
                    <TableHead>Data</TableHead>
                    {hasReasons && <TableHead className="text-destructive">Errore</TableHead>}
                </TableRow></TableHeader>
                <TableBody>
                    {parsedData.map((row, index) => (
                        <TableRow key={row.__originalIndex ?? index}>
                            <TableCell>{row["Codice Materiale"]}</TableCell><TableCell>{row["Lotto"]}</TableCell>
                            <TableCell>{row["DDT"]}</TableCell><TableCell>{row["Quantita Netta"]}</TableCell>
                             <TableCell>
                                <Badge variant={row['Unita'] ? 'secondary' : 'destructive'}>
                                  {String(row['Unita'] || '???').toUpperCase()}
                                </Badge>
                             </TableCell>
                            <TableCell>{typeof row["Data"] === 'number' ? new Date(Date.UTC(1899, 11, 30 + (row["Data"] as number))).toLocaleDateString('it-IT') : new Date(row["Data"] as string).toLocaleDateString('it-IT')}</TableCell>
                            {row.reason && <TableCell className="text-destructive text-xs font-semibold">{row.reason}</TableCell>}
                        </TableRow>
                    ))}
                </TableBody>
            </>
        );
    } else { // scarico
         return (
            <>
                <TableHeader className="sticky top-0 bg-muted"><TableRow>
                    <TableHead>Codice Materiale</TableHead><TableHead>Lotto</TableHead>
                    <TableHead>Q.t├á da Scaricare</TableHead><TableHead>Unit├á</TableHead>
                    <TableHead>Commessa</TableHead>
                    {hasReasons && <TableHead className="text-destructive">Errore</TableHead>}
                </TableRow></TableHeader>
                <TableBody>
                    {parsedData.map((row, index) => (
                        <TableRow key={row.__originalIndex ?? index}>
                            <TableCell>{row["Codice Materiale"]}</TableCell><TableCell>{row["Lotto"]}</TableCell>
                            <TableCell>{row["Quantita da Scaricare"]}</TableCell><TableCell>{row["Unita"]}</TableCell>
                            <TableCell>{row["Commessa Associata"]}</TableCell>
                            {row.reason && <TableCell className="text-destructive text-xs font-semibold">{row.reason}</TableCell>}
                        </TableRow>
                    ))}
                </TableBody>
            </>
        );
    }
  };

  return (
    <div className="space-y-6">
        {!operation ? (
            <Card>
                <CardHeader>
                    <CardTitle className="flex items-center gap-3"><Upload className="h-8 w-8 text-primary" />Carico/Scarico Merce da File</CardTitle>
                    <CardDescription>Seleziona l'operazione che vuoi eseguire.</CardDescription>
                </CardHeader>
                <CardContent className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-6">
                    <Button onClick={() => setOperation('carico')} variant="outline" className="h-28 text-lg flex-col gap-2 border-green-500/50 hover:bg-green-500/10 hover:text-green-700 dark:hover:text-green-400">
                        <FileUp className="h-8 w-8 text-green-500" />
                        Carico Merce
                    </Button>
                    <Button onClick={() => setOperation('scarico')} variant="outline" className="h-28 text-lg flex-col gap-2 border-red-500/50 hover:bg-red-500/10 hover:text-red-700 dark:hover:text-red-400">
                        <FileDown className="h-8 w-8 text-red-500" />
                        Scarico Merce
                    </Button>
                </CardContent>
            </Card>
        ) : (
        <>
          <Button variant="ghost" onClick={() => { setOperation(null); clearData(); }}>
            <ArrowLeft className="mr-2"/>
            Torna alla selezione
          </Button>
          <Card>
            <CardHeader>
              <CardTitle className="capitalize">{operation} Merce da File</CardTitle>
              <CardDescription>Scarica il template, compilalo e carica il file per avviare l'importazione.</CardDescription>
            </CardHeader>
            <CardContent className="flex flex-wrap items-center gap-4">
              <Button onClick={handleDownloadTemplate} variant="secondary">
                <Download className="mr-2" />
                Scarica Template
              </Button>
               <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" className="hidden" />
               <Button onClick={() => fileInputRef.current?.click()} disabled={isProcessing}>
                <Upload className="mr-2" />
                Seleziona File Excel
              </Button>
              {fileName && <p className="text-sm text-muted-foreground">File selezionato: {fileName}</p>}
            </CardContent>
          </Card>

          {parsedData.length > 0 && (
            <Card className={cn(parsedData.some(r => r.reason) && "border-destructive")}>
                <CardHeader>
                    <div className="flex justify-between items-center">
                        <div className="space-y-1">
                            <CardTitle className="flex items-center gap-2">
                                {parsedData.some(r => r.reason) ? <XCircle className="text-destructive"/> : <List className="h-6 w-6"/>}
                                Anteprima Dati
                            </CardTitle>
                            <CardDescription>
                                {parsedData.some(r => r.reason) 
                                    ? "Alcune righe presentano errori. Correggi il file Excel o procedi ignorando le righe errate." 
                                    : "Controlla i dati letti dal file. Se sono corretti, procedi con l'importazione."
                                }
                            </CardDescription>
                        </div>
                        <Button variant="destructive" size="sm" onClick={clearData}>
                            <Trash2 className="mr-2"/>
                            Annulla e Svuota
                        </Button>
                    </div>
                </CardHeader>
                <CardContent>
                    <ScrollArea className="h-96 border rounded-lg">
                        <Table>{renderHeaderAndTable()}</Table>
                    </ScrollArea>
                </CardContent>
                <CardFooter>
                     <AlertDialog>
                        <AlertDialogTrigger asChild>
                          <Button className="w-full" disabled={isProcessing || parsedData.length === 0}>
                            {isProcessing ? <Loader2 className="mr-2 animate-spin"/> : <Send className="mr-2" />}
                            Conferma e Importa {parsedData.filter(r => !r.reason).length} righe valide
                          </Button>
                        </AlertDialogTrigger>
                        <AlertDialogContent>
                          <AlertDialogHeader>
                            <AlertDialogTitle className="flex items-center gap-2"><AlertTriangle/> Sei assolutamente sicuro?</AlertDialogTitle>
                            <AlertDialogDescription>
                               Stai per eseguire un {operation} massivo per {parsedData.filter(r => !r.reason).length} righe. L'operazione aggiorner├á lo stock dei materiali. Questa azione non pu├▓ essere annullata facilmente.
                            </AlertDialogDescription>
                          </AlertDialogHeader>
                          <AlertDialogFooter>
                            <AlertDialogCancel>Annulla</AlertDialogCancel>
                            <AlertDialogAction onClick={handleConfirmImport} disabled={isProcessing}>
                                {isProcessing ? <Loader2 className="mr-2 animate-spin"/> : null}
                                S├¼, importa
                            </AlertDialogAction>
                          </AlertDialogFooter>
                        </AlertDialogContent>
                      </AlertDialog>
                </CardFooter>
            </Card>
          )}
        </>
        )}
    </div>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';
import * as XLSX from 'xlsx';

import { type Operator, type Department } from '@/lib/mock-data';
import { saveOperator, deleteOperator } from './actions';
import { cn } from '@/lib/utils';
import type { StatoOperatore, OperatorRole } from '@/lib/mock-data';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage, FormDescription } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from '@/components/ui/badge';
import { Users, PlusCircle, Edit, Trash2, CheckCircle2, ShieldAlert, Download, Mail, Loader2, Warehouse, MinusSquare, UserCheck, UserX } from 'lucide-react';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { useRouter } from 'next/navigation';
import { Switch } from '@/components/ui/switch';


const operatorFormSchema = z.object({
  id: z.string().optional(),
  nome: z.string().min(1, "Il nome ├¿ obbligatorio."),
  email: z.string().email("Formato email non valido.").refine(email => email.endsWith('@prodfastxcan.app'), {
    message: "L'email deve terminare con @prodfastxcan.app",
  }),
  reparto: z.array(z.string()).max(3, "Puoi selezionare al massimo 3 reparti.").optional(),
  role: z.enum(['admin', 'supervisor', 'operator']),
  canAccessInventory: z.boolean().optional(),
  canAccessMaterialWithdrawal: z.boolean().optional(),
  isReal: z.boolean().optional(),
}).refine(data => {
  if (data.role === 'operator') {
    return data.reparto && data.reparto.length > 0;
  }
  return true;
}, {
  message: "Selezionare almeno un reparto per il ruolo operatore.",
  path: ["reparto"],
});

type OperatorFormValues = z.infer<typeof operatorFormSchema>;

const StatusBadge = ({ status }: { status: StatoOperatore }) => (
  <Badge
    className={cn(
      "text-xs font-semibold",
      status === 'attivo' && "bg-green-500/20 text-green-700 border-green-400",
      status === 'inattivo' && "bg-gray-500/20 text-gray-700 border-gray-400",
      status === 'in pausa' && "bg-orange-500/20 text-orange-700 border-orange-400"
    )}
    variant="outline"
  >
    {status.charAt(0).toUpperCase() + status.slice(1)}
  </Badge>
);

interface OperatorManagementClientPageProps {
  initialOperators: Operator[];
  initialDepartments: Department[];
}

export default function OperatorManagementClientPage({ initialOperators, initialDepartments }: OperatorManagementClientPageProps) {
  const [operators, setOperators] = useState<Operator[]>(initialOperators);
  const [departments, setDepartments] = useState<Department[]>(initialDepartments);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingOperator, setEditingOperator] = useState<Operator | null>(null);
  const { toast } = useToast();
  const router = useRouter();

  const form = useForm<OperatorFormValues>({
    resolver: zodResolver(operatorFormSchema),
    defaultValues: {
      id: undefined,
      nome: "",
      email: "",
      reparto: [],
      role: 'operator',
      canAccessInventory: false,
      canAccessMaterialWithdrawal: false,
      isReal: true,
    },
  });

  const watchedRole = form.watch('role');
  const roles: OperatorRole[] = ['admin', 'supervisor', 'operator'];

  useEffect(() => {
    setDepartments(initialDepartments);
  }, [initialDepartments]);

  useEffect(() => {
    if (watchedRole === 'admin' || watchedRole === 'supervisor') {
      form.setValue('reparto', []);
    }
  }, [watchedRole, form]);

  const refreshData = () => {
    router.refresh();
  };

  const handleOpenDialog = (operator: Operator | null = null) => {
    setEditingOperator(operator);
    if (operator) {
      form.reset({
        id: operator.id,
        nome: operator.nome,
        email: operator.email || '',
        reparto: operator.reparto || [],
        role: operator.role,
        canAccessInventory: operator.canAccessInventory || false,
        canAccessMaterialWithdrawal: operator.canAccessMaterialWithdrawal || false,
        isReal: operator.isReal !== undefined ? operator.isReal : true,
      });
    } else {
      form.reset({ id: undefined, nome: "", email: "", reparto: [], role: 'operator', canAccessInventory: false, canAccessMaterialWithdrawal: false, isReal: true });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingOperator(null);
    form.reset();
  }

  const onSubmit = async (values: OperatorFormValues) => {
    const result = await saveOperator(values);

    if (result.success) {
      toast({ title: "Successo", description: result.message });
      refreshData();
      handleCloseDialog();
    } else {
      toast({
        variant: "destructive",
        title: "Errore",
        description: result.message || "Impossibile salvare l'operatore.",
      });
    }
  };

  const handleDelete = async (id: string) => {
    const result = await deleteOperator(id);
    if (result.success) {
      toast({ title: "Successo", description: result.message });
      refreshData();
    } else {
      toast({ variant: "destructive", title: "Errore", description: result.message });
    }
  };

  const handleExport = () => {
    const dataToExport = operators.map(op => ({
      'ID': op.id,
      'Nome': op.nome,
      'Email': op.email,
      'Reparto': (op.reparto || []).map(r => departments.find(d => d.code === r)?.name || r).join(', '),
      'Ruolo': op.role,
      'Stato': op.stato,
      'Operatore Reale': op.isReal ? 'S├¼' : 'No',
      'Privacy Firmata': op.privacySigned ? 'S├¼' : 'No',
      'Accesso Inventario': op.canAccessInventory ? 'S├¼' : 'No',
      'Accesso Scarico Materiale': op.canAccessMaterialWithdrawal ? 'S├¼' : 'No',
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Operatori");
    XLSX.writeFile(wb, "elenco_operatori.xlsx");
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-start gap-4 flex-wrap">
        <header>
          <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
            <Users className="h-8 w-8 text-primary" />
            Gestione Operatori
          </h1>
          <p className="text-muted-foreground mt-1">
            Aggiungi, modifica o elimina gli account degli operatori.
          </p>
        </header>
        <div className="flex items-center gap-2 pt-2">
          <Button onClick={handleExport} variant="outline" disabled={operators.length === 0}>
            <Download className="mr-2 h-4 w-4" />
            Esporta Operatori
          </Button>
          <Button onClick={() => handleOpenDialog()}>
            <PlusCircle className="mr-2 h-4 w-4" />
            Aggiungi Operatore
          </Button>
        </div>
      </div>

      <Card>
        <CardHeader>
          <CardTitle>Elenco Operatori</CardTitle>
          <CardDescription>Aggiungi, modifica o elimina gli account degli operatori.</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Reale</TableHead>
                  <TableHead>Nome</TableHead>
                  <TableHead>Email</TableHead>
                  <TableHead>Reparto</TableHead>
                  <TableHead>Ruolo</TableHead>
                  <TableHead>Stato</TableHead>
                  <TableHead>Privacy</TableHead>
                  <TableHead>Permessi</TableHead>
                  <TableHead className="text-right">Azioni</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {operators.length > 0 ? (
                  operators.map((op) => {
                    const opReparti = op.reparto || [];

                    return (
                      <TableRow key={op.id}>
                        <TableCell className="text-center">
                          <TooltipProvider>
                            <Tooltip>
                              <TooltipTrigger asChild>
                                <div className="flex justify-center">
                                  {op.isReal !== false ? (
                                    <UserCheck className="h-5 w-5 text-green-500" />
                                  ) : (
                                    <UserX className="h-5 w-5 text-muted-foreground opacity-50" />
                                  )}
                                </div>
                              </TooltipTrigger>
                              <TooltipContent>
                                <p>{op.isReal !== false ? 'Lavoratore Reale (Incluso in Capacit├á)' : 'Profilo Sviluppo/Test'}</p>
                              </TooltipContent>
                            </Tooltip>
                          </TooltipProvider>
                        </TableCell>
                        <TableCell className="font-medium">{op.nome}</TableCell>
                        <TableCell>{op.email}</TableCell>
                        <TableCell>
                          <div className="flex flex-wrap gap-1">
                            {op.role === 'supervisor' ? (
                              <Badge variant="secondary">Officina</Badge>
                            ) : (
                              opReparti.map(r => <Badge key={r} variant="secondary">{departments.find(d => d.code === r)?.name || r}</Badge>)
                            )}
                          </div>
                        </TableCell>
                        <TableCell className="capitalize">{op.role}</TableCell>
                        <TableCell><StatusBadge status={op.stato} /></TableCell>
                        <TableCell>
                          <TooltipProvider>
                            <Tooltip>
                              <TooltipTrigger asChild>
                                <div className="flex items-center justify-center">
                                  {op.privacySigned ? (
                                    <CheckCircle2 className="h-5 w-5 text-green-500" />
                                  ) : (
                                    <ShieldAlert className="h-5 w-5 text-yellow-500" />
                                  )}
                                </div>
                              </TooltipTrigger>
                              <TooltipContent>
                                <p>{op.privacySigned ? 'Informativa Firmata' : 'Informativa Non Firmata'}</p>
                              </TooltipContent>
                            </Tooltip>
                          </TooltipProvider>
                        </TableCell>
                        <TableCell>
                          <div className="flex items-center justify-center gap-2">
                            <TooltipProvider>
                              <Tooltip>
                                <TooltipTrigger asChild>
                                  <div>
                                    {op.canAccessInventory ? (
                                      <Warehouse className="h-5 w-5 text-green-500" />
                                    ) : (
                                      <Warehouse className="h-5 w-5 text-muted-foreground opacity-50" />
                                    )}
                                  </div>
                                </TooltipTrigger>
                                <TooltipContent>
                                  <p>{op.canAccessInventory ? 'Accesso Inventario Abilitato' : 'Accesso Inventario Disabilitato'}</p>
                                </TooltipContent>
                              </Tooltip>
                            </TooltipProvider>
                            <TooltipProvider>
                              <Tooltip>
                                <TooltipTrigger asChild>
                                  <div>
                                    {op.canAccessMaterialWithdrawal ? (
                                      <MinusSquare className="h-5 w-5 text-green-500" />
                                    ) : (
                                      <MinusSquare className="h-5 w-5 text-muted-foreground opacity-50" />
                                    )}
                                  </div>
                                </TooltipTrigger>
                                <TooltipContent>
                                  <p>{op.canAccessMaterialWithdrawal ? 'Accesso Scarico Materiale Abilitato' : 'Accesso Scarico Materiale Disabilitato'}</p>
                                </TooltipContent>
                              </Tooltip>
                            </TooltipProvider>
                          </div>
                        </TableCell>
                        <TableCell className="text-right space-x-2">
                          <Button variant="outline" size="icon" onClick={() => handleOpenDialog(op)}>
                            <Edit className="h-4 w-4" />
                            <span className="sr-only">Modifica</span>
                          </Button>
                          <AlertDialog>
                            <AlertDialogTrigger asChild>
                              <Button variant="destructive" size="icon">
                                <Trash2 className="h-4 w-4" />
                                <span className="sr-only">Elimina</span>
                              </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                              <AlertDialogHeader>
                                <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                <AlertDialogDescription>
                                  Questa azione non pu├▓ essere annullata. L'operatore verr├á eliminato definitivamente.
                                </AlertDialogDescription>
                              </AlertDialogHeader>
                              <AlertDialogFooter>
                                <AlertDialogCancel>Annulla</AlertDialogCancel>
                                <AlertDialogAction onClick={() => handleDelete(op.id)}>Continua</AlertDialogAction>
                              </AlertDialogFooter>
                            </AlertDialogContent>
                          </AlertDialog>
                        </TableCell>
                      </TableRow>
                    )
                  })
                ) : (
                  <TableRow>
                    <TableCell colSpan={9} className="text-center h-24">Nessun operatore trovato.</TableCell>
                  </TableRow>
                )}
