            <DialogDescription>
              {editingOperator ? "Modifica i dettagli dell'operatore." : "Compila i campi per aggiungere un nuovo operatore. L'email deve corrispondere a quella dell'utente creato in Firebase Authentication."}
            </DialogDescription>
          </DialogHeader>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4">
              <FormField control={form.control} name="nome" render={({ field }) => (
                <FormItem>
                  <FormLabel>Nome</FormLabel>
                  <FormControl><Input placeholder="Es. Mario" {...field} /></FormControl>
                  <FormMessage />
                </FormItem>
              )} />
              <FormField control={form.control} name="email" render={({ field }) => (
                <FormItem>
                  <FormLabel className="flex items-center"><Mail className="mr-2 h-4 w-4" />Email (per il login)</FormLabel>
                  <FormControl><Input type="email" placeholder="es. m.rossi@prodfastxcan.app" {...field} /></FormControl>
                  <FormMessage />
                </FormItem>
              )} />
              <FormField control={form.control} name="role" render={({ field }) => (
                <FormItem>
                  <FormLabel>Ruolo</FormLabel>
                  <Select onValueChange={field.onChange} value={field.value}>
                    <FormControl>
                      <SelectTrigger>
                        <SelectValue placeholder="Seleziona un ruolo" />
                      </SelectTrigger>
                    </FormControl>
                    <SelectContent>
                      {roles.map(r => <SelectItem key={r} value={r} className="capitalize">{r}</SelectItem>)}
                    </SelectContent>
                  </Select>
                  <FormMessage />
                </FormItem>
              )} />
              {watchedRole === 'operator' && (
                <FormField
                  control={form.control}
                  name="reparto"
                  render={({ field }) => (
                    <FormItem>
                      <div className="mb-4">
                        <FormLabel>Reparti di Competenza</FormLabel>
                        <FormDescription>
                          Seleziona uno o pi├╣ reparti (max 3).
                        </FormDescription>
                      </div>
                      <div className="space-y-2">
                        {departments.map((item) => (
                          <FormItem
                            key={item.id}
                            className="flex flex-row items-start space-x-3 space-y-0"
                          >
                            <FormControl>
                              <Checkbox
                                checked={field.value?.includes(item.code)}
                                onCheckedChange={(checked) => {
                                  const currentValue = field.value || [];
                                  const newValue = checked
                                    ? [...currentValue, item.code]
                                    : currentValue.filter(
                                      (value) => value !== item.code
                                    );
                                  field.onChange(newValue);
                                }}
                              />
                            </FormControl>
                            <FormLabel className="font-normal">
                              {item.name}
                            </FormLabel>
                          </FormItem>
                        ))}
                      </div>
                      <FormMessage />
                    </FormItem>
                  )}
                />
              )}

              <FormField
                control={form.control}
                name="isReal"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4 bg-primary/5 border-primary/20">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base flex items-center gap-2">
                        <UserCheck className="h-5 w-5 text-primary" />
                        Lavoratore Reale
                      </FormLabel>
                      <FormDescription>
                        Spegni se il profilo ├¿ usato solo per test o sviluppo.
                      </FormDescription>
                    </div>
                    <FormControl>
                      <Switch
                        checked={field.value}
                        onCheckedChange={field.onChange}
                      />
                    </FormControl>
                  </FormItem>
                )}
              />

              <FormField
                control={form.control}
                name="canAccessInventory"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base flex items-center gap-2">
                        <Warehouse className="h-5 w-5" />
                        Accesso a Inventario
                      </FormLabel>
                      <FormDescription>
                        Consenti a questo operatore di accedere alla sezione Inventario.
                      </FormDescription>
                    </div>
                    <FormControl>
                      <Checkbox
                        checked={field.value}
                        onCheckedChange={field.onChange}
                      />
                    </FormControl>
                  </FormItem>
                )}
              />
              <FormField
                control={form.control}
                name="canAccessMaterialWithdrawal"
                render={({ field }) => (
                  <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                    <div className="space-y-0.5">
                      <FormLabel className="text-base flex items-center gap-2">
                        <MinusSquare className="h-5 w-5" />
                        Accesso Scarico Materiale
                      </FormLabel>
                      <FormDescription>
                        Consenti di registrare uno scarico manuale di materiale.
                      </FormDescription>
                    </div>
                    <FormControl>
                      <Checkbox
                        checked={field.value}
                        onCheckedChange={field.onChange}
                      />
                    </FormControl>
                  </FormItem>
                )}
              />
              <DialogFooter className="pt-4">
                <Button type="button" variant="outline" onClick={handleCloseDialog}>Annulla</Button>
                <Button type="submit">{editingOperator ? "Salva Modifiche" : "Aggiungi Operatore"}</Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>

    </div>
  );
}

"use client";

import React, { useState, useEffect, useTransition } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';

import { type Packaging, type PackagingAssociation, RawMaterialTypeValues } from '@/lib/mock-data';
import { getPackagingItems, savePackagingItem, deletePackagingItem } from './actions';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage, FormDescription } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Checkbox } from '@/components/ui/checkbox';
import { Badge } from '@/components/ui/badge';
import { Archive, PlusCircle, Edit, Trash2, Loader2, Weight, Link2 } from 'lucide-react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';

const packagingAssociationTypes: PackagingAssociation[] = [...RawMaterialTypeValues, 'PRODOTTO'];

const packagingSchema = z.object({
  id: z.string().optional(),
  name: z.string().min(3, 'Il nome deve avere almeno 3 caratteri.'),
  description: z.string().optional(),
  weightKg: z.coerce.number().min(0, 'Il peso non pu├▓ essere negativo.'),
  associatedTypes: z.array(z.string()).optional(),
});

type PackagingFormValues = z.infer<typeof packagingSchema>;

export default function PackagingManagementPage() {
  const [items, setItems] = useState<Packaging[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Packaging | null>(null);
  const [isPending, setIsPending] = useState(false);
  const { toast } = useToast();

  const form = useForm<PackagingFormValues>({
    resolver: zodResolver(packagingSchema),
    defaultValues: { id: undefined, name: "", description: "", weightKg: 0, associatedTypes: [] },
  });

  const fetchData = async () => {
    setIsLoading(true);
    const data = await getPackagingItems();
    setItems(data);
    setIsLoading(false);
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleOpenDialog = (item: Packaging | null = null) => {
    setEditingItem(item);
    if (item) {
      form.reset({
        ...item,
        associatedTypes: item.associatedTypes || [],
      });
    } else {
      form.reset({ id: undefined, name: "", description: "", weightKg: 0, associatedTypes: [] });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingItem(null);
    form.reset();
  };

  const onSubmit = async (values: PackagingFormValues) => {
    const formData = new FormData();
    Object.entries(values).forEach(([key, value]) => {
      if (key === 'associatedTypes' && Array.isArray(value)) {
        value.forEach(v => formData.append(key, v));
      } else if (value !== undefined && value !== null) {
        formData.append(key, String(value));
      }
    });
    
    setIsPending(true);
    const result = await savePackagingItem(formData);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
        await fetchData();
        handleCloseDialog();
    }
    setIsPending(false);
  };

  const handleDelete = async (id: string) => {
    setIsPending(true);
    const result = await deletePackagingItem(id);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) await fetchData();
    setIsPending(false);
  };
  
  const renderLoading = () => (
      <TableRow>
          <TableCell colSpan={5} className="h-24 text-center">
              <div className="flex items-center justify-center gap-2 text-muted-foreground">
                  <Loader2 className="h-5 w-5 animate-spin" />
                  <span>Caricamento imballi...</span>
              </div>
          </TableCell>
      </TableRow>
  );

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <div className="flex justify-between items-center">
            <header>
              <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                <Archive className="h-8 w-8 text-primary" />
                Gestione Imballi (Tare)
              </h1>
              <p className="text-muted-foreground mt-2">
                Definisci gli imballi e le relative tare da associare ai materiali.
              </p>
            </header>
            <div className="flex items-center gap-2">
                <Button onClick={() => handleOpenDialog()} disabled={isLoading}>
                    <PlusCircle className="mr-2 h-4 w-4" />
                    Nuovo Imballo
                </Button>
            </div>
          </div>

          <Card>
            <CardHeader>
              <CardTitle>Anagrafica Imballi</CardTitle>
              <CardDescription>Elenco degli imballi, del loro peso (tara) e a cosa sono associati.</CardDescription>
            </CardHeader>
            <CardContent>
              <div className="overflow-x-auto">
                <Table>
                  <TableHeader>
                    <TableRow>
                      <TableHead>Nome Imballo</TableHead>
                      <TableHead>Descrizione</TableHead>
                      <TableHead>Peso (Kg)</TableHead>
                      <TableHead>Associazione</TableHead>
                      <TableHead className="text-right">Azioni</TableHead>
                    </TableRow>
                  </TableHeader>
                  <TableBody>
                    {isLoading ? renderLoading() : items.length > 0 ? (
                      items.map((item) => (
                        <TableRow key={item.id}>
                          <TableCell className="font-medium">{item.name}</TableCell>
                          <TableCell>{item.description || 'N/D'}</TableCell>
                          <TableCell>{Number(item.weightKg)}</TableCell>
                           <TableCell>
                            <div className="flex flex-wrap gap-1">
                                {item.associatedTypes && item.associatedTypes.length > 0 ? 
                                item.associatedTypes.map(type => <Badge key={type} variant="outline">{type}</Badge>) :
                                <span className="text-xs text-muted-foreground">Nessuna</span>
                                }
                            </div>
                           </TableCell>
                          <TableCell className="text-right space-x-2">
                            <Button variant="outline" size="icon" onClick={() => handleOpenDialog(item)}>
                              <Edit className="h-4 w-4" />
                            </Button>
                            <AlertDialog>
                              <AlertDialogTrigger asChild>
                                <Button variant="destructive" size="icon">
                                  <Trash2 className="h-4 w-4" />
                                </Button>
                              </AlertDialogTrigger>
                              <AlertDialogContent>
                                <AlertDialogHeader>
                                  <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                  <AlertDialogDescription>
                                    Questa azione non pu├▓ essere annullata. L'imballo verr├á eliminato.
                                  </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                  <AlertDialogCancel>Annulla</AlertDialogCancel>
                                  <AlertDialogAction onClick={() => handleDelete(item.id)}>Continua</AlertDialogAction>
                                </AlertDialogFooter>
                              </AlertDialogContent>
                            </AlertDialog>
                          </TableCell>
                        </TableRow>
                      ))
                    ) : (
                      <TableRow>
                        <TableCell colSpan={5} className="text-center h-24">Nessun imballo trovato.</TableCell>
                      </TableRow>
                    )}
                  </TableBody>
                </Table>
              </div>
            </CardContent>
          </Card>
        
        <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
          <DialogContent className="sm:max-w-md" onInteractOutside={(e) => {if (!isPending) handleCloseDialog();}}>
            <DialogHeader>
              <DialogTitle>{editingItem ? "Modifica Imballo" : "Aggiungi Nuovo Imballo"}</DialogTitle>
              <DialogDescription>
                Compila i campi per definire un nuovo tipo di imballo e la sua tara.
              </DialogDescription>
            </DialogHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4 max-h-[70vh] overflow-y-auto pr-4">
                <FormField control={form.control} name="name" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Nome</FormLabel>
                    <FormControl><Input placeholder="Es. Rocchetto Grande" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="description" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Descrizione (Opzionale)</FormLabel>
                    <FormControl><Input placeholder="Materiale, dimensioni, etc." {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="weightKg" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Peso / Tara (Kg)</FormLabel>
                     <div className="relative">
                        <Weight className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <FormControl><Input type="number" step="0.001" placeholder="Es. 0.150" className="pl-9" {...field} /></FormControl>
                     </div>
                    <FormMessage />
                  </FormItem>
                )} />

                <FormField
                    control={form.control}
                    name="associatedTypes"
                    render={() => (
                      <FormItem>
                        <div className="mb-4">
                          <FormLabel className="flex items-center gap-2"><Link2 className="h-4 w-4"/> Associazione</FormLabel>
                          <FormDescription>
                            Seleziona per cosa pu├▓ essere usato questo imballo.
                          </FormDescription>
                        </div>
                        <div className="grid grid-cols-2 gap-2 p-4 border rounded-md">
                        {packagingAssociationTypes.map((item) => (
                          <FormField
                            key={item}
                            control={form.control}
                            name="associatedTypes"
                            render={({ field }) => {
                              return (
                                <FormItem
                                  key={item}
                                  className="flex flex-row items-start space-x-3 space-y-0"
                                >
                                  <FormControl>
                                    <Checkbox
                                      checked={field.value?.includes(item)}
                                      onCheckedChange={(checked) => {
                                        const currentValue = field.value || [];
                                        return checked
                                          ? field.onChange([...currentValue, item])
                                          : field.onChange(currentValue.filter((value) => value !== item));
                                      }}
                                    />
                                  </FormControl>
                                  <FormLabel className="font-normal">
                                    {item}
                                  </FormLabel>
                                </FormItem>
                              )
                            }}
                          />
                        ))}
                        </div>
                        <FormMessage />
                      </FormItem>
                    )}
                  />


                <DialogFooter>
                  <Button type="button" variant="outline" onClick={handleCloseDialog} disabled={isPending}>Annulla</Button>
                  <Button type="submit" disabled={isPending}>
                    {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                    {editingItem ? "Salva Modifiche" : "Crea Imballo"}
                  </Button>
                </DialogFooter>
              </form>
            </Form>
          </DialogContent>
        </Dialog>
      </div>
    </AppShell>
  </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { LockKeyhole, Save, Loader2, RefreshCw } from 'lucide-react';
import { getPrivacyPolicy, savePrivacyPolicy } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { format } from 'date-fns';
import { it } from 'date-fns/locale';
import { Textarea } from '@/components/ui/textarea';
import { Skeleton } from '@/components/ui/skeleton';


export default function PrivacyManagementPage() {
  const [policy, setPolicy] = useState<{ content: string, lastUpdated: string | null }>({ content: '', lastUpdated: null });
  const [editedContent, setEditedContent] = useState('');
  const [isLoading, setIsLoading] = useState(true);
  const [isPending, setIsPending] = useState(false);
  const { user } = useAuth();
  const { toast } = useToast();
  
  const fetchPolicy = async () => {
    setIsLoading(true);
    try {
        const data = await getPrivacyPolicy();
        setPolicy(data);
        // Convert simple HTML to text for textarea
        setEditedContent(data.content.replace(/<p>/g, '').replace(/<\/p>/g, '\n\n').replace(/<strong>/g, '').replace(/<\/strong>/g, '').trim());
    } catch (error) {
        toast({
            variant: "destructive",
            title: "Errore",
            description: "Impossibile caricare l'informativa sulla privacy.",
        });
    }
    setIsLoading(false);
  };

  useEffect(() => {
    fetchPolicy();
  }, []);

  const handleSave = async () => {
    if (!user) return;
    setIsPending(true);
    // Convert text back to simple HTML
    const htmlContent = editedContent
      .split('\n')
      .filter(p => p.trim() !== '')
      .map(p => `<p>${p}</p>`)
      .join('');
      
    const result = await savePrivacyPolicy(htmlContent, user.uid);
    toast({
      title: result.success ? "Operazione Completata" : "Operazione Fallita",
      description: result.message,
      variant: result.success ? "default" : "destructive",
      duration: 9000,
    });
    if (result.success) {
      await fetchPolicy();
    }
    setIsPending(false);
  };

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <LockKeyhole className="h-8 w-8 text-primary" />
              Gestione Informativa Privacy
            </h1>
            <p className="text-muted-foreground">
              Modifica il testo dell'informativa sulla privacy che gli operatori devono accettare al primo accesso o dopo una modifica.
            </p>
          </header>

          <Card>
            <CardHeader>
              <div className="flex justify-between items-center flex-wrap gap-2">
                <div>
                    <CardTitle>Editor Informativa</CardTitle>
                    <CardDescription>
                        {policy.lastUpdated 
                            ? `Ultimo aggiornamento: ${format(new Date(policy.lastUpdated), 'dd MMMM yyyy HH:mm', { locale: it })}`
                            : "Nessuna modifica ancora salvata."}
                    </CardDescription>
                </div>
                <Button onClick={handleSave} disabled={isPending || isLoading || editedContent === policy.content}>
                    {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Save className="mr-2 h-4 w-4" />}
                    Salva e Richiedi Nuova Firma
                </Button>
              </div>
            </CardHeader>
            <CardContent>
              {isLoading ? (
                <div className="space-y-2">
                  <Skeleton className="h-40 w-full" />
                </div>
              ) : (
                <Textarea
                    value={editedContent}
                    onChange={(e) => setEditedContent(e.target.value)}
                    className="w-full h-80 p-4 border rounded-md bg-background"
                    placeholder="Scrivi qui il testo dell'informativa..."
                />
              )}
            </CardContent>
          </Card>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

import type { JobOrder, JobPhase, Operator } from '@/lib/mock-data';
import type { OverallStatus } from '@/lib/types';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { StatusBadge } from '@/components/production-console/StatusBadge';
import { Package, Building, Circle, Hourglass, CheckCircle2, ShieldAlert, PauseCircle, Calendar, Printer, MoreVertical, FastForward, CheckSquare, CornerDownRight, CornerUpLeft, Undo2, ClipboardList, Factory, Users, PowerOff, RefreshCcw, EyeOff, ListOrdered, ArrowUp, ArrowDown, ArchiveRestore, Boxes, User, BarChart3, Copy, Timer, HelpCircle, ChevronDown } from 'lucide-react';
import { format, parseISO, isPast, differenceInSeconds } from 'date-fns';
import Link from 'next/link';
import { it } from 'date-fns/locale';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { TooltipProvider, Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import React, { useState, useMemo, useEffect } from 'react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import type { ProductionTimeData } from '@/app/admin/production-console/actions';
import { Loader2 } from 'lucide-react';


interface ActivePhaseInfo {
  phaseId: string;
  phaseName: string;
  operators: { id: string; name: string }[];
}

function getPhaseIcon(status: JobPhase['status']) {
  switch (status) {
    case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
    case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
    case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
    case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
    case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
    default: return <Circle className="h-4 w-4 text-muted-foreground" />;
  }
}

function formatTime(seconds: number): string {
    if (seconds < 0) seconds = 0;
    const totalMinutes = Math.round(seconds / 60);
    const h = Math.floor(totalMinutes / 60);
    const m = totalMinutes % 60;
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
}

function PhaseLiveTimer({ phase }: { phase: JobPhase }) {
  const [elapsedTime, setElapsedTime] = useState('00:00');

  useEffect(() => {
    let interval: NodeJS.Timeout;

    const activeWorkPeriod = phase.workPeriods?.find(wp => wp.end === null);

    if (phase.status === 'in-progress' && activeWorkPeriod) {
      const startTime = new Date(activeWorkPeriod.start).getTime();
      
      const updateTimer = () => {
        const now = Date.now();
        const totalSeconds = Math.floor((now - startTime) / 1000);
        setElapsedTime(formatTime(totalSeconds));
      };

      updateTimer(); // Initial update
      interval = setInterval(updateTimer, 1000);
    } else {
        const totalSeconds = (phase.workPeriods || []).reduce((acc, wp) => {
            if(wp.end) {
                return acc + differenceInSeconds(new Date(wp.end), new Date(wp.start));
            }
            return acc;
        }, 0);
        setElapsedTime(formatTime(totalSeconds));
    }

    return () => clearInterval(interval);
  }, [phase]);

  return <p className="font-mono text-lg">{elapsedTime}</p>;
}


export default function JobOrderCard({ 
    jobOrder,
    allOperators,
    analysisData,
    onFetchAnalysis,
    isAnalysisLoading,
    groupPhases,
    onProblemClick, 
    onForceFinishClick,
    onRevertForceFinishClick,
    onToggleGuainaClick, 
    onRevertPhaseClick, 
    onForcePauseClick,
    onForceCompleteClick,
    onResetJobOrderClick,
    onOpenPhaseManager,
    onOpenMaterialManager,
    onRevertCompletionClick,
    isSelected,
    onSelect,
    overallStatus,
    onNavigateToAnalysis,
    onCopyArticleCode,
}: { 
    jobOrder: JobOrder;
    allOperators: Operator[];
    analysisData?: ProductionTimeData | null;
    onFetchAnalysis: () => void;
    isAnalysisLoading: boolean;
    groupPhases?: JobPhase[];
    onProblemClick: () => void; 
    onForceFinishClick: (jobId: string) => void;
    onRevertForceFinishClick: (jobId: string) => void;
    onToggleGuainaClick: (jobId: string, phaseId: string, currentState: 'default' | 'postponed') => void; 
    onRevertPhaseClick: (jobId: string, phaseId: string) => void; 
    onForcePauseClick: (jobId: string, operatorIds: string[]) => void; 
    onForceCompleteClick: (jobId: string) => void;
    onResetJobOrderClick: (jobId: string) => void;
    onOpenPhaseManager: (item: JobOrder) => void;
    onOpenMaterialManager: (item: JobOrder) => void;
    onRevertCompletionClick: (jobId: string) => void;
    isSelected: boolean;
    onSelect: (jobId: string) => void;
    overallStatus: OverallStatus;
    onNavigateToAnalysis: (articleCode: string) => void;
    onCopyArticleCode: (articleCode: string) => void;
}) {
  const [isPauseDialogOpen, setIsPauseDialogOpen] = useState(false);
  const [selectedOperatorsToPause, setSelectedOperatorsToPause] = useState<string[]>([]);
  const hasMaterialMissing = jobOrder.phases.some(p => p.materialStatus === 'missing');
  const [remainingTime, setRemainingTime] = useState<string | null>(null);

   const updateRemainingTime = React.useCallback(() => {
    if (!analysisData || !analysisData.isTimeCalculationReliable) {
      setRemainingTime(null);
      return;
    }
    const completedPhasesTotalMinutes = jobOrder.phases
      .filter(p => p.status === 'completed' && analysisData.phases[p.name])
      .reduce((acc, p) => acc + (analysisData.phases[p.name].averageMinutesPerPiece * jobOrder.qta), 0);

    const totalEstimatedMinutes = analysisData.averageMinutesPerPiece * jobOrder.qta;
    const remainingMinutes = totalEstimatedMinutes - completedPhasesTotalMinutes;
    
    setRemainingTime(formatTime(remainingMinutes * 60));
  }, [analysisData, jobOrder]);
  
  useEffect(() => {
    // We only automatically calculate the time if the data is already present.
    if (analysisData) {
      updateRemainingTime();
    }
  }, [analysisData, updateRemainingTime]);


  const activePhasesWithOperators = useMemo((): ActivePhaseInfo[] => {
    const activePhasesMap = new Map<string, ActivePhaseInfo>();
    const phasesToInspect = groupPhases || jobOrder.phases || [];
    
    phasesToInspect.forEach(phase => {
        if (phase.status === 'in-progress') {
            const phaseOperators: ActivePhaseInfo['operators'] = [];
            (phase.workPeriods || []).forEach(wp => {
                if (wp.end === null) {
                    const operator = allOperators.find(op => op.id === wp.operatorId);
                    if (operator) {
                        phaseOperators.push({ id: operator.id, name: operator.nome });
                    }
                }
            });

            // Filter out duplicates before adding to the map
            const uniqueOperators = Array.from(new Map(phaseOperators.map(op => [op.id, op])).values());

            if (uniqueOperators.length > 0) {
                if (!activePhasesMap.has(phase.id)) {
                    activePhasesMap.set(phase.id, {
                        phaseId: phase.id,
                        phaseName: phase.name,
                        operators: [],
                    });
                }
                activePhasesMap.get(phase.id)!.operators.push(...uniqueOperators);
            }
        }
    });

    return Array.from(activePhasesMap.values());
  }, [jobOrder, groupPhases, allOperators]);
  
  const handleOpenPauseDialog = () => {
    setSelectedOperatorsToPause([]);
    setIsPauseDialogOpen(true);
  };
  
  const handleConfirmPause = () => {
    if (selectedOperatorsToPause.length > 0) {
      onForcePauseClick(jobOrder.id, selectedOperatorsToPause);
    }
    setIsPauseDialogOpen(false);
  };

  const toggleOperatorSelection = (opId: string) => {
    setSelectedOperatorsToPause(prev =>
      prev.includes(opId) ? prev.filter(currentId => currentId !== opId) : [...prev, opId]
    );
  };

  const toggleSelectAll = () => {
    const allActiveOperatorIds = activePhasesWithOperators.flatMap(p => p.operators.map(op => op.id));
    if (selectedOperatorsToPause.length === allActiveOperatorIds.length) {
      setSelectedOperatorsToPause([]);
    } else {
      setSelectedOperatorsToPause(allActiveOperatorIds);
    }
  };
  
  const completedPhasesCount = jobOrder.phases.filter(p => p.status === 'completed' || p.status === 'skipped').length;
  const progressPercentage = jobOrder.phases.length > 0 ? (completedPhasesCount / jobOrder.phases.length) * 100 : 0;
  
  const deliveryDateString = jobOrder.dataConsegnaFinale;
  const deliveryDate = deliveryDateString && /^\d{4}-\d{2}-\d{2}$/.test(deliveryDateString)
    ? parseISO(deliveryDateString)
    : null;
    
  const isOverdue = deliveryDate && isPast(new Date(deliveryDate.toDateString())) && overallStatus !== 'Completata';
  
  const isAnyPhaseInProgress = activePhasesWithOperators.length > 0;
  const canForceFinish = ['In Preparazione', 'Pronto per Produzione', 'In Lavorazione'].includes(overallStatus);
  const canForceComplete = !isAnyPhaseInProgress && overallStatus !== 'Completata';

  const isForcedToFinish = jobOrder.phases.some(p => p.forced);


  const guainaPhase = jobOrder.phases.find(p => p.name === "Taglio Guaina");
  
  const firstProductionPhase = jobOrder.phases
      .filter(p => p.type === 'production')
      .sort((a,b) => a.sequence - b.sequence)[0];
      
  const isGuainaPostponed = guainaPhase && firstProductionPhase && guainaPhase.sequence > firstProductionPhase.sequence;

  const isWorkInProgress = jobOrder.phases.some(p => p.status === 'in-progress' || p.status === 'paused');
  const canToggleGuaina = guainaPhase && (guainaPhase.status === 'pending' || guainaPhase.status === 'paused') && !isWorkInProgress;
  
  const isPartOfGroup = !!jobOrder.workGroupId;

  return (
    <>
      <Collapsible
        asChild
        className="w-full"
      >
        <Card
            className={cn(
            "relative flex flex-col h-full bg-card hover:bg-card/90 transition-all duration-300", 
            (jobOrder.isProblemReported || hasMaterialMissing) && "cursor-pointer border-destructive/50 hover:border-destructive",
            isSelected && "border-primary ring-2 ring-primary/50",
            isPartOfGroup && "shadow-none border-border/70",
            isOverdue && 'border-destructive/30'
            )}
            onClick={(jobOrder.isProblemReported || hasMaterialMissing) ? onProblemClick : undefined}
        >
          <div className="flex-grow">
            <CardHeader className="pb-4 space-y-2">
                <div className="flex justify-between items-center gap-4">
                    <div className="flex items-center gap-3">
                        {!isPartOfGroup && (
                          <Checkbox
                              checked={isSelected}
                              onCheckedChange={() => onSelect(jobOrder.id)}
                              aria-label={`Seleziona commessa ${jobOrder.id}`}
                              className="h-4 w-4"
                          />
                        )}
                        <CollapsibleTrigger asChild>
                          <div className="flex items-center gap-2 cursor-pointer group">
                              <CardTitle className="font-headline text-lg">{jobOrder.ordinePF}</CardTitle>
                               <ChevronDown className="h-5 w-5 text-muted-foreground transition-transform duration-200 group-data-[state=open]:-rotate-180" />
                          </div>
                        </CollapsibleTrigger>
                    </div>
                    <StatusBadge status={overallStatus} />
                </div>
                <div className="flex justify-between items-center gap-4">
                    <CardDescription className="flex items-center gap-2">
                        <Building className="h-4 w-4 text-muted-foreground" />
                        {jobOrder.cliente}
                    </CardDescription>
                    <div className="flex items-center gap-1">
                        {!isPartOfGroup && (
                            <TooltipProvider>
                                <Tooltip>
                                    <TooltipTrigger asChild>
                                        <Button asChild variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground">
                                            <Link href={`/admin/reports/${jobOrder.id}`}><CheckSquare className="h-4 w-4" /></Link>
                                        </Button>
                                    </TooltipTrigger>
                                    <TooltipContent><p>Vedi Dettagli Report</p></TooltipContent>
                                </Tooltip>
                                <Tooltip>
                                    <TooltipTrigger asChild>
                                        <Button asChild variant="ghost" size="icon" className="h-8 w-8 text-muted-foreground">
                                            <Link href={`/admin/data-management/print?jobId=${encodeURIComponent(jobOrder.id)}`} target="_blank"><Printer className="h-4 w-4" /></Link>
                                        </Button>
                                    </TooltipTrigger>
                                    <TooltipContent><p>Stampa Scheda</p></TooltipContent>
                                </Tooltip>
                            </TooltipProvider>
                        )}
                        {!isPartOfGroup && (
                          <DropdownMenu>
                              <DropdownMenuTrigger asChild>
                                  <Button variant="ghost" size="icon" className="h-8 w-8" onClick={e => e.stopPropagation()}>
                                      <MoreVertical className="h-4 w-4" />
                                  </Button>
                              </DropdownMenuTrigger>
                              <DropdownMenuContent align="end">
                                 <DropdownMenuItem onSelect={() => onOpenPhaseManager(jobOrder)} disabled={overallStatus === 'Completata'}>
                                      <ListOrdered className="mr-2 h-4 w-4" />
                                      <span>Gestisci Fasi</span>
                                  </DropdownMenuItem>
                                  <DropdownMenuItem onSelect={() => onOpenMaterialManager(jobOrder)} disabled={overallStatus === 'Completata'}>
                                      <Boxes className="mr-2 h-4 w-4" />
                                      <span>Gestisci Materiali</span>
                                  </DropdownMenuItem>
                                  {canToggleGuaina && guainaPhase && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild>
                                              <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                                              {isGuainaPostponed ? <CornerUpLeft className="mr-2 h-4 w-4" /> : <CornerDownRight className="mr-2 h-4 w-4" />}
                                              <span>{isGuainaPostponed ? 'Ripristina Guaina' : 'Posticipa Guaina'}</span>
                                              </DropdownMenuItem>
                                          </AlertDialogTrigger>
                                          <AlertDialogContent>
                                              <AlertDialogHeader>
                                                  <AlertDialogTitle>Conferma Spostamento Fase</AlertDialogTitle>
                                                  <AlertDialogDescription>
                                                  Stai per {isGuainaPostponed ? 'riportare la fase "Taglio Guaina" alla sua posizione originale.' : 'posticipare la fase "Taglio Guaina" a dopo la produzione.'} Vuoi continuare?
                                                  </AlertDialogDescription>
                                              </AlertDialogHeader>
                                              <AlertDialogFooter>
                                                  <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                  <AlertDialogAction onClick={() => onToggleGuainaClick(jobOrder.id, guainaPhase.id, isGuainaPostponed ? 'postponed' : 'default')}>Conferma</AlertDialogAction>
                                              </AlertDialogFooter>
                                          </AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   <DropdownMenuSeparator />
                                   <DropdownMenuItem onSelect={handleOpenPauseDialog} disabled={!isAnyPhaseInProgress}>
                                      <Users className="mr-2 h-4 w-4" />
                                      <span>Forza Pausa Operatori</span>
                                  </DropdownMenuItem>
                                   {canForceFinish && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" />Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Forzare tutte le fasi di produzione a 'completata'?</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceFinishClick(jobOrder.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   {isForcedToFinish && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-amber-600 focus:text-amber-700"><Undo2 className="mr-2 h-4 w-4" />Annulla Forzatura</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Annullare la Forzatura?</AlertDialogTitle><AlertDialogDescription>Le fasi completate forzatamente verranno resettate allo stato 'in attesa'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onRevertForceFinishClick(jobOrder.id)}>S├¼, annulla</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                  {canForceComplete && (
                                      <AlertDialog>
                                          <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" />Forza Chiusura Commessa</DropdownMenuItem></AlertDialogTrigger>
                                          <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Stai per impostare manualmente questa commessa come 'Completata'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceCompleteClick(jobOrder.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                      </AlertDialog>
                                  )}
                                   {jobOrder.forcedCompletion && (
                                    <AlertDialog>
                                      <AlertDialogTrigger asChild>
                                        <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-amber-600 focus:text-amber-700">
                                          <ArchiveRestore className="mr-2 h-4 w-4" />
                                          <span>Riapri Commessa</span>
                                        </DropdownMenuItem>
                                      </AlertDialogTrigger>
                                      <AlertDialogContent>
                                        <AlertDialogHeader>
                                          <AlertDialogTitle>Sei sicuro di voler riaprire?</AlertDialogTitle>
                                          <AlertDialogDescription>
                                            Questa azione riporter├á la commessa al suo ultimo stato di avanzamento, annullando la chiusura forzata.
                                          </AlertDialogDescription>
                                        </AlertDialogHeader>
                                        <AlertDialogFooter>
                                          <AlertDialogCancel>Annulla</AlertDialogCancel>
                                          <AlertDialogAction onClick={() => onRevertCompletionClick(jobOrder.id)}>S├¼, riapri</AlertDialogAction>
                                        </AlertDialogFooter>
                                      </AlertDialogContent>
                                    </AlertDialog>
                                  )}
                                  <DropdownMenuSeparator />
                                  <AlertDialog>
                                      <AlertDialogTrigger asChild>
                                      <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-destructive focus:text-destructive">
                                          <RefreshCcw className="mr-2 h-4 w-4" />
                                          <span>Annulla e Resetta</span>
                                      </DropdownMenuItem>
                                      </AlertDialogTrigger>
                                      <AlertDialogContent>
                                      <AlertDialogHeader>
                                          <AlertDialogTitle>Sei assolutamente sicuro?</AlertDialogTitle>
                                          <AlertDialogDescription>
                                          Questa azione ├¿ irreversibile. La commessa <span className="font-bold">{jobOrder.ordinePF}</span> verr├á riportata allo stato "pianificata", le lavorazioni azzerate e lo stock dei materiali consumati verr├á ripristinato.
                                          </AlertDialogDescription>
                                      </AlertDialogHeader>
                                      <AlertDialogFooter>
                                          <AlertDialogCancel>Annulla</AlertDialogCancel>
                                          <AlertDialogAction onClick={() => onResetJobOrderClick(jobOrder.id)} className="bg-destructive hover:bg-destructive/90">S├¼, annulla e resetta</AlertDialogAction>
                                      </AlertDialogFooter>
                                      </AlertDialogContent>
                                  </AlertDialog>
                              </DropdownMenuContent>
                          </DropdownMenu>
                        )}
                    </div>
                </div>

                {(jobOrder.isProblemReported || hasMaterialMissing) && (
                    <p className="text-sm text-destructive font-semibold mt-2 flex items-center">
                        <ShieldAlert className="mr-2 h-4 w-4" /> 
                        {jobOrder.isProblemReported ? "Problema segnalato!" : "Materiale mancante!"}
                    </p>
                )}
            </CardHeader>
            <CardContent className="pt-0 pb-4 px-6 space-y-4">
                <div className="flex justify-between items-start gap-4">
                    <div className="space-y-3 text-sm">
                        <p className="flex items-center gap-2 text-muted-foreground">
                            <ClipboardList className="h-4 w-4" />
                            <span className="font-semibold text-foreground">{jobOrder.numeroODLInterno || 'N/D'}</span>
                        </p>
                        <p className="flex items-center gap-2 text-muted-foreground">
                            <Factory className="h-4 w-4" />
                            {jobOrder.department}
                        </p>
                        <ContextMenu>
                          <ContextMenuTrigger>
                            <p className="flex items-center gap-2 text-muted-foreground hover:text-primary cursor-pointer">
                                <Package className="h-4 w-4" />
                                <span className="hover:underline">{jobOrder.details}</span>
                            </p>
                          </ContextMenuTrigger>
                           <ContextMenuContent>
                              <ContextMenuItem onSelect={() => onNavigateToAnalysis(jobOrder.details)}>
                                  <BarChart3 className="mr-2 h-4 w-4"/>
                                  Analisi Tempi Articolo
                              </ContextMenuItem>
                              <ContextMenuItem onSelect={() => onCopyArticleCode(jobOrder.details)}>
                                  <Copy className="mr-2 h-4 w-4"/>
                                  Copia Codice Articolo
                              </ContextMenuItem>
                          </ContextMenuContent>
                        </ContextMenu>
                        {deliveryDate && (
                            <p className={cn("flex items-center gap-2 font-medium", isOverdue ? "text-destructive" : "text-muted-foreground")}>
                                <Calendar className="h-4 w-4" />
                                <span>Consegna: {format(deliveryDate, 'dd MMM yyyy', { locale: it })}</span>
                            </p>
                        )}
                    </div>
                    <div className="text-right flex-shrink-0">
                        <div className="flex items-center gap-1 justify-end">
                          <Package className="h-4 w-4 text-muted-foreground" />
                          <span className="font-bold">{jobOrder.qta}</span>
                          <span className="text-muted-foreground text-xs">pz</span>
                        </div>
                    </div>
                </div>

                {isAnyPhaseInProgress && (
                  <div className="rounded-lg border-2 border-cyan-400/50 bg-cyan-900/20 p-3 space-y-3 animate-pulse">
                      <h4 className="text-sm font-semibold text-foreground/90 flex items-center gap-2">
                          <Hourglass className="h-4 w-4 text-cyan-500"/>
                          Operatori Attivi
                      </h4>
                      {activePhasesWithOperators.map(info => (
                          <div key={info.phaseId} className="pl-2">
                            <p className="font-semibold text-primary">{info.phaseName}:</p>
                            <div className="flex flex-wrap gap-2 pt-1">
                                {info.operators.map(op => (
                                    <Badge key={op.id} variant="outline" className="flex items-center gap-1.5 py-1 bg-background">
                                        <User className="h-3 w-3" />
                                        {op.name}
                                    </Badge>
                                ))}
                            </div>
                          </div>
                      ))}
                  </div>
                )}
                
                <div className="p-3 rounded-lg border bg-background/50 space-y-2">
                    {remainingTime ? (
                        <>
                            <div className="flex justify-between items-center">
                                <div className="flex items-center gap-2 text-sm font-semibold">
                                    <Timer className="h-4 w-4 text-primary"/>
                                    Ore Rimanenti Stimate
                                </div>
                                <TooltipProvider>
                                    <Tooltip>
                                        <TooltipTrigger asChild>
                                            <Button variant="ghost" size="icon" className="h-6 w-6" onClick={(e) => { e.stopPropagation(); updateRemainingTime(); }}>
                                                <RefreshCcw className="h-4 w-4" />
                                            </Button>
                                        </TooltipTrigger>
                                        <TooltipContent><p>Aggiorna stima</p></TooltipContent>
                                    </Tooltip>
                                </TooltipProvider>
                            </div>
