                                        <AlertDialogContent>
                                            <AlertDialogHeader><AlertDialogTitle>Ripristinare la fase?</AlertDialogTitle><AlertDialogDescription>Questa azione riporter├á la fase "{phase.name}" allo stato di pausa, conservando il tempo di lavoro gi├á registrato. Sei sicuro?</AlertDialogDescription></AlertDialogHeader>
                                            <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onRevertPhaseClick(jobOrder.id, phase.id)}>S├¼, ripristina</AlertDialogAction></AlertDialogFooter>
                                        </AlertDialogContent>
