          <DialogContent>
              <DialogHeader>
                  <DialogTitle>Seleziona Operatori da Mettere in Pausa</DialogTitle>
                  <DialogDescription>
                      Scegli quali operatori attivi sulla commessa <span className="font-bold">{jobOrder.ordinePF}</span> vuoi mettere in pausa.
                  </DialogDescription>
              </DialogHeader>
              <div className="py-4 space-y-3">
                   <div className="flex items-center space-x-2">
                      <Checkbox
                          id="select-all"
                          checked={selectedOperatorsToPause.length === activePhasesWithOperators.flatMap(p => p.operators).length && activePhasesWithOperators.length > 0}
                          onCheckedChange={toggleSelectAll}
                      />
                      <Label htmlFor="select-all">Seleziona Tutti</Label>
                  </div>
                  {activePhasesWithOperators.flatMap(p => p.operators).map(op => (
                      <div key={op.id} className="flex items-center space-x-2 p-2 rounded-md border">
                           <Checkbox
                              id={op.id}
                              checked={selectedOperatorsToPause.includes(op.id)}
                              onCheckedChange={() => toggleOperatorSelection(op.id)}
                           />
                           <Label htmlFor={op.id} className="flex-1">
                              <span className="font-semibold">{op.name}</span>
                           </Label>
                      </div>
                  ))}
                  {activePhasesWithOperators.length === 0 && <p className="text-sm text-muted-foreground text-center py-4">Nessun operatore attivo su questa commessa.</p>}
              </div>
              <DialogFooter>
                  <Button variant="outline" onClick={() => setIsPauseDialogOpen(false)}>Annulla</Button>
                  <Button onClick={handleConfirmPause} disabled={selectedOperatorsToPause.length === 0}>
                      Metti in Pausa Selezionati ({selectedOperatorsToPause.length})
                  </Button>
              </DialogFooter>
          </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import React, { useState, useMemo, useEffect, useCallback, useRef } from 'react';
import { useSearchParams, useRouter } from 'next/navigation';
import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { 
  Briefcase, 
  Loader2, 
  ShieldAlert, 
  Unlock, 
  Search, 
  Combine, 
  PowerOff, 
  Activity, 
  Calendar as CalendarIcon, 
  FastForward, 
  MoreVertical, 
  Undo2, 
  Unlink, 
  ListOrdered, 
  ArrowUp, 
  ArrowDown, 
  Circle, 
  CheckCircle2,
  Hourglass, 
  PauseCircle, 
  EyeOff, 
  RefreshCcw, 
  BarChart3, 
  Copy, 
  PlayCircle, 
  CheckSquare, 
  Boxes, 
  PackageX, 
  Package2, 
  PackageCheck,
  ChevronDown,
  AlertCircle,
  CalendarDays,
  Clock
} from 'lucide-react';
import type { JobOrder, JobPhase, Operator, WorkGroup, RawMaterial, WorkingHoursConfig } from '@/lib/mock-data';
import type { OverallStatus } from '@/lib/types';
import JobOrderCard from '@/components/production-console/JobOrderCard';
import WorkGroupCard from '@/components/production-console/WorkGroupCard';
import { useToast } from '@/hooks/use-toast';
import { collection, query, where, onSnapshot } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from "@/components/ui/dropdown-menu";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { resolveJobProblem } from '@/app/scan-job/actions';
import { 
  forceFinishProduction, 
  toggleGuainaPhasePosition, 
  revertPhaseCompletion, 
  forcePauseOperators, 
  forceCompleteJob, 
  resetSingleCompletedJobOrder, 
  revertForceFinish, 
  forceFinishMultiple, 
  forceCompleteMultiple, 
  updatePhasesForJob, 
  revertCompletion, 
  reportMaterialMissing, 
  resolveMaterialMissing, 
  getProductionTimeAnalysisMap, 
  type ProductionTimeData, 
  updateJobDeliveryDate 
} from '@/app/admin/production-console/actions';
import { getOverallStatus } from '@/lib/types';
import { dissolveWorkGroup } from '@/app/admin/work-group-management/actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { Input } from '@/components/ui/input';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { format, isSameDay, isPast, parseISO, startOfWeek, endOfWeek, getWeek, isValid } from 'date-fns';
import { it } from 'date-fns/locale';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Checkbox } from '@/components/ui/checkbox';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';
import { getWorkingHoursConfig } from '@/app/admin/working-hours/actions';

type FilterStatus = OverallStatus | 'all' | 'LIVE';

interface WeeklyGroup {
    weekNumber: number;
    weekLabel: string;
    items: (JobOrder | WorkGroup)[];
    totalPcs: number;
}

export default function ProductionConsoleClientPage() {
  const [jobOrders, setJobOrders] = useState<JobOrder[]>([]);
  const [workGroups, setWorkGroups] = useState<WorkGroup[]>([]);
  const [allOperators, setAllOperators] = useState<Operator[]>([]);
  const [allRawMaterials, setAllRawMaterials] = useState<RawMaterial[]>([]);
  const [workingHours, setWorkingHours] = useState<WorkingHoursConfig | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState<FilterStatus>('all');
  const [problemJob, setProblemJob] = useState<JobOrder | WorkGroup | null>(null);
  const [phaseManagedItem, setPhaseManagedItem] = useState<JobOrder | WorkGroup | null>(null);
  const [materialManagedItem, setMaterialManagedItem] = useState<JobOrder | WorkGroup | null>(null);
  const [analysisDataMap, setAnalysisDataMap] = useState<Map<string, ProductionTimeData | null>>(new Map());
  const [jobsWithLoadingAnalysis, setJobsWithLoadingAnalysis] = useState<Set<string>>(new Set());

  const searchParams = useSearchParams();
  const groupIdFromUrl = searchParams.get('groupId');
  const [searchTerm, setSearchTerm] = useState(groupIdFromUrl || '');
  const [completedDateFilter, setCompletedDateFilter] = useState<Date | undefined>(new Date());
  const [isDateFilterActive, setIsDateFilterActive] = useState(false);
  const [showOnlyOverdue, setShowOnlyOverdue] = useState(false);
  const [showCompleted, setShowCompleted] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  
  const [editablePhases, setEditablePhases] = useState<JobPhase[]>([]);
  const [isOrderChanged, setIsOrderChanged] = useState(false);

  const { toast } = useToast();
  const { user, operator } = useAuth();
  const router = useRouter();
  
  const jobsLoadedRef = useRef(false);
  const groupsLoadedRef = useRef(false);

  const isJobLive = useCallback((item: JobOrder | WorkGroup): boolean => {
      return (item.phases || []).some(p => p.status === 'in-progress');
  }, []);
  
  const isOverdueItem = (item: JobOrder | WorkGroup) => {
    const deliveryDateString = item.dataConsegnaFinale;
    if (!deliveryDateString || !/^\d{4}-\d{2}-\d{2}$/.test(deliveryDateString)) return false;
    const deliveryDate = parseISO(deliveryDateString);
    return isPast(deliveryDate) && getOverallStatus(item) !== 'Completata';
  };

  useEffect(() => {
    setIsLoading(true);
    getWorkingHoursConfig().then(setWorkingHours);

    const unsubscribeJobs = onSnapshot(query(collection(db, "jobOrders"), where("status", "in", ["production", "suspended", "completed", "paused"])), (snap) => {
        const jobs = snap.docs.map(doc => JSON.parse(JSON.stringify(doc.data()), (key, value) => {
            if ((['start', 'end', 'overallStartTime', 'overallEndTime', 'odlCreationDate', 'createdAt']).includes(key) && value && typeof value === 'object' && value.seconds !== undefined) return new Date(value.seconds * 1000);
            return value;
        }) as JobOrder);
        setJobOrders(jobs); jobsLoadedRef.current = true; if (groupsLoadedRef.current) setIsLoading(false);
    });
    const unsubscribeGroups = onSnapshot(collection(db, "workGroups"), (snap) => {
        const groups = snap.docs.map(doc => JSON.parse(JSON.stringify(doc.data()), (key, value) => {
            if ((['createdAt', 'overallStartTime', 'overallEndTime']).includes(key) && value && typeof value === 'object' && value.seconds !== undefined) return new Date(value.seconds * 1000);
            return value;
        }) as WorkGroup);
        setWorkGroups(groups); groupsLoadedRef.current = true; if (jobsLoadedRef.current) setIsLoading(false);
    });
    onSnapshot(collection(db, "operators"), (snap) => setAllOperators(snap.docs.map(d => d.data() as Operator)));
    onSnapshot(collection(db, "rawMaterials"), (snap) => setAllRawMaterials(snap.docs.map(d => ({id: d.id, ...d.data()} as RawMaterial))));
    return () => { unsubscribeJobs(); unsubscribeGroups(); };
  }, [toast]);
  
  const workGroupsMap = useMemo(() => new Map(workGroups.map(g => [g.id, g])), [workGroups]);
  
  const { standaloneJobs, jobsByGroupId } = useMemo(() => {
    const grouped = new Map<string, JobOrder[]>();
    const standalone: JobOrder[] = [];
    jobOrders.forEach(job => {
      if (job.workGroupId && workGroupsMap.has(job.workGroupId)) {
        if (!grouped.has(job.workGroupId)) grouped.set(job.workGroupId, []);
        grouped.get(job.workGroupId)!.push(job);
      } else standalone.push(job);
    });
    return { standaloneJobs: standalone, jobsByGroupId: grouped };
  }, [jobOrders, workGroupsMap]);

  const applyFilters = <T extends JobOrder | WorkGroup>(items: T[]): T[] => {
      let f = items;
      if (showCompleted) {
          f = f.filter(i => getOverallStatus(i) === 'Completata');
          if (isDateFilterActive && completedDateFilter) f = f.filter(i => i.overallEndTime && isSameDay(new Date(i.overallEndTime), completedDateFilter));
      } else {
          f = f.filter(i => getOverallStatus(i) !== 'Completata');
          if (activeFilter !== 'all') f = activeFilter === 'LIVE' ? f.filter(isJobLive) : f.filter(i => getOverallStatus(i) === activeFilter);
      }
      if (showOnlyOverdue) f = f.filter(isOverdueItem);
      if (searchTerm) {
          const l = searchTerm.toLowerCase();
          f = f.filter(i => {
              const isG = 'jobOrderIds' in i;
              if (isG) return (i as WorkGroup).id.toLowerCase().includes(l) || (i as WorkGroup).details.toLowerCase().includes(l) || (jobsByGroupId.get(i.id) || []).some(j => j.ordinePF.toLowerCase().includes(l));
              return (i as JobOrder).ordinePF.toLowerCase().includes(l) || (i as JobOrder).details.toLowerCase().includes(l) || (i as JobOrder).cliente.toLowerCase().includes(l);
          });
      }
      return f;
  };

  const filteredItems = useMemo(() => {
      const filteredStandalone = applyFilters(standaloneJobs);
      const filteredGroups = applyFilters(Array.from(workGroupsMap.values()));
      return [...filteredStandalone, ...filteredGroups];
  }, [standaloneJobs, workGroupsMap, activeFilter, searchTerm, showCompleted, isDateFilterActive, completedDateFilter, showOnlyOverdue, isJobLive, jobsByGroupId]);

  const { weeklyGroups, daVerificare } = useMemo(() => {
      const weeksMap = new Map<string, WeeklyGroup>();
      const daVerificare: (JobOrder | WorkGroup)[] = [];

      filteredItems.forEach(item => {
          const dateStr = item.dataConsegnaFinale;
          if (!dateStr || dateStr === 'N/D' || !isValid(parseISO(dateStr))) {
              daVerificare.push(item);
              return;
          }

          const date = parseISO(dateStr);
          const weekNum = getWeek(date, { weekStartsOn: 1 });
          const weekStart = startOfWeek(date, { weekStartsOn: 1 });
          const weekEnd = endOfWeek(date, { weekStartsOn: 1 });
          const year = format(date, 'yyyy');
          const key = `${year}-W${String(weekNum).padStart(2, '0')}`;

          if (!weeksMap.has(key)) {
              weeksMap.set(key, {
                  weekNumber: weekNum,
                  weekLabel: `Settimana ${weekNum} (${format(weekStart, 'dd/MM')} - ${format(weekEnd, 'dd/MM')})`,
                  items: [],
                  totalPcs: 0
              });
          }

          const group = weeksMap.get(key)!;
          group.items.push(item);
          group.totalPcs += ('totalQuantity' in item) ? (item.totalQuantity || 0) : (item.qta || 0);
      });

      const sortedWeeks = Array.from(weeksMap.entries())
          .sort((a, b) => a[0].localeCompare(b[0]))
          .map(([_, group]) => group);

      return { weeklyGroups: sortedWeeks, daVerificare };
  }, [filteredItems]);

  const handleSelectAll = () => {
    if (selectedIds.length === filteredItems.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredItems.map(i => i.id));
    }
  };
  
  const handleSelectItem = (itemId: string) => {
    setSelectedIds(prev =>
      prev.includes(itemId) ? prev.filter(selectedId => selectedId !== itemId) : [...prev, itemId]
    );
  };
  
  const handleBulkForceFinish = async () => {
    if (!user || selectedIds.length === 0) return;
    const result = await forceFinishMultiple(selectedIds, user.uid);
    toast({ title: result.success ? "Operazione Riuscita" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) setSelectedIds([]);
  };

  const handleBulkForceComplete = async () => {
    if (!user || selectedIds.length === 0) return;
    const result = await forceCompleteMultiple(selectedIds, user.uid);
    toast({ title: result.success ? "Operazione Riuscita" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) setSelectedIds([]);
  };
  
  const handleBulkReset = async () => {
     if (selectedIds.length === 0 || !user) return;
     setIsLoading(true);
     for (const id of selectedIds) { await resetSingleCompletedJobOrder(id, user.uid); }
     toast({ title: "Reset Completato" });
     setSelectedIds([]); setIsLoading(false);
  };

  const handleResolveProblem = async () => {
    if (!problemJob || !user) return;
    const result = await resolveJobProblem(problemJob.id, user.uid);
    toast({ title: result.success ? "Problema Risolto" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    setProblemJob(null);
  };

  const handleFilterClick = (filter: FilterStatus) => {
    setActiveFilter(filter);
    setShowCompleted(false);
  };

  const handleForceFinish = async (jobId: string) => { if (!user) return; await forceFinishProduction(jobId, user.uid); };
  const handleRevertForceFinish = async (jobId: string) => { if (!user) return; await revertForceFinish(jobId, user.uid); };
  const handleForceComplete = async (jobId: string) => { if (!user) return; await forceCompleteJob(jobId, user.uid); };
  const handleToggleGuaina = async (jobId: string, phaseId: string, currentState: 'default' | 'postponed') => { if (!user) return; await toggleGuainaPhasePosition(jobId, phaseId, currentState); };
  const handleRevertPhase = async (jobId: string, phaseId: string) => { if (!user) return; await revertPhaseCompletion(jobId, phaseId, user.uid); };
  const handleRevertCompletion = async (itemId: string) => { if (!user) return; await revertCompletion(itemId, user.uid); };
  const handleForcePause = async (jobId: string, ops: string[]) => { if (!user) return; await forcePauseOperators(jobId, ops, user.uid); };
  const onResetJobOrderClick = async (jobId: string) => { if (!user) return; await resetSingleCompletedJobOrder(jobId, user.uid); };
  const handleUpdateDeliveryDate = async (itemId: string, newDate: string) => { if (!user) return; await updateJobDeliveryDate(itemId, newDate, user.uid); };
  const handleDissolveGroup = async (groupId: string) => { await dissolveWorkGroup(groupId); };

  const handleOpenPhaseManager = (item: JobOrder | WorkGroup) => {
    setPhaseManagedItem(item);
    setEditablePhases([...item.phases].sort((a,b) => a.sequence - b.sequence));
    setIsOrderChanged(false);
  };
  
  const handlePhaseStatusToggle = (phaseId: string) => {
    setEditablePhases(prev => {
      const news = prev.map(p => {
        if (p.id === phaseId) {
          if (p.status === 'pending') return { ...p, status: 'skipped' as const };
          if (p.status === 'skipped') return { ...p, status: 'pending' as const };
        }
        return p;
      });
      setIsOrderChanged(true); return news;
    });
  };

  const handleMovePhase = (index: number, direction: 'up' | 'down') => {
    setEditablePhases(prev => {
        const news = [...prev];
        const targetIndex = direction === 'up' ? index - 1 : index + 1;
        if (targetIndex >= 0 && targetIndex < news.length) {
            const temp = news[index];
            news[index] = news[targetIndex];
            news[targetIndex] = temp;
        }
        setIsOrderChanged(true); return news;
    });
  };
  
  const handleSaveChanges = async () => {
    if (!user || !phaseManagedItem) return;
    const res = await updatePhasesForJob(phaseManagedItem.id, editablePhases, user.uid);
    if (res.success) {
        toast({ title: "Fasi aggiornate" });
        setPhaseManagedItem(null);
    } else {
        toast({ variant: "destructive", title: "Errore", description: res.message });
    }
  };

  const handleFetchAnalysis = async (job: JobOrder) => {
    if (!job.id) return;
    setJobsWithLoadingAnalysis(prev => new Set(prev).add(job.id));
    try {
        const map = await getProductionTimeAnalysisMap();
        setAnalysisDataMap(prev => new Map(prev).set(job.id, map.get(job.details) || null));
    } catch (e) { toast({ variant: "destructive", title: "Errore Analisi" }); }
    finally { setJobsWithLoadingAnalysis(prev => { const n = new Set(prev); n.delete(job.id); return n; }); }
  };

  const handleNavigateToAnalysis = (articleCode: string) => {
    router.push(`/admin/production-time-analysis?articleCode=${encodeURIComponent(articleCode)}`);
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    toast({ title: "Copiato!" });
  };

  const handleMaterialStatusToggle = async (itemId: string, phaseId: string, currentStatus?: string) => {
      if (!user) return;
      if (currentStatus === 'missing') {
          await resolveMaterialMissing(itemId, phaseId, user.uid);
      } else {
          await reportMaterialMissing(itemId, phaseId, user.uid);
      }
  };

  function getPhaseIconLocal(status: JobPhase['status']) {
    switch (status) {
      case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
      case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
      case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
      case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
      case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
      default: return <Circle className="h-4 w-4 text-muted-foreground" />;
    }
  }

  const renderItem = (item: JobOrder | WorkGroup) => {
      const isGroup = 'jobOrderIds' in item;
      if (isGroup) {
          return (
            <WorkGroupCard 
                key={item.id} 
                group={item as WorkGroup} 
                jobsInGroup={jobsByGroupId.get(item.id) || []} 
                allOperators={allOperators} 
                allRawMaterials={allRawMaterials} 
                onProblemClick={() => setProblemJob(item as WorkGroup)} 
                onForceFinishClick={handleForceFinish} 
                onForcePauseClick={handleForcePause} 
                onForceCompleteClick={handleForceComplete} 
                onDissolveGroupClick={handleDissolveGroup} 
                onOpenPhaseManager={handleOpenPhaseManager} 
                onOpenMaterialManager={() => setMaterialManagedItem(item as WorkGroup)} 
                onToggleGuainaClick={handleToggleGuaina} 
                onUpdateDeliveryDate={handleUpdateDeliveryDate} 
                isSelected={selectedIds.includes(item.id)} 
                onSelect={handleSelectItem} 
                overallStatus={getOverallStatus(item as WorkGroup)} 
                getOverallStatus={getOverallStatus} 
                onNavigateToAnalysis={handleNavigateToAnalysis} 
                onCopyArticleCode={handleCopy}
            />
          );
      }
      return (
        <JobOrderCard 
            key={item.id} 
            jobOrder={item as JobOrder} 
            allOperators={allOperators} 
            allRawMaterials={allRawMaterials} 
            analysisData={analysisDataMap.get(item.id)} 
            onFetchAnalysis={() => handleFetchAnalysis(item as JobOrder)} 
            isAnalysisLoading={jobsWithLoadingAnalysis.has(item.id)} 
            onProblemClick={() => setProblemJob(item as JobOrder)} 
            onForceFinishClick={handleForceFinish} 
            onRevertForceFinishClick={handleRevertForceFinish} 
            onToggleGuainaClick={handleToggleGuaina} 
            onRevertPhaseClick={handleRevertPhase} 
            onRevertCompletionClick={handleRevertCompletion} 
            onForcePauseClick={handleForcePause} 
            onForceCompleteClick={handleForceComplete} 
            onResetJobOrderClick={onResetJobOrderClick} 
            onOpenPhaseManager={handleOpenPhaseManager} 
            onOpenMaterialManager={() => setMaterialManagedItem(item as JobOrder)} 
            onUpdateDeliveryDate={handleUpdateDeliveryDate} 
            isSelected={selectedIds.includes(item.id)} 
            onSelect={handleSelectItem} 
            overallStatus={getOverallStatus(item as JobOrder)} 
            onNavigateToAnalysis={handleNavigateToAnalysis} 
            onCopyArticleCode={handleCopy}
        />
      );
  };

  return (
    <>
      <div className="space-y-6">
        <header className="flex flex-col sm:flex-row justify-between items-start gap-4">
            <div><h1 className="text-3xl font-bold font-headline flex items-center gap-3"><Briefcase className="h-8 w-8 text-primary" /> Console Controllo Produzione</h1></div>
            <div className="relative w-full sm:max-w-xs"><Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" /><Input placeholder="Cerca..." className="pl-9" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
        </header>
        
        <Card className="p-2 space-y-2">
          <div className="flex flex-wrap items-center justify-center gap-1">
              {[
                { label: 'Tutte', value: 'all', icon: Briefcase },
                { label: 'In Corso (Live)', value: 'LIVE', icon: Activity },
                { label: 'In Lavorazione', value: 'In Lavorazione', icon: Hourglass },
                { label: 'Sospesa', value: 'Sospesa', icon: PauseCircle },
                { label: 'Problema', value: 'Problema', icon: ShieldAlert },
                { label: 'Manca Materiale', value: 'Manca Materiale', icon: PackageX },
              ].map(f => (
                <Button key={f.value} variant={activeFilter === f.value && !showCompleted ? 'secondary' : 'ghost'} onClick={() => handleFilterClick(f.value as any)} className="text-xs sm:text-sm">
                  <f.icon className={cn("mr-2 h-4 w-4", f.value === 'LIVE' && "text-red-400 animate-pulse")} /> {f.label}
                </Button>
              ))}
          </div>
           <div className="border-t pt-2 flex items-center justify-center gap-4 flex-wrap">
                  <div className="flex items-center space-x-2"><Switch id="over-sw" checked={showOnlyOverdue} onCheckedChange={setShowOnlyOverdue} /><Label htmlFor="over-sw" className="text-destructive">Filtra Ritardi</Label></div>
                  <div className="flex items-center space-x-2"><Switch id="comp-sw" checked={showCompleted} onCheckedChange={setShowCompleted} /><Label htmlFor="comp-sw">Mostra Completate</Label></div>
                  {showCompleted && (
                    <div className="flex items-center gap-2">
                      <Switch id="dt-sw" checked={isDateFilterActive} onCheckedChange={setIsDateFilterActive} /><Label htmlFor="dt-sw">Filtra Data</Label>
                      <Popover><PopoverTrigger asChild><Button variant="outline" className={cn("w-[200px] justify-start", !isDateFilterActive && "opacity-50")} disabled={!isDateFilterActive}><CalendarIcon className="mr-2 h-4 w-4" />{completedDateFilter ? format(completedDateFilter, "PPP", { locale: it }) : "Data"}</Button></PopoverTrigger>
                      <PopoverContent className="w-auto p-0"><Calendar mode="single" selected={completedDateFilter} onSelect={setCompletedDateFilter} initialFocus /></PopoverContent></Popover>
                    </div>
                  )}
           </div>
        </Card>
        
         {filteredItems.length > 0 && (
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                  <Checkbox id="sel-all" checked={selectedIds.length > 0 && selectedIds.length === filteredItems.length} onCheckedChange={handleSelectAll} />
                  <Label htmlFor="sel-all">Seleziona Tutte ({filteredItems.length})</Label>
              </div>
              {selectedIds.length > 0 && (
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild><Button variant="outline" size="sm">Azioni di Gruppo ({selectedIds.length}) <MoreVertical className="ml-2 h-4 w-4" /></Button></DropdownMenuTrigger>
                     <DropdownMenuContent align="start">
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" /> Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Confermi l'avanzamento forzato?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkForceFinish}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                        
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" /> Chiudi Item</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Confermi la chiusura forzata?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkForceComplete}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                        
                        <DropdownMenuSeparator />
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()} className="text-destructive"><RefreshCcw className="mr-2 h-4 w-4" /> Annulla e Resetta</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro di voler resettare?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkReset} className="bg-destructive">S├¼, Resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                    </DropdownMenuContent>
                  </DropdownMenu>
              )}
          </div>
        )}

        {isLoading ? (
            <div className="flex flex-col items-center justify-center py-20"><Loader2 className="h-12 w-12 animate-spin text-primary" /><p className="mt-4 text-muted-foreground">Aggiornamento...</p></div>
        ) : filteredItems.length > 0 ? (
          <div className="space-y-12">
            
            {daVerificare.length > 0 && (
                <section className="space-y-4">
                    <div className="flex items-center gap-3 border-b-2 border-destructive/20 pb-2">
                        <AlertCircle className="h-6 w-6 text-destructive" />
                        <h2 className="text-xl font-black uppercase tracking-tight text-destructive">Da Gestire e Verificare (N/D)</h2>
                        <Badge variant="destructive">{daVerificare.length}</Badge>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {daVerificare.map(renderItem)}
                    </div>
                </section>
            )}

            {weeklyGroups.map((group) => (
                <section key={group.weekLabel} className="space-y-4">
                    <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 border-b-2 border-primary/20 pb-2">
                        <div className="flex items-center gap-3">
                            <CalendarDays className="h-6 w-6 text-primary" />
                            <h2 className="text-xl font-black uppercase tracking-tight text-primary">{group.weekLabel}</h2>
                            <Badge variant="outline" className="border-primary text-primary">{group.items.length} Item</Badge>
                        </div>
                        <div className="flex items-center gap-4 text-sm font-bold text-muted-foreground">
                            <div className="flex items-center gap-1.5"><Package2 className="h-4 w-4"/> {group.totalPcs} pz totali</div>
                        </div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {group.items.map(renderItem)}
                    </div>
                </section>
            ))}

          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-20 border-2 border-dashed rounded-lg mt-8"><Package2 className="h-16 w-16 text-muted-foreground mb-4" /><h2 className="text-xl font-semibold text-muted-foreground">Nessuna Commessa Trovata</h2></div>
        )}
      </div>
      
      <Dialog open={!!phaseManagedItem} onOpenChange={o => !o && setPhaseManagedItem(null)}>
        <DialogContent className="max-w-xl"><DialogHeader><DialogTitle>Gestione Fasi: {phaseManagedItem?.id}</DialogTitle></DialogHeader>
           <div className="py-4 space-y-2 max-h-[60vh] overflow-y-auto">
            {editablePhases.map((phase, index) => (
                <div key={phase.id} className={cn("flex items-center justify-between p-3 rounded-md", (phase.status !== 'pending' && phase.status !== 'skipped') && 'bg-muted/50 opacity-70')}>
                  <div className="flex items-center gap-3">{getPhaseIconLocal(phase.status)}<span className={cn('font-medium', phase.status === 'skipped' && 'line-through text-muted-foreground')}>{phase.name}</span></div>
                  <div className="flex items-center gap-1">
                    {(phase.status === 'pending' || phase.status === 'skipped') ? (
                      <>
                        <Button size="icon" variant="ghost" onClick={() => handleMovePhase(index, 'up')} disabled={index === 0}><ArrowUp className="h-4 w-4" /></Button>
                        <Button size="icon" variant="ghost" onClick={() => handleMovePhase(index, 'down')} disabled={index === editablePhases.length - 1}><ArrowDown className="h-4 w-4" /></Button>
                        <Button size="sm" variant="outline" onClick={() => handlePhaseStatusToggle(phase.id)}>{phase.status === 'pending' ? <EyeOff className="mr-2 h-4 w-4" /> : <Undo2 className="mr-2 h-4 w-4" />}{phase.status === 'pending' ? 'Bypassa' : 'Ripristina'}</Button>
                      </>
                    ) : <Badge variant="secondary">{phase.status}</Badge>}
                  </div>
                </div>
            ))}
          </div>
          <DialogFooter><Button variant="outline" onClick={() => setPhaseManagedItem(null)}>Annulla</Button><Button onClick={handleSaveChanges} className={cn(isOrderChanged && 'bg-amber-500 animate-pulse')}>Salva Modifiche</Button></DialogFooter>
        </DialogContent>
      </Dialog>
      
      <Dialog open={!!materialManagedItem} onOpenChange={o => !o && setMaterialManagedItem(null)}>
        <DialogContent className="max-w-xl"><DialogHeader><DialogTitle>Mancanza Materiale: {materialManagedItem?.id}</DialogTitle></DialogHeader>
           <div className="py-4 space-y-2">
            {(materialManagedItem?.phases || []).filter(p => p.type === 'preparation').map(phase => (
                <div key={phase.id} className="flex items-center justify-between p-3 rounded-md">
                  <div className="flex items-center gap-3">{phase.materialStatus === 'missing' ? <PackageX className="h-5 w-5 text-destructive" /> : <PackageCheck className="h-5 w-5 text-green-500" />}<span>{phase.name}</span></div>
                  <Button size="sm" variant={phase.materialStatus === 'missing' ? 'secondary' : 'destructive'} onClick={() => handleMaterialStatusToggle(materialManagedItem!.id, phase.id, phase.materialStatus)}>{phase.materialStatus === 'missing' ? <Unlock className="mr-2 h-4 w-4" /> : <PlayCircle className="mr-2 h-4 w-4" />}{phase.materialStatus === 'missing' ? 'Risolvi' : 'Segnala'}</Button>
                </div>
            ))}
          </div>
        </DialogContent>
      </Dialog>

       <Dialog open={!!problemJob} onOpenChange={o => !o && setProblemJob(null)}>
        <DialogContent><DialogHeader><DialogTitle>Dettaglio Problema: {problemJob?.id}</DialogTitle></DialogHeader>
            <div className="space-y-4 text-sm pt-4">
                {problemJob?.problemType === 'MANCA_MATERIALE' && (
                    <ul className="list-disc pl-5 text-destructive">{(problemJob?.phases || []).filter(p => p.materialStatus === 'missing').map(p => <li key={p.id}>{p.name}</li>)}</ul>
                )}
                {problemJob?.problemNotes && <p className="text-muted-foreground p-2 bg-muted rounded-md">{problemJob.problemNotes}</p>}
            </div>
            <DialogFooter>
                <Button variant="outline" onClick={() => setProblemJob(null)}>Chiudi</Button>
                { (operator?.role === 'supervisor' || operator?.role === 'admin') && (
                  <Button onClick={handleResolveProblem} className="bg-green-600 hover:bg-green-700">
                     <Unlock className="mr-2 h-4 w-4"/> Sblocca Commessa
                  </Button>
                )}
            </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

import type { JobOrder, JobPhase, Operator, WorkGroup } from '@/lib/mock-data';
import type { OverallStatus } from '@/lib/types';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { StatusBadge } from '@/components/production-console/StatusBadge';
import { Package, Building, Circle, Hourglass, CheckCircle2, ShieldAlert, PauseCircle, MoreVertical, FastForward, CornerUpLeft, CornerDownRight, ListOrdered, Boxes, Users, PowerOff, Unlink, View, Combine, User, EyeOff, ChevronDown, Timer, Loader2 } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { TooltipProvider, Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import React, { useState, useMemo } from 'react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from "@/components/ui/dropdown-menu";
import {
  Collapsible,
  CollapsibleContent,
  CollapsibleTrigger,
} from "@/components/ui/collapsible";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import JobOrderCard from './JobOrderCard';
import { Separator } from '@/components/ui/separator';
import type { ProductionTimeData } from '@/app/admin/production-console/actions';


interface ActivePhaseInfo {
  phaseId: string;
  phaseName: string;
  operators: { id: string; name: string }[];
}

function getPhaseIcon(status: JobPhase['status']) {
  switch (status) {
    case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
    case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
    case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
    case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
    case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
    default: return <Circle className="h-4 w-4 text-muted-foreground" />;
  }
}

export default function WorkGroupCard({ 
    group,
    jobsInGroup,
    allOperators,
    onProblemClick,
    onForceFinishClick,
    onForcePauseClick,
    onForceCompleteClick,
    onDissolveGroupClick,
    onOpenPhaseManager,
    onOpenMaterialManager,
    onToggleGuainaClick,
    isSelected,
    onSelect,
    overallStatus,
    getOverallStatus,
}: { 
    group: WorkGroup;
    jobsInGroup: JobOrder[];
    allOperators: Operator[];
    onProblemClick: () => void;
    onForceFinishClick: (groupId: string) => void;
    onForcePauseClick: (groupId: string, operatorIds: string[]) => void;
    onForceCompleteClick: (groupId: string) => void;
    onDissolveGroupClick: (groupId: string) => void;
    onOpenPhaseManager: (item: JobOrder | WorkGroup) => void;
    onOpenMaterialManager: (item: JobOrder | WorkGroup) => void;
    onToggleGuainaClick: (itemId: string, phaseId: string, currentState: 'default' | 'postponed') => void;
    isSelected: boolean;
    onSelect: (groupId: string) => void;
    overallStatus: OverallStatus;
    getOverallStatus: (job: JobOrder) => OverallStatus;
}) {
  const [isPauseDialogOpen, setIsPauseDialogOpen] = useState(false);
  const [isExplodeViewOpen, setIsExplodeViewOpen] = useState(false);
  const [selectedOperatorsToPause, setSelectedOperatorsToPause] = useState<string[]>([]);
  const hasMaterialMissing = group.phases.some(p => p.materialStatus === 'missing');

  const activePhasesWithOperators = useMemo((): ActivePhaseInfo[] => {
    const activePhasesMap = new Map<string, ActivePhaseInfo>();
    
    (group.phases || []).forEach(phase => {
        if (phase.status === 'in-progress') {
            const phaseOperators: { id: string; name: string }[] = [];
            (phase.workPeriods || []).forEach(wp => {
                if (wp.end === null) {
                    const operator = allOperators.find(op => op.id === wp.operatorId);
                    if (operator) {
                        phaseOperators.push({ id: operator.id, name: operator.nome });
                    }
                }
            });

            // Filter out duplicates before adding to the map
            const uniqueOperators = Array.from(new Map(phaseOperators.map(op => [op.id, op])).values());

            if (uniqueOperators.length > 0) {
                if (!activePhasesMap.has(phase.id)) {
                    activePhasesMap.set(phase.id, {
                        phaseId: phase.id,
                        phaseName: phase.name,
                        operators: [],
                    });
                }
                activePhasesMap.get(phase.id)!.operators.push(...uniqueOperators);
            }
        }
    });

    return Array.from(activePhasesMap.values());
  }, [group, allOperators]);
  
  const handleOpenPauseDialog = () => {
    setSelectedOperatorsToPause([]);
    setIsPauseDialogOpen(true);
  };
  
  const handleConfirmPause = () => {
    if (selectedOperatorsToPause.length > 0) {
      onForcePauseClick(group.id, selectedOperatorsToPause);
    }
    setIsPauseDialogOpen(false);
  };

  const toggleOperatorSelection = (opId: string) => {
    setSelectedOperatorsToPause(prev =>
      prev.includes(opId) ? prev.filter(currentId => currentId !== opId) : [...prev, opId]
    );
  };

  const toggleSelectAll = () => {
    const allActiveOperatorIds = activePhasesWithOperators.flatMap(p => p.operators.map(op => op.id));
    if (selectedOperatorsToPause.length === allActiveOperatorIds.length) {
      setSelectedOperatorsToPause([]);
    } else {
      setSelectedOperatorsToPause(allActiveOperatorIds);
    }
  };

  const completedPhasesCount = group.phases.filter(p => p.status === 'completed' || p.status === 'skipped').length;
  const progressPercentage = group.phases.length > 0 ? (completedPhasesCount / group.phases.length) * 100 : 0;
  
  const canForceFinish = ['In Preparazione', 'Pronto per Produzione', 'In Lavorazione'].includes(overallStatus);
  const isAnyPhaseInProgress = activePhasesWithOperators.length > 0;
  const canForceComplete = !isAnyPhaseInProgress && overallStatus !== 'Completata';
  
  const guainaPhase = group.phases.find(p => p.name === "Taglio Guaina");
  const isWorkInProgress = group.phases.some(p => p.status === 'in-progress' || p.status === 'paused');
  const canToggleGuaina = guainaPhase && (guainaPhase.status === 'pending' || guainaPhase.status === 'paused') && !isWorkInProgress;
  
  const firstProductionPhase = group.phases
      .filter(p => p.type === 'production')
      .sort((a,b) => a.sequence - b.sequence)[0];
  const isGuainaPostponed = guainaPhase && firstProductionPhase && guainaPhase.sequence > firstProductionPhase.sequence;


  return (
    <>
    <Collapsible asChild>
      <Card 
        className={cn(
            "relative flex flex-col h-full bg-card hover:bg-card/90 transition-all duration-300 border-2 border-teal-500/70", 
            (group.isProblemReported || hasMaterialMissing) && "cursor-pointer border-destructive/50 hover:border-destructive",
            isSelected && "border-primary ring-2 ring-primary/50",
        )}
        onClick={(group.isProblemReported || hasMaterialMissing) ? onProblemClick : undefined}
      >
        <div className="flex-grow">
            <CardHeader className="pb-3 space-y-2">
                <div className="flex justify-between items-center gap-4">
                    <div className="flex items-center gap-3">
                        <Checkbox
                            checked={isSelected}
                            onCheckedChange={() => onSelect(group.id)}
                            aria-label={`Seleziona gruppo ${group.id}`}
                            className="h-4 w-4"
                        />
                         <TooltipProvider>
                            <Tooltip>
                                <TooltipTrigger>
                                    <Combine className="h-5 w-5 text-teal-400" />
                                </TooltipTrigger>
                                <TooltipContent>
                                    <p>Gruppo: {group.id}</p>
                                </TooltipContent>
                            </Tooltip>
                        </TooltipProvider>
                        <CollapsibleTrigger asChild>
                           <div className="flex items-center gap-2 cursor-pointer group">
                                <CardTitle className="font-headline text-base font-mono">{group.id}</CardTitle>
                                <ChevronDown className="h-5 w-5 text-muted-foreground transition-transform duration-200 group-data-[state=open]:-rotate-180" />
                            </div>
                        </CollapsibleTrigger>
                    </div>
                    <StatusBadge status={overallStatus} />
                </div>
                <div className="flex justify-between items-center gap-4">
                    <CardDescription className="flex items-center gap-2">
                        <Building className="h-4 w-4 text-muted-foreground" />
                        {group.cliente}
                    </CardDescription>
                    <div className="flex items-center gap-1">
                        <DropdownMenu>
                            <DropdownMenuTrigger asChild>
                                <Button variant="ghost" size="icon" className="h-8 w-8" onClick={(e) => e.stopPropagation()}>
                                    <MoreVertical className="h-4 w-4" />
                                </Button>
                            </DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                                <DropdownMenuItem onSelect={() => onOpenPhaseManager(group)} disabled={overallStatus === 'Completata'}>
                                    <ListOrdered className="mr-2 h-4 w-4" />
                                    <span>Gestisci Fasi</span>
                                </DropdownMenuItem>
                                <DropdownMenuItem onSelect={() => onOpenMaterialManager(group)} disabled={overallStatus === 'Completata'}>
                                    <Boxes className="mr-2 h-4 w-4" />
                                    <span>Gestisci Materiali</span>
                                </DropdownMenuItem>
                                {canToggleGuaina && guainaPhase && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild>
                                            <DropdownMenuItem onSelect={(e) => e.preventDefault()}>
                                            {isGuainaPostponed ? <CornerUpLeft className="mr-2 h-4 w-4" /> : <CornerDownRight className="mr-2 h-4 w-4" />}
                                            <span>{isGuainaPostponed ? 'Ripristina Guaina' : 'Posticipa Guaina'}</span>
                                            </DropdownMenuItem>
                                        </AlertDialogTrigger>
                                        <AlertDialogContent>
                                            <AlertDialogHeader>
                                                <AlertDialogTitle>Conferma Spostamento Fase</AlertDialogTitle>
                                                <AlertDialogDescription>
                                                Stai per {isGuainaPostponed ? 'riportare la fase "Taglio Guaina" alla sua posizione originale.' : 'posticipare la fase "Taglio Guaina" a dopo la produzione.'} L'esecuzione di questa azione su un gruppo ne causer├á lo scioglimento immediato. Vuoi continuare?
                                                </AlertDialogDescription>
                                            </AlertDialogHeader>
                                            <AlertDialogFooter>
                                                <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                <AlertDialogAction onClick={() => onToggleGuainaClick(group.id, guainaPhase.id, isGuainaPostponed ? 'postponed' : 'default')}>Conferma e Sciogli</AlertDialogAction>
                                            </AlertDialogFooter>
                                        </AlertDialogContent>
                                    </AlertDialog>
                                )}
                                <DropdownMenuSeparator />
                                <DropdownMenuItem onSelect={handleOpenPauseDialog} disabled={!isAnyPhaseInProgress}>
                                    <Users className="mr-2 h-4 w-4" />
                                    <span>Forza Pausa Operatori</span>
                                </DropdownMenuItem>
                                {canForceFinish && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" />Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Forzare tutte le fasi di produzione del gruppo a 'completata'?</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceFinishClick(group.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                    </AlertDialog>
                                )}
                                {canForceComplete && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild><DropdownMenuItem onSelect={(e) => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" />Forza Chiusura Gruppo</DropdownMenuItem></AlertDialogTrigger>
                                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Conferma Azione</AlertDialogTitle><AlertDialogDescription>Stai per impostare manualmente questo gruppo come 'Completato'.</AlertDialogDescription></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onForceCompleteClick(group.id)}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent>
                                    </AlertDialog>
                                )}
                                <DropdownMenuSeparator />
                                <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                        <DropdownMenuItem onSelect={(e) => e.preventDefault()} className="text-destructive focus:text-destructive">
                                            <Unlink className="mr-2 h-4 w-4" />
                                            <span>Annulla Gruppo</span>
                                        </DropdownMenuItem>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader><AlertDialogTitle>Sei sicuro di voler annullare il gruppo?</AlertDialogTitle><AlertDialogDescription>Le commesse torneranno individuali e dovranno essere gestite singolarmente. L'avanzamento verr├á ereditato dal gruppo.</AlertDialogDescription></AlertDialogHeader>
                                        <AlertDialogFooter><AlertDialogCancel>Chiudi</AlertDialogCancel><AlertDialogAction onClick={() => onDissolveGroupClick(group.id)} className="bg-destructive hover:bg-destructive/90">S├¼, annulla gruppo</AlertDialogAction></AlertDialogFooter>
                                    </AlertDialogContent>
                                </AlertDialog>
                            </DropdownMenuContent>
                        </DropdownMenu>
                    </div>
                </div>

                {(group.isProblemReported || hasMaterialMissing) && (
                    <p className="text-sm text-destructive font-semibold mt-2 flex items-center">
                        <ShieldAlert className="mr-2 h-4 w-4" /> 
                        {group.isProblemReported ? "Problema segnalato!" : "Materiale mancante!"}
                    </p>
                )}
            </CardHeader>
            <CardContent className="flex-grow space-y-4 pt-0">
                <div className="flex justify-between items-start gap-4">
                    <div className="space-y-3 text-sm">
                        <p className="flex items-center gap-2 text-muted-foreground">
                            <Package className="h-4 w-4" />
                            {group.details}
                        </p>
                    </div>
                    <div className="text-right flex-shrink-0">
                        <div className="flex items-center gap-1 justify-end">
                        <Package className="h-4 w-4 text-muted-foreground" />
                        <span className="font-bold">{group.qta}</span>
                        <span className="text-muted-foreground text-xs">pz totali</span>
                        </div>
                    </div>
                </div>

                <div className="space-y-1 text-sm">
                    <p className="font-semibold text-foreground/80">Commesse nel Gruppo:</p>
                    <div className="flex flex-wrap gap-1">
                        {group.jobOrderPFs?.map(pf => <Badge key={pf} variant="secondary">{pf}</Badge>)}
                    </div>
                </div>
                
                {isAnyPhaseInProgress && (
                  <div className="rounded-lg border-2 border-cyan-400/50 bg-cyan-900/20 p-3 space-y-3 animate-pulse">
                      <h4 className="text-sm font-semibold text-foreground/90 flex items-center gap-2">
                          <Hourglass className="h-4 w-4 text-cyan-500"/>
                          Operatori Attivi
                      </h4>
                      {activePhasesWithOperators.map(info => (
                          <div key={info.phaseId} className="pl-2">
                            <p className="font-semibold text-primary">{info.phaseName}:</p>
                            <div className="flex flex-wrap gap-2 pt-1">
                                {info.operators.map(op => (
                                    <Badge key={op.id} variant="outline" className="flex items-center gap-1.5 py-1 bg-background">
                                        <User className="h-3 w-3" />
                                        {op.name}
                                    </Badge>
                                ))}
                            </div>
                          </div>
                      ))}
                  </div>
                )}
            </CardContent>
        </div>
        <CardFooter className="flex-col items-start gap-2 pt-4">
          <div className="w-full">
              <div className="flex justify-between text-xs text-muted-foreground mb-1">
                  <span>Progresso</span>
                  <span>{Math.round(progressPercentage)}%</span>
              </div>
              <Progress value={progressPercentage} className="h-2" />
          </div>
        </CardFooter>
        <CollapsibleContent>
             <div className="space-y-2 p-4">
                <Separator />
                <h4 className="text-sm font-semibold text-foreground/80 pt-2">Avanzamento Fasi</h4>
                {group.phases && group.phases.length > 0 ? (
                    group.phases.sort((a,b) => a.sequence - b.sequence).map(phase => (
                        <div key={phase.id} className="flex items-center gap-3 text-sm text-muted-foreground">
                            {getPhaseIcon(phase.status)}
                            <span className={cn("flex-1", phase.status === 'skipped' && 'line-through')}>{phase.name}</span>
                        </div>
                    ))
                ) : (
                    <p className="text-sm text-muted-foreground">Nessuna fase definita per questo gruppo.</p>
                )}
                 <Button variant="secondary" size="sm" className="w-full mt-4" onClick={() => setIsExplodeViewOpen(true)}>
                      <View className="mr-2 h-4 w-4" />
                      Esplodi e Vedi Dettagli Commesse ({jobsInGroup.length})
                  </Button>
            </div>
        </CollapsibleContent>
      </Card>
      </Collapsible>

      <Dialog open={isPauseDialogOpen} onOpenChange={setIsPauseDialogOpen}>
          <DialogContent>
              <DialogHeader>
                  <DialogTitle>Seleziona Operatori da Mettere in Pausa</DialogTitle>
                  <DialogDescription>
                      Scegli quali operatori attivi sul gruppo <span className="font-bold">{group.id}</span> vuoi mettere in pausa.
                  </DialogDescription>
              </DialogHeader>
              <div className="py-4 space-y-3">
                   <div className="flex items-center space-x-2">
                      <Checkbox
                          id="select-all"
                          checked={selectedOperatorsToPause.length === activePhasesWithOperators.flatMap(p => p.operators).length && activePhasesWithOperators.length > 0}
                          onCheckedChange={toggleSelectAll}
                      />
                      <Label htmlFor="select-all">Seleziona Tutti</Label>
                  </div>
                  {activePhasesWithOperators.flatMap(p => p.operators).map(op => (
                      <div key={op.id} className="flex items-center space-x-2 p-2 rounded-md border">
                           <Checkbox
                              id={op.id}
                              checked={selectedOperatorsToPause.includes(op.id)}
                              onCheckedChange={() => toggleOperatorSelection(op.id)}
                           />
                           <Label htmlFor={op.id} className="flex-1">
                              <span className="font-semibold">{op.name}</span>
                           </Label>
                      </div>
                  ))}
                  {activePhasesWithOperators.length === 0 && <p className="text-sm text-muted-foreground text-center py-4">Nessun operatore attivo su questo gruppo.</p>}
              </div>
              <DialogFooter>
                  <Button variant="outline" onClick={() => setIsPauseDialogOpen(false)}>Annulla</Button>
                  <Button onClick={handleConfirmPause} disabled={selectedOperatorsToPause.length === 0}>
                      Metti in Pausa Selezionati ({selectedOperatorsToPause.length})
                  </Button>
              </DialogFooter>
          </DialogContent>
      </Dialog>
      
      <Dialog open={isExplodeViewOpen} onOpenChange={setIsExplodeViewOpen}>
          <DialogContent className="max-w-7xl h-[90vh]">
              <DialogHeader>
                  <DialogTitle>Dettaglio Commesse nel Gruppo: {group.id}</DialogTitle>
              </DialogHeader>
              <div className="h-full overflow-y-auto p-2">
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                      {jobsInGroup.map(job => (
                          <JobOrderCard
                              key={job.id}
                              jobOrder={job}
                              groupPhases={group.phases}
                              allOperators={allOperators}
                              onProblemClick={() => {}}
                              onFetchAnalysis={() => {}}
                              isAnalysisLoading={false}
                              onForceFinishClick={() => {}}
                              onRevertForceFinishClick={() => {}}
                              onToggleGuainaClick={() => {}}
                              onRevertPhaseClick={() => {}}
                              onRevertCompletionClick={() => {}}
                              onForcePauseClick={() => {}}
                              onForceCompleteClick={() => {}}
                              onResetJobOrderClick={() => {}}
                              onOpenPhaseManager={() => {}}
                              onOpenMaterialManager={() => {}}
                              isSelected={false}
                              onSelect={() => {}}
                              overallStatus={getOverallStatus(job)}
                              onNavigateToAnalysis={() => {}}
                              onCopyArticleCode={() => {}}
                          />
                      ))}
                  </div>
              </div>
          </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import React, { useState, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { useSearchParams, useRouter } from 'next/navigation';

import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Timer, Package, Download, ChevronRight, Search, BarChart, Copy, ClipboardList, PackagePlus, Workflow, TestTube } from 'lucide-react';
import type { ProductionTimeAnalysisReport } from '../reports/actions';
import { Badge } from '@/components/ui/badge';
import {
    Collapsible,
    CollapsibleContent,
    CollapsibleTrigger,
} from "@/components/ui/collapsible";
import {
    ContextMenu,
    ContextMenuContent,
    ContextMenuItem,
    ContextMenuTrigger,
} from "@/components/ui/context-menu";
import { cn } from '@/lib/utils';
import { TooltipProvider, Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import { useToast } from '@/hooks/use-toast';
import { Separator } from '@/components/ui/separator';

interface ProductionTimeAnalysisClientPageProps {
    report: ProductionTimeAnalysisReport[];
}

const phaseTypeTitles: Record<string, { title: string, icon: React.ElementType }> = {
    preparation: { title: 'Fasi di Preparazione', icon: PackagePlus },
    production: { title: 'Fasi di Produzione', icon: Workflow },
    quality: { title: 'Controllo Qualit├á', icon: TestTube },
    packaging: { title: 'Packaging', icon: Package },
};


export default function ProductionTimeAnalysisClientPage({ report }: ProductionTimeAnalysisClientPageProps) {
    const [searchTerm, setSearchTerm] = useState('');
    const [openAccordion, setOpenAccordion] = useState<string | undefined>(undefined);
    const searchParams = useSearchParams();
    const articleCodeFromUrl = searchParams.get('articleCode');
    const router = useRouter();
    const { toast } = useToast();

    useEffect(() => {
        if (articleCodeFromUrl) {
            setSearchTerm(articleCodeFromUrl);
            setOpenAccordion(articleCodeFromUrl);
        }
    }, [articleCodeFromUrl]);

    const filteredReport = useMemo(() => {
        if (!searchTerm) {
            return report;
        }
        const lowercasedFilter = searchTerm.toLowerCase();
        return report.filter(item =>
            item.articleCode.toLowerCase().includes(lowercasedFilter)
        );
    }, [report, searchTerm]);

    const handleExport = (articleReport: ProductionTimeAnalysisReport) => {
        const dataToExport: any[] = [];

        // Add average phase times first
        dataToExport.push({ 'Dettaglio': 'TEMPI MEDI PER FASE' });
        articleReport.averagePhaseTimes.forEach(phase => {
            dataToExport.push({
                'Dettaglio': phase.name,
                'Tempo Medio/Pezzo': phase.averageMinutesPerPiece.toFixed(4),
            });
        });
        dataToExport.push({}); // Add empty row for separation

        // Add job details
        dataToExport.push({ 'Dettaglio': 'DETTAGLIO PER COMMESSA' });
        articleReport.jobs.forEach(job => {
            // Main job row
            dataToExport.push({
                'Dettaglio': `Commessa: ${job.id}`,
                'Cliente': job.cliente,
                'Quantit├á': job.qta,
                'Calcolo Affidabile': job.isTimeCalculationReliable ? 'S├¼' : 'No',
                'Fase': 'TOTALE COMMESSA',
                'Tempo Totale (min)': job.totalTimeMinutes.toFixed(2),
                'Tempo Medio/Pezzo': job.minutesPerPiece.toFixed(4),
            });
            // Phase rows
            job.phases.forEach(phase => {
                dataToExport.push({
                    'Fase': phase.name,
                    'Tempo Totale (min)': phase.totalTimeMinutes.toFixed(2),
                    'Tempo Medio/Pezzo': phase.minutesPerPiece.toFixed(4),
                });
            })
        });

        const ws = XLSX.utils.json_to_sheet(dataToExport);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, `Analisi ${articleReport.articleCode}`);
        XLSX.writeFile(wb, `analisi_tempi_${articleReport.articleCode}.xlsx`);
    };

    const handleCopy = (text: string) => {
        navigator.clipboard.writeText(text);
        toast({
            title: "Copiato!",
            description: `Il codice "${text}" ├¿ stato copiato negli appunti.`,
        });
    }


    return (
        <div className="space-y-6">
            <header className="space-y-2">
                <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                    <Timer className="h-8 w-8 text-primary" />
                    Analisi Tempi di Produzione per Articolo
                </h1>
                <p className="text-muted-foreground">
                    Riepilogo dei tempi medi di lavorazione raggruppati per codice articolo.
                </p>
            </header>

            <Card>
                <CardHeader>
                    <div className="flex justify-between items-center flex-wrap gap-4">
                        <div>
                            <CardTitle>Report Articoli</CardTitle>
                            <CardDescription>
                                Espandi ogni articolo per visualizzare il dettaglio delle commesse e dei relativi tempi di produzione.
                            </CardDescription>
                        </div>
                        <div className="relative w-full sm:w-auto">
                            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                placeholder="Cerca per codice articolo..."
                                className="pl-9 w-full sm:w-64"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                        </div>
                    </div>
                </CardHeader>
                <CardContent>
                    {report.length > 0 ? (
                        <Accordion type="single" collapsible className="w-full" value={openAccordion} onValueChange={setOpenAccordion}>
                            {filteredReport.map((item) => {
                                const groupedPhases = item.averagePhaseTimes.reduce((acc, phase) => {
                                    const type = phase.type || 'production';
                                    if (!acc[type]) {
                                        acc[type] = [];
                                    }
                                    acc[type].push(phase);
                                    return acc;
                                }, {} as Record<string, typeof item.averagePhaseTimes>);

                                return (
                                    <AccordionItem value={item.articleCode} key={item.articleCode}>
                                        <AccordionTrigger>
                                            <div className="flex justify-between items-center w-full pr-4">
                                                <div className="flex items-center gap-3">
                                                    <Package className="h-5 w-5 text-primary" />
                                                    <ContextMenu>
                                                        <ContextMenuTrigger>
                                                            <span className="font-semibold text-lg hover:text-primary hover:underline cursor-pointer">{item.articleCode}</span>
                                                        </ContextMenuTrigger>
                                                        <ContextMenuContent>
                                                            <ContextMenuItem onSelect={() => handleCopy(item.articleCode)}>
                                                                <Copy className="mr-2 h-4 w-4" />
                                                                Copia Codice Articolo
                                                            </ContextMenuItem>
                                                        </ContextMenuContent>
                                                    </ContextMenu>
                                                </div>
                                                <div className="text-right">
                                                    <TooltipProvider>
                                                        <Tooltip>
                                                            <TooltipTrigger>
                                                                <div className="text-sm text-muted-foreground">
                                                                    Tempo Medio/Pz
                                                                    <span className={cn(
                                                                        "ml-1 font-semibold",
                                                                        item.averageMinutesPerPiece > 0 ? "text-green-600 dark:text-green-500" : "text-amber-600 dark:text-amber-500"
                                                                    )}>
                                                                        ({item.averageMinutesPerPiece > 0 ? 'Affidabile' : 'Parziale'})
                                                                    </span>
                                                                </div>
                                                            </TooltipTrigger>
                                                            <TooltipContent>
                                                                <p>Calcolato solo su commesse completate senza forzature.</p>
                                                            </TooltipContent>
                                                        </Tooltip>
                                                    </TooltipProvider>
                                                    <div className="font-bold text-lg text-primary">{item.averageMinutesPerPiece > 0 ? `${item.averageMinutesPerPiece.toFixed(4)} min` : 'N/D'}</div>
                                                </div>
                                            </div>
                                        </AccordionTrigger>
                                        <AccordionContent>
                                            <div className="p-4 bg-muted/50 rounded-lg space-y-6">
                                                <div className="space-y-4">
                                                    <h4 className="font-semibold text-base mb-2 flex items-center gap-2"><BarChart className="h-5 w-5 text-primary" />Riepilogo Tempi Medi per Fase</h4>
                                                    {Object.entries(groupedPhases).map(([type, phases]) => {
                                                        const phaseInfo = phaseTypeTitles[type] || { title: type, icon: BarChart };
                                                        const Icon = phaseInfo.icon;
                                                        return (
                                                            <div key={type}>
                                                                <div className="flex items-center gap-2 mb-2">
                                                                    <Icon className="h-4 w-4 text-muted-foreground" />
                                                                    <h5 className="font-semibold text-muted-foreground">{phaseInfo.title}</h5>
                                                                </div>
                                                                <div className="overflow-x-auto border rounded-lg">
                                                                    <Table>
                                                                        <TableHeader>
                                                                            <TableRow>
                                                                                <TableHead>Fase di Lavorazione</TableHead>
                                                                                <TableHead className="text-right">Tempo Medio/Pezzo</TableHead>
                                                                            </TableRow>
                                                                        </TableHeader>
                                                                        <TableBody>
                                                                            {phases.map(phase => (
                                                                                <TableRow key={phase.name}>
                                                                                    <TableCell>{phase.name}</TableCell>
                                                                                    <TableCell className="text-right font-mono">{phase.averageMinutesPerPiece.toFixed(4)} min</TableCell>
                                                                                </TableRow>
                                                                            ))}
                                                                        </TableBody>
                                                                    </Table>
                                                                </div>
                                                                <Separator className="my-4" />
                                                            </div>
                                                        )
                                                    })}
                                                    {item.averagePhaseTimes.length === 0 && (
                                                        <p className="text-center text-sm text-muted-foreground py-4">Nessun dato aggregato disponibile per le fasi.</p>
                                                    )}
                                                </div>

                                                <div>
                                                    <div className="flex justify-between items-center mb-2">
                                                        <h4 className="font-semibold text-base flex items-center gap-2">Dettaglio Commesse ({item.totalJobs})</h4>
                                                        <Button variant="outline" size="sm" onClick={() => handleExport(item)}>
                                                            <Download className="mr-2 h-4 w-4" />
                                                            Esporta Dettaglio
                                                        </Button>
                                                    </div>
                                                    <div className="space-y-4">
                                                        {item.jobs.map(job => (
                                                            <Collapsible key={job.id} className="border-t pt-4">
                                                                <CollapsibleTrigger asChild>
                                                                    <div className="flex justify-between items-center w-full cursor-pointer hover:bg-background/50 p-2 rounded-md group">
                                                                        <div className="flex-1">
                                                                            <div className="font-mono text-base font-semibold">{job.id} <Badge variant="secondary" className="ml-2">Cliente: {job.cliente}</Badge></div>
                                                                            <div className="text-sm text-muted-foreground">Q.t├á: {job.qta}</div>
                                                                        </div>
                                                                        <div className="text-right">
                                                                            <div className={cn("font-semibold", job.isTimeCalculationReliable ? "text-green-600 dark:text-green-500" : "text-amber-600 dark:text-amber-500")}>{job.minutesPerPiece.toFixed(4)} min/pz</div>
                                                                            <div className="text-xs text-muted-foreground">Tot: {job.totalTimeMinutes.toFixed(2)} min</div>
                                                                        </div>
                                                                        <ChevronRight className="h-4 w-4 ml-2 transition-transform duration-200 group-data-[state=open]:rotate-90" />
                                                                    </div>
                                                                </CollapsibleTrigger>
                                                                <CollapsibleContent>
                                                                    <div className="pl-6 pt-2">
                                                                        <Table>
                                                                            <TableHeader>
                                                                                <TableRow>
                                                                                    <TableHead>Fase (con tempo tracciato)</TableHead>
                                                                                    <TableHead className="text-right">Tempo Totale Fase</TableHead>
                                                                                    <TableHead className="text-right">Minuti/Pezzo</TableHead>
                                                                                </TableRow>
                                                                            </TableHeader>
                                                                            <TableBody>
                                                                                {job.phases.map((phase, index) => (
                                                                                    <TableRow key={index}>
                                                                                        <TableCell>{phase.name}</TableCell>
                                                                                        <TableCell className="text-right">{phase.totalTimeMinutes.toFixed(2)} min</TableCell>
                                                                                        <TableCell className="text-right font-medium">{phase.minutesPerPiece.toFixed(4)} min</TableCell>
                                                                                    </TableRow>
                                                                                ))}
                                                                            </TableBody>
                                                                        </Table>
                                                                    </div>
                                                                </CollapsibleContent>
                                                            </Collapsible>
                                                        ))}
                                                    </div>
                                                </div>
                                            </div>
                                        </AccordionContent>
                                    </AccordionItem>
                                )
                            })}
                            {filteredReport.length === 0 && (
                                <div className="text-center py-10 text-muted-foreground">
                                    Nessun articolo trovato per "{searchTerm}".
                                </div>
                            )}
                        </Accordion>
                    ) : (
                        <div className="flex flex-col items-center justify-center py-10 text-center">
                            <Package className="h-16 w-16 text-muted-foreground mb-4" />
                            <p className="text-lg font-semibold text-muted-foreground">Nessun dato disponibile.</p>
                            <p className="text-sm text-muted-foreground">
                                Non ci sono ancora commesse con tempi di lavorazione registrati.
                            </p>
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    );
}

"use client";

import React, { useState, useRef, useMemo, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { format, parseISO } from 'date-fns';
import { useToast } from '@/hooks/use-toast';
import { useAuth } from '@/components/auth/AuthProvider';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { 
  Truck, 
  PlusCircle, 
  Search, 
  Trash2, 
  Upload, 
  Loader2, 
  Calendar as CalendarIcon, 
  Save, 
  ChevronsUpDown, 
  Check, 
  Pencil, 
  Plus, 
  X, 
  Boxes, 
  ArrowUpDown,
  CheckCircle2,
  Package2
} from 'lucide-react';
import { getPurchaseOrders, deleteOrderGroup, importPurchaseOrders, savePurchaseOrder, closePurchaseOrder } from './actions';
import { 
  AlertDialog, 
  AlertDialogAction, 
  AlertDialogCancel, 
  AlertDialogContent, 
  AlertDialogDescription, 
  AlertDialogFooter, 
  AlertDialogHeader, 
  AlertDialogTitle,
  AlertDialogTrigger
} from '@/components/ui/alert-dialog';
import { 
  Dialog, 
  DialogContent, 
  DialogHeader, 
  DialogTitle,
  DialogFooter
} from '@/components/ui/dialog';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem, CommandList } from '@/components/ui/command';
import { Calendar } from '@/components/ui/calendar';
import { type PurchaseOrder, type RawMaterial } from '@/lib/mock-data';
import { useForm, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { cn } from '@/lib/utils';
import { ScrollArea } from '@/components/ui/scroll-area';
import { useSearchParams } from 'next/navigation';
import { Accordion, AccordionContent, AccordionItem, AccordionTrigger } from '@/components/ui/accordion';

const itemSchema = z.object({
  id: z.string().optional(),
  materialCode: z.string().min(1, "Il codice materiale ├¿ obbligatorio."),
  quantity: z.coerce.number().positive("La quantit├á deve essere positiva."),
  unitOfMeasure: z.enum(['n', 'mt', 'kg']),
  expectedDeliveryDate: z.date({ required_error: "La data di consegna ├¿ obbligatoria." }),
});

const orderFormSchema = z.object({
  orderNumber: z.string().min(1, "Il numero ordine ├¿ obbligatorio."),
  supplierName: z.string().optional(),
  items: z.array(itemSchema).min(1, "Aggiungere almeno un materiale."),
});

type OrderFormValues = z.infer<typeof orderFormSchema>;

export default function PurchaseOrderManagementClientPage({ 
  initialOrders,
  rawMaterials
}: { 
  initialOrders: PurchaseOrder[],
  rawMaterials: RawMaterial[]
}) {
  const searchParams = useSearchParams();
  const materialCodeParam = searchParams.get('materialCode');
  
  const [orders, setOrders] = useState<PurchaseOrder[]>(initialOrders);
  const [searchTerm, setSearchTerm] = useState(materialCodeParam || '');
  const [isImporting, setIsImporting] = useState(false);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [editingOrderNumber, setEditingOrderNumber] = useState<string | null>(null);
  const [sortDirection, setSortDirection] = useState<'asc' | 'desc'>('asc');
  
  const [openComboboxIndex, setOpenComboboxIndex] = useState<number | null>(null);
  
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { toast } = useToast();
  const { user } = useAuth();

  useEffect(() => {
    if (materialCodeParam) {
      setSearchTerm(materialCodeParam);
    }
  }, [materialCodeParam]);

  const form = useForm<OrderFormValues>({
    resolver: zodResolver(orderFormSchema),
    defaultValues: {
      orderNumber: '',
      supplierName: '',
      items: [{ materialCode: '', quantity: 0, unitOfMeasure: 'n', expectedDeliveryDate: new Date() }]
    }
  });

  const { fields, append, remove } = useFieldArray({
    control: form.control,
    name: "items"
  });

  const groupedOrders = useMemo(() => {
    const groups: Record<string, {
        orderNumber: string;
        supplierName: string;
        items: PurchaseOrder[];
        earliestDelivery: string;
        status: 'pending' | 'received';
    }> = {};

    orders.forEach(o => {
        if (!groups[o.orderNumber]) {
            groups[o.orderNumber] = {
                orderNumber: o.orderNumber,
                supplierName: o.supplierName || 'N/D',
                items: [],
                earliestDelivery: '',
                status: 'received'
            };
        }
        groups[o.orderNumber].items.push(o);
        if (o.status === 'pending' || o.status === 'partially_received') {
            groups[o.orderNumber].status = 'pending';
        }
    });

    Object.values(groups).forEach(group => {
        const pendingItems = group.items.filter(i => i.status === 'pending' || i.status === 'partially_received');
        if (pendingItems.length > 0) {
            group.earliestDelivery = pendingItems.reduce((min, i) => 
                (min === '' || i.expectedDeliveryDate < min) ? i.expectedDeliveryDate : min, ''
            );
        } else {
            group.earliestDelivery = group.items.reduce((min, i) => 
                (min === '' || i.expectedDeliveryDate < min) ? i.expectedDeliveryDate : min, ''
            );
        }
    });

    let result = Object.values(groups);

    if (searchTerm) {
        const lower = searchTerm.toLowerCase();
        result = result.filter(g => 
            g.orderNumber.toLowerCase().includes(lower) ||
            g.supplierName.toLowerCase().includes(lower) ||
            g.items.some(i => i.materialCode.toLowerCase().includes(lower))
        );
    }

    result.sort((a, b) => {
        const dateA = new Date(a.earliestDelivery).getTime();
        const dateB = new Date(b.earliestDelivery).getTime();
        return sortDirection === 'asc' ? dateA - dateB : dateB - dateA;
    });

    return result;
  }, [orders, searchTerm, sortDirection]);

  const handleOpenDialog = (orderToEdit?: any) => {
    if (orderToEdit) {
        setEditingOrderNumber(orderToEdit.orderNumber);
        form.reset({
            orderNumber: orderToEdit.orderNumber,
            supplierName: orderToEdit.supplierName,
            items: orderToEdit.items.map((item: PurchaseOrder) => ({
                id: item.id,
                materialCode: item.materialCode,
                quantity: item.quantity,
                unitOfMeasure: item.unitOfMeasure,
                expectedDeliveryDate: new Date(item.expectedDeliveryDate)
            }))
        });
    } else {
        setEditingOrderNumber(null);
        form.reset({
            orderNumber: '',
            supplierName: '',
            items: [{ materialCode: '', quantity: 0, unitOfMeasure: 'n', expectedDeliveryDate: new Date() }]
        });
    }
    setIsDialogOpen(true);
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || !user) return;
    setIsImporting(true);
    try {
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data, { type: 'array', cellDates: true });
      const json: any[] = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]]);
      const result = await importPurchaseOrders(json, user.uid);
      if (result.success) {
        toast({ title: "Importazione Riuscita" });
        const updated = await getPurchaseOrders();
        setOrders(updated);
      } else toast({ variant: 'destructive', title: "Errore", description: result.message });
    } catch (e) { toast({ variant: 'destructive', title: "Errore File" }); }
    finally { setIsImporting(false); }
  };

  const onManualSubmit = async (values: OrderFormValues) => {
    if (!user) return;
    setIsSaving(true);
    const payload = { 
        orderNumber: values.orderNumber, 
        supplierName: values.supplierName || '', 
        items: values.items.map(item => ({ 
            ...item, 
            expectedDeliveryDate: item.expectedDeliveryDate.toISOString() 
        })) 
    };
    
    const result = await savePurchaseOrder(payload, user.uid);
    if (result.success) {
      toast({ title: editingOrderNumber ? "Ordine Aggiornato" : "Ordini Salvati" });
      const updated = await getPurchaseOrders();
      setOrders(updated);
      setIsDialogOpen(false);
      form.reset();
    } else toast({ variant: "destructive", title: "Errore", description: result.message });
    setIsSaving(false);
  };

  const handleDeleteOrder = async (orderNumber: string) => {
      if (!user) return;
      const res = await deleteOrderGroup(orderNumber, user.uid);
      if (res.success) {
          toast({ title: "Ordine Eliminato" });
          setOrders(prev => prev.filter(o => o.orderNumber !== orderNumber));
      } else {
          toast({ variant: "destructive", title: "Errore", description: res.message });
      }
  };

  const handleCloseItem = async (itemId: string) => {
      if (!user) return;
      const res = await closePurchaseOrder(itemId, user.uid);
      if (res.success) {
          toast({ title: "Riga chiusa" });
          const updated = await getPurchaseOrders();
          setOrders(updated);
      } else {
          toast({ variant: "destructive", title: "Errore", description: res.message });
      }
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col sm:flex-row justify-between items-start gap-4">
        <div><h1 className="text-3xl font-bold font-headline flex items-center gap-3"><Truck className="h-8 w-8 text-primary" /> Ordini Fornitore</h1></div>
        <div className="flex items-center gap-2 pt-2 flex-wrap">
          <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" className="hidden" />
          <Button onClick={() => fileInputRef.current?.click()} variant="outline" size="sm" disabled={isImporting}><Upload className="mr-2 h-4 w-4" /> Importa Excel</Button>
          <Button size="sm" onClick={() => handleOpenDialog()}><PlusCircle className="mr-2 h-4 w-4" /> Nuovo Ordine</Button>
        </div>
      </header>

      <Card>
        <CardHeader>
            <div className="flex flex-col md:flex-row justify-between items-center gap-4">
                <div>
                    <CardTitle>Riepilogo Ordini Raggruppati</CardTitle>
                    <CardDescription>Visualizza e gestisci gli ordini completi per fornitore.</CardDescription>
                </div>
                <div className="flex items-center gap-2 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                        <Input 
                            placeholder="Cerca ordine, materiale..." 
                            className="pl-9" 
                            value={searchTerm} 
                            onChange={(e) => setSearchTerm(e.target.value)} 
                        />
                    </div>
                    <Button 
                        variant="outline" 
                        size="sm" 
                        onClick={() => setSortDirection(prev => prev === 'asc' ? 'desc' : 'asc')}
                        className="whitespace-nowrap"
                    >
                        <ArrowUpDown className="mr-2 h-4 w-4" />
                        Scadenza {sortDirection === 'asc' ? 'Ôåæ' : 'Ôåô'}
                    </Button>
                </div>
            </div>
        </CardHeader>
        <CardContent>
          <ScrollArea className="h-[600px] pr-4">
            <Accordion type="multiple" className="space-y-4">
                {groupedOrders.length > 0 ? groupedOrders.map((group) => (
                    <AccordionItem key={group.orderNumber} value={group.orderNumber} className="border rounded-lg bg-card overflow-hidden">
                        <AccordionTrigger className="px-4 py-3 hover:no-underline hover:bg-muted/30">
                            <div className="flex flex-1 items-center justify-between gap-4 text-left">
                                <div className="flex items-center gap-4">
                                    <Badge 
                                        className={cn(
                                            "min-w-[100px] justify-center uppercase font-bold",
                                            group.status === 'pending' ? "bg-amber-500 hover:bg-amber-600" : "bg-green-600 hover:bg-green-700"
                                        )}
                                    >
                                        {group.status === 'pending' ? 'In Attesa' : 'Ricevuto'}
                                    </Badge>
                                    <div>
                                        <p className="font-bold text-lg font-mono">{group.orderNumber}</p>
                                        <p className="text-xs text-muted-foreground">{group.supplierName}</p>
                                    </div>
                                </div>
                                <div className="text-right mr-4">
                                    <p className="text-[10px] uppercase font-bold text-muted-foreground">Scadenza Prossima</p>
                                    <p className="font-semibold text-sm flex items-center gap-1 justify-end">
                                        <CalendarIcon className="h-3 w-3" />
                                        {group.earliestDelivery ? format(parseISO(group.earliestDelivery), 'dd/MM/yy') : '---'}
                                    </p>
                                </div>
                            </div>
                        </AccordionTrigger>
                        <AccordionContent className="px-4 pb-4 border-t pt-2">
                            <div className="flex justify-end gap-2 mb-4 mt-2">
                                <Button size="sm" variant="outline" onClick={() => handleOpenDialog(group)}>
                                    <Pencil className="mr-2 h-4 w-4" /> Modifica Ordine
                                </Button>
                                <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                        <Button size="sm" variant="destructive">
                                            <Trash2 className="mr-2 h-4 w-4" /> Elimina
                                        </Button>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader>
                                            <AlertDialogTitle>Sei sicuro di voler eliminare l'intero ordine?</AlertDialogTitle>
                                            <AlertDialogDescription>
                                                Questa azione eliminer├á tutte le {group.items.length} righe dell'ordine {group.orderNumber}.
                                            </AlertDialogDescription>
                                        </AlertDialogHeader>
                                        <AlertDialogFooter>
                                            <AlertDialogCancel>Annulla</AlertDialogCancel>
                                            <AlertDialogAction onClick={() => handleDeleteOrder(group.orderNumber)} className="bg-destructive">Elimina Tutto</AlertDialogAction>
                                        </AlertDialogFooter>
                                    </AlertDialogContent>
                                </AlertDialog>
                            </div>
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Materiale</TableHead>
                                        <TableHead>Quantit├á</TableHead>
                                        <TableHead>Ricevuta</TableHead>
                                        <TableHead>Data Consegna</TableHead>
                                        <TableHead>Stato</TableHead>
                                        <TableHead className="text-right">Azioni</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {group.items.map(item => (
                                        <TableRow key={item.id}>
                                            <TableCell className="font-semibold">{item.materialCode}</TableCell>
                                            <TableCell>{item.quantity} {item.unitOfMeasure.toUpperCase()}</TableCell>
                                            <TableCell>{item.receivedQuantity || 0} {item.unitOfMeasure.toUpperCase()}</TableCell>
                                            <TableCell>{format(parseISO(item.expectedDeliveryDate), 'dd/MM/yy')}</TableCell>
                                            <TableCell>
                                                <Badge variant={item.status === 'received' ? 'default' : 'outline'} className={cn(item.status === 'received' && 'bg-green-600 hover:bg-green-700')}>
                                                    {item.status === 'received' ? 'OK' : item.status === 'partially_received' ? 'Parziale' : 'In Attesa'}
                                                </Badge>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                {item.status !== 'received' && (
                                                    <AlertDialog>
                                                        <AlertDialogTrigger asChild>
                                                            <Button size="sm" variant="ghost" className="h-8 text-xs text-blue-600 hover:text-blue-700 hover:bg-blue-50">
                                                                <CheckCircle2 className="mr-1 h-3 w-3" /> Chiudi
                                                            </Button>
                                                        </AlertDialogTrigger>
                                                        <AlertDialogContent>
                                                            <AlertDialogHeader>
                                                                <AlertDialogTitle>Chiudere forzatamente la riga?</AlertDialogTitle>
                                                                <AlertDialogDescription>
                                                                    La quantit├á ordinata ({item.quantity}) verr├á equiparata a quella ricevuta ({item.receivedQuantity || 0}). 
                                                                    La riga non risulter├á pi├╣ come "in arrivo".
                                                                </AlertDialogDescription>
                                                            </AlertDialogHeader>
                                                            <AlertDialogFooter>
                                                                <AlertDialogCancel>Annulla</AlertDialogCancel>
                                                                <AlertDialogAction onClick={() => handleCloseItem(item.id)}>Conferma Chiusura</AlertDialogAction>
                                                            </AlertDialogFooter>
                                                        </AlertDialogContent>
                                                    </AlertDialog>
                                                )}
                                            </TableCell>
                                        </TableRow>
                                    ))}
                                </TableBody>
                            </Table>
                        </AccordionContent>
                    </AccordionItem>
                )) : (
                    <div className="flex flex-col items-center justify-center py-20 text-muted-foreground">
                        <Package2 className="h-16 w-16 opacity-20 mb-4" />
                        <p>Nessun ordine trovato.</p>
                    </div>
                )}
            </Accordion>
          </ScrollArea>
        </CardContent>
      </Card>

      <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
        <DialogContent className="max-w-4xl max-h-[90vh] flex flex-col">
          <DialogHeader>
            <DialogTitle>{editingOrderNumber ? `Modifica Ordine: ${editingOrderNumber}` : 'Crea Nuovo Ordine Fornitore'}</DialogTitle>
          </DialogHeader>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onManualSubmit)} className="flex-1 overflow-hidden flex flex-col">
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 pb-4 border-b">
                <FormField control={form.control} name="orderNumber" render={({ field }) => ( 
                    <FormItem>
                        <FormLabel>N┬░ Ordine</FormLabel>
                        <FormControl><Input {...field} disabled={!!editingOrderNumber} placeholder="Es. 123/G" /></FormControl>
                        <FormMessage />
                    </FormItem> 
                )} />
                <FormField control={form.control} name="supplierName" render={({ field }) => ( 
                    <FormItem>
                        <FormLabel>Fornitore</FormLabel>
                        <FormControl><Input {...field} placeholder="Nome Fornitore" /></FormControl>
                        <FormMessage />
                    </FormItem> 
                )} />
              </div>
              <ScrollArea className="flex-1 py-4">
                <div className="space-y-4">
                  <h4 className="font-semibold flex items-center gap-2"><Boxes className="h-4 w-4"/> Righe Materiale</h4>
                  {fields.map((item, index) => (
                    <div key={item.id} className="p-4 border rounded-lg grid grid-cols-12 gap-3 items-end bg-muted/20 relative">
                      <div className="col-span-12 sm:col-span-4">
                        <FormField control={form.control} name={`items.${index}.materialCode`} render={({ field }) => (
                          <FormItem className="flex flex-col"><FormLabel>Materiale</FormLabel>
                            <Popover open={openComboboxIndex === index} onOpenChange={(open) => setOpenComboboxIndex(open ? index : null)}>
                              <PopoverTrigger asChild><FormControl><Button variant="outline" className="w-full justify-between">{field.value || "Seleziona..."}<ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" /></Button></FormControl></PopoverTrigger>
                              <PopoverContent className="w-[--radix-popover-trigger-width] p-0"><Command><CommandInput placeholder="Cerca..." /><CommandList><CommandEmpty>Nessun materiale.</CommandEmpty><CommandGroup>
                                {rawMaterials.map((m) => (<CommandItem key={m.id} value={m.code} onSelect={() => { form.setValue(`items.${index}.materialCode`, m.code); form.setValue(`items.${index}.unitOfMeasure`, m.unitOfMeasure); setOpenComboboxIndex(null); }}>{m.code}</CommandItem>))}
                              </CommandGroup></CommandList></Command></PopoverContent>
                            </Popover>
                          </FormItem>
                        )} />
                      </div>
                      <div className="col-span-6 sm:col-span-2"><FormField control={form.control} name={`items.${index}.quantity`} render={({ field }) => ( <FormItem><FormLabel>Quantit├á</FormLabel><FormControl><Input type="number" step="any" {...field} /></FormControl></FormItem> )} /></div>
                      <div className="col-span-6 sm:col-span-2"><FormField control={form.control} name={`items.${index}.unitOfMeasure`} render={({ field }) => ( <FormItem><FormLabel>UM</FormLabel><FormControl><Input readOnly {...field} className="bg-muted"/></FormControl></FormItem> )} /></div>
                      <div className="col-span-10 sm:col-span-3"><FormField control={form.control} name={`items.${index}.expectedDeliveryDate`} render={({ field }) => ( <FormItem><FormLabel>Consegna</FormLabel><Popover><PopoverTrigger asChild><Button variant="outline" className="w-full justify-start">{field.value ? format(field.value, "dd/MM/yy") : "Data"}</Button></PopoverTrigger><PopoverContent className="w-auto p-0"><Calendar mode="single" selected={field.value} onSelect={field.onChange} initialFocus /></PopoverContent></Popover></FormItem> )} /></div>
                      <div className="col-span-2 sm:col-span-1">
                        <Button type="button" variant="ghost" size="icon" onClick={() => remove(index)} className="text-destructive">
                            <X className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  ))}
                  <Button type="button" variant="outline" className="w-full border-dashed" onClick={() => append({ materialCode: '', quantity: 0, unitOfMeasure: 'n', expectedDeliveryDate: new Date() })}><Plus className="mr-2 h-4 w-4"/> Aggiungi riga materiale</Button>
                </div>
              </ScrollArea>
              <DialogFooter className="pt-4 border-t">
                <Button type="submit" disabled={isSaving}>
                    {isSaving ? <Loader2 className="animate-spin mr-2" /> : <Save className="mr-2" />} 
                    {editingOrderNumber ? "Salva Modifiche" : "Registra Ordine"}
                </Button>
              </DialogFooter>
            </form>
          </Form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';
import { format, parseISO, parse, isValid } from 'date-fns';
import { it } from 'date-fns/locale';
import * as XLSX from 'xlsx';

import { type ManualCommitment, type Article, type RawMaterial, type RawMaterialBatch } from '@/lib/mock-data';
import { saveManualCommitment, deleteManualCommitment, importManualCommitments, revertManualCommitmentFulfillment, declareCommitmentFulfillment, type LotSelectionPayload, getMaterialsByCodes, getLotInfoForMaterial, type LotInfo } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';

import { Button } from '@/components/ui/button';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Dialog, DialogTrigger, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter, DialogClose } from '@/components/ui/dialog';
import { AlertDialog, AlertDialogTrigger, AlertDialogContent, AlertDialogHeader, AlertDialogTitle, AlertDialogDescription, AlertDialogFooter, AlertDialogCancel, AlertDialogAction } from '@/components/ui/alert-dialog';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Input } from '@/components/ui/input';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem } from '@/components/ui/command';
import { Calendar } from '@/components/ui/calendar';
import { Badge } from '@/components/ui/badge';
import { CalendarIcon, Check, ChevronsUpDown, FileCheck2, Loader2, PlusCircle, Trash2, CheckCircle2, Circle, Upload, Download, Undo2, TestTube, Send, Search } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Label } from '@/components/ui/label';
import { formatDisplayStock } from '@/lib/utils';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { Select, SelectTrigger, SelectValue, SelectContent, SelectItem } from '@/components/ui/select';
import { Checkbox } from '@/components/ui/checkbox';

// Schemas and types at top level
const declarationSchema = z.object({
  goodPieces: z.coerce.number().min(0, "La quantit├á non pu├▓ essere negativa."),
  scrapPieces: z.coerce.number().min(0, "La quantit├á non pu├▓ essere negativa.").default(0),
});
type DeclarationFormValues = z.infer<typeof declarationSchema>;


// Declaration Dialog Component moved to top level
function DeclarationDialog({
  isOpen,
  onOpenChange,
  commitment,
  article,
  onDeclare,
}: {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  commitment: ManualCommitment;
  article: Article | undefined;
  onDeclare: (values: DeclarationFormValues, lotSelections: LotSelectionPayload[]) => void;
}) {
  const { toast } = useToast();
  const form = useForm<DeclarationFormValues>({
    resolver: zodResolver(declarationSchema),
  });

  const [componentMaterials, setComponentMaterials] = useState<RawMaterial[]>([]);
  const [lotInfo, setLotInfo] = useState<LotInfo[]>([]);
  const [isLoadingMaterials, setIsLoadingMaterials] = useState(false);
  const [selectedLottos, setSelectedLottos] = useState<Set<string>>(new Set());

  const { goodPieces, scrapPieces } = form.watch();

  useEffect(() => {
    if (isOpen) {
      form.reset({ goodPieces: commitment.quantity, scrapPieces: 0 });
      setSelectedLottos(new Set()); // Reset selections

      if (article?.billOfMaterials) {
        const fetchComponentMaterialsAndLots = async () => {
          setIsLoadingMaterials(true);
          const componentCode = article.billOfMaterials[0]?.component;
          if (componentCode) {
            const materials = await getMaterialsByCodes([componentCode]);
            const material = materials[0];
            if (material) {
              setComponentMaterials([material]);
              const lotData = await getLotInfoForMaterial(material.id);
              setLotInfo(lotData);
            } else {
              setComponentMaterials([]);
              setLotInfo([]);
            }
          } else {
            setComponentMaterials([]);
            setLotInfo([]);
          }
          setIsLoadingMaterials(false);
        };
        fetchComponentMaterialsAndLots();
      }
    }
  }, [isOpen, article, commitment.quantity, form]);

  const bomItem = useMemo(() => article?.billOfMaterials?.[0], [article]);
  const displayUnit = useMemo(() => bomItem?.lunghezzaTaglioMm && bomItem.lunghezzaTaglioMm > 0 ? 'mt' : bomItem?.unit || 'n', [bomItem]);

  const totalRequirement = useMemo(() => {
    if (!bomItem) return 0;
    const totalPieces = (Number(goodPieces) || 0) + (Number(scrapPieces) || 0);

    if (displayUnit === 'mt' && bomItem.lunghezzaTaglioMm) {
      return (totalPieces * bomItem.quantity * bomItem.lunghezzaTaglioMm) / 1000;
    }
    return totalPieces * bomItem.quantity;
  }, [bomItem, goodPieces, scrapPieces, displayUnit]);

  const sortedSelectedLottos = useMemo(() => {
    return lotInfo
      .filter(l => selectedLottos.has(l.lotto))
      .sort((a, b) => new Date(a.batches[0].date).getTime() - new Date(b.batches[0].date).getTime());
  }, [lotInfo, selectedLottos]);

  const { consumptionMap, totalSelected, isRequirementMet } = useMemo(() => {
    const newConsumptionMap = new Map<string, number>();
    let remainingRequirement = totalRequirement;

    for (const lot of sortedSelectedLottos) {
      if (remainingRequirement <= 0.001) break;
      const consumedFromThisLot = Math.min(remainingRequirement, lot.available);
      newConsumptionMap.set(lot.lotto, consumedFromThisLot);
      remainingRequirement -= consumedFromThisLot;
    }

    const totalSelectedAmount = Array.from(newConsumptionMap.values()).reduce((sum, val) => sum + val, 0);

    return {
      consumptionMap: newConsumptionMap,
      totalSelected: totalSelectedAmount,
      isRequirementMet: totalRequirement === 0 || totalSelectedAmount >= totalRequirement - 0.001,
    };
  }, [sortedSelectedLottos, totalRequirement]);

  const handleDeclareSubmit = (values: DeclarationFormValues) => {
    if (!isRequirementMet) {
      toast({ variant: "destructive", title: "Fabbisogno non soddisfatto", description: "Selezionare lotti sufficienti a coprire il fabbisogno." });
      return;
    }

    const selectionsPayload: LotSelectionPayload[] = [];
    consumptionMap.forEach((consumed, lotto) => {
      if (consumed > 0) {
        const material = componentMaterials[0];
        if (material) {
          selectionsPayload.push({
            materialId: material.id,
            componentCode: material.code,
            lotto: lotto,
            consumed: consumed
          });
        }
      }
    });

    onDeclare(values, selectionsPayload);
  };

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl h-[90vh] flex flex-col p-0">
        <DialogHeader className="p-6 pb-2">
          <DialogTitle>Dichiarazione di Produzione</DialogTitle>
          <DialogDescription>
            Conferma la quantit├á prodotta, eventuali scarti e seleziona i lotti da cui scaricare il materiale per la commessa <span className="font-bold">{commitment.jobOrderCode}</span>.
          </DialogDescription>
        </DialogHeader>
        <Form {...form}>
          <form onSubmit={form.handleSubmit(handleDeclareSubmit)} className="flex-1 flex flex-col overflow-hidden">
            <div className="px-6 pt-4">
              <div className="grid grid-cols-2 gap-4">
                <FormField control={form.control} name="goodPieces" render={({ field }) => (
                  <FormItem>
                    <FormLabel>Pezzi Prodotti</FormLabel>
                    <FormControl><Input type="number" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
                <FormField control={form.control} name="scrapPieces" render={({ field }) => (
                  <FormItem>
                    <FormLabel className="flex items-center gap-2"><TestTube className="h-4 w-4 text-destructive" /> Pezzi di Scarto</FormLabel>
                    <FormControl><Input type="number" {...field} /></FormControl>
                    <FormMessage />
                  </FormItem>
                )} />
              </div>
            </div>
            <div className="flex-1 px-6 py-4 min-h-0">
              <ScrollArea className="h-full pr-6">
                {isLoadingMaterials ? (
                  <div className="space-y-4"> <Skeleton className="h-24 w-full" /> <Skeleton className="h-24 w-full" /> </div>
                ) : bomItem ? (
                  <div className="p-4 border rounded-lg">
                    <div className="flex justify-between items-center mb-4 flex-wrap gap-2">
                      <h4 className="font-semibold">{bomItem.component}</h4>
                      <div className="text-right text-sm">
                        <p>Fabbisogno: <span className="font-bold">{formatDisplayStock(totalRequirement, displayUnit)} {displayUnit}</span></p>
                        <p>Selezionato: <span className={cn("font-bold", !isRequirementMet && totalRequirement > 0 ? 'text-destructive' : 'text-green-600')}>{formatDisplayStock(totalSelected, displayUnit)} {displayUnit}</span></p>
                      </div>
                    </div>
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead className="w-[50px]">Sel.</TableHead>
                          <TableHead>Lotto</TableHead>
                          <TableHead>Disponibile</TableHead>
                          <TableHead className="text-right">Da Usare</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {lotInfo.map(lot => {
                          const consumed = consumptionMap.get(lot.lotto) || 0;
                          return (
                            <TableRow key={lot.lotto} data-state={selectedLottos.has(lot.lotto) && "selected"}>
                              <TableCell>
                                <Checkbox
                                  checked={selectedLottos.has(lot.lotto)}
                                  onCheckedChange={(checked) => {
                                    setSelectedLottos(prev => {
                                      const newSet = new Set(prev);
                                      if (checked) {
                                        newSet.add(lot.lotto);
                                      } else {
                                        newSet.delete(lot.lotto);
                                      }
                                      return newSet;
                                    })
                                  }}
                                />
                              </TableCell>
                              <TableCell>{lot.lotto}</TableCell>
                              <TableCell>{formatDisplayStock(lot.available, displayUnit)} {displayUnit}</TableCell>
                              <TableCell className="text-right font-mono font-semibold text-primary">{formatDisplayStock(consumed, displayUnit)} {displayUnit}</TableCell>
                            </TableRow>
                          )
                        })}
                      </TableBody>
                    </Table>
                  </div>
                ) : null}
              </ScrollArea>
            </div>
            <DialogFooter className="p-6 pt-4 border-t sticky bottom-0 bg-background">
              <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>Annulla</Button>
              <Button type="submit" disabled={form.formState.isSubmitting || !isRequirementMet || isLoadingMaterials}>
                {form.formState.isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Send className="mr-2 h-4 w-4" />}
                Dichiara e Scarica Stock
              </Button>
            </DialogFooter>
          </form>
        </Form>
      </DialogContent>
    </Dialog>
  );
}

// Main Component
export default function CommitmentManagementClientPage({
  initialCommitments,
  initialArticles,
}: {
  initialCommitments: ManualCommitment[];
  initialArticles: Article[];
}) {
  const [commitments, setCommitments] = useState(initialCommitments);
  const [searchTerm, setSearchTerm] = useState('');
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [isPending, setIsPending] = useState(false);
  const [declarationTarget, setDeclarationTarget] = useState<ManualCommitment | null>(null);

  const { toast } = useToast();
  const { user } = useAuth();
  const router = useRouter();
  const [dateString, setDateString] = useState<string>('');

  const fileInputRef = useRef<HTMLInputElement>(null);
  const [isImporting, setIsImporting] = useState(false);

  // New state for article popover
  const [isArticlePopoverOpen, setIsArticlePopoverOpen] = useState(false);

  const commitmentFormSchema = z.object({
    id: z.string().optional(),
    jobOrderCode: z.string().min(1, "Il codice commessa ├¿ obbligatorio."),
    articleCode: z.string().min(1, "Selezionare un articolo."),
    quantity: z.coerce.number().positive("La quantit├á deve essere un numero positivo."),
    deliveryDate: z.date({ required_error: "La data di consegna ├¿ obbligatoria." }),
  });
  type CommitmentFormValues = z.infer<typeof commitmentFormSchema>;

  const form = useForm<CommitmentFormValues>({
    resolver: zodResolver(commitmentFormSchema),
  });

  useEffect(() => {
    setCommitments(initialCommitments);
  }, [initialCommitments]);

  useEffect(() => {
    if (isFormOpen) {
      const deliveryDate = form.getValues('deliveryDate');
      if (deliveryDate && isValid(deliveryDate)) {
        setDateString(format(deliveryDate, 'dd/MM/yyyy'));
      } else {
        setDateString('');
      }
    }
  }, [isFormOpen, form]);

  const filteredCommitments = useMemo(() => {
    if (!searchTerm) {
      return commitments;
    }
    const lowercasedFilter = searchTerm.toLowerCase();
    return commitments.filter(c =>
      c.jobOrderCode.toLowerCase().includes(lowercasedFilter) ||
      c.articleCode.toLowerCase().includes(lowercasedFilter)
    );
  }, [commitments, searchTerm]);

  const onSubmit = async (values: CommitmentFormValues) => {
    if (!user) return;
    setIsPending(true);
    const result = await saveManualCommitment(values, user.uid);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
      router.refresh();
      setIsFormOpen(false);
      form.reset();
    }
    setIsPending(false);
  };

  const handleDelete = async (commitmentId: string) => {
    setIsPending(true);
    const result = await deleteManualCommitment(commitmentId);
    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      router.refresh();
    }
    setIsPending(false);
  };

  const handleDeclare = async (values: DeclarationFormValues, lotSelections: LotSelectionPayload[]) => {
    if (!user || !declarationTarget) return;
    setIsPending(true);

    const result = await declareCommitmentFulfillment(
      declarationTarget.id,
      values.goodPieces,
      values.scrapPieces,
      lotSelections,
      user.uid
    );

    toast({
      title: result.success ? "Successo" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
      duration: 9000
    });

    if (result.success) {
      router.refresh();
      setDeclarationTarget(null);
    }
    setIsPending(false);
  };

  const handleRevertFulfillment = async (commitmentId: string) => {
    if (!user) return;
    setIsPending(true);
    const result = await revertManualCommitmentFulfillment(commitmentId, user.uid);
    toast({
      title: result.success ? "Operazione Annullata" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      router.refresh();
    }
    setIsPending(false);
  };

  const handleDownloadTemplate = () => {
    const templateData = [
      {
        "Commessa": "COMM-001/24",
        "Codice Articolo": "ART-001",
        "Quantita": 100,
        "Data Consegna": "25/07/2024",
      },
    ];
    const ws = XLSX.utils.json_to_sheet(templateData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Impegni Manuali");
    XLSX.writeFile(wb, "template_impegni_manuali.xlsx");
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file || !user) return;

    setIsImporting(true);
    toast({ title: 'Importazione in corso...', description: 'Lettura e validazione del file Excel in corso.' });

    try {
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data, { type: 'array', cellDates: true });
      const sheetName = workbook.SheetNames[0];
      const worksheet = workbook.Sheets[sheetName];
      const json: any[] = XLSX.utils.sheet_to_json(worksheet);

      if (json.length === 0) {
        toast({ variant: 'destructive', title: "File Vuoto", description: "Il file non contiene righe da importare." });
        setIsImporting(false);
        return;
      }

      const result = await importManualCommitments(json, user.uid);

      toast({
        title: result.success ? "Importazione Completata" : "Errore di Importazione",
        description: result.message,
        variant: result.success ? "default" : "destructive",
        duration: 9000,
      });

      if (result.success) {
        router.refresh();
      }

    } catch (error) {
      toast({
        variant: "destructive",
        title: "Errore Importazione",
        description: error instanceof Error ? error.message : "Impossibile leggere o processare il file.",
      });
    } finally {
      setIsImporting(false);
      if (fileInputRef.current) fileInputRef.current.value = "";
    }
  };

  return (
    <>
      <Card>
        <CardHeader>
          <div className="flex justify-between items-center">
            <CardTitle className="font-headline">Impegni Manuali su Commessa</CardTitle>
            <div className="flex items-center gap-2">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Cerca..."
                  className="pl-9"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>
              <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".xlsx, .xls" className="hidden" />
              <Button onClick={handleDownloadTemplate} variant="outline" size="sm">
                <Download className="mr-2 h-4 w-4" />
                Scarica Template
              </Button>
              <Button onClick={handleImportClick} variant="outline" size="sm" disabled={isImporting}>
                {isImporting ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : <Upload className="mr-2 h-4 w-4" />}
                Carica da File
              </Button>
              <Dialog open={isFormOpen} onOpenChange={setIsFormOpen}>
                <DialogTrigger asChild>
                  <Button><PlusCircle className="mr-2 h-4 w-4" /> Aggiungi Impegno</Button>
                </DialogTrigger>
                <DialogContent className="sm:max-w-xl">
                  <DialogHeader>
                    <DialogTitle>Aggiungi Nuovo Impegno Manuale</DialogTitle>
                    <DialogDescription>
                      Inserisci i dettagli per creare un nuovo impegno di materiale su una commessa.
                    </DialogDescription>
                  </DialogHeader>
                  <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4">
                      <FormField control={form.control} name="jobOrderCode" render={({ field }) => (<FormItem> <FormLabel>Commessa di Riferimento</FormLabel> <FormControl><Input placeholder="Es. Comm-1234/24" {...field} /></FormControl> <FormMessage /> </FormItem>)} />
                      <FormField control={form.control} name="articleCode" render={({ field }) => (
                        <FormItem className="flex flex-col">
                          <FormLabel>Codice Articolo</FormLabel>
                          <Popover open={isArticlePopoverOpen} onOpenChange={setIsArticlePopoverOpen}><PopoverTrigger asChild><FormControl>
                            <Button variant="outline" role="combobox" className={cn("w-full justify-between", !field.value && "text-muted-foreground")}>
                              {field.value ? initialArticles.find(a => a.code === field.value)?.code : "Seleziona articolo..."}
                              <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                            </Button>
                          </FormControl></PopoverTrigger>
                            <PopoverContent className="w-[--radix-popover-trigger-width] p-0"><Command>
                              <CommandInput placeholder="Cerca articolo..." />
                              <CommandEmpty>Nessun articolo trovato.</CommandEmpty>
                              <CommandGroup>
                                {initialArticles.map((article) => (
                                  <CommandItem value={article.code} key={article.id} onSelect={() => { form.setValue("articleCode", article.code); setIsArticlePopoverOpen(false); }}>
                                    <Check className={cn("mr-2 h-4 w-4", article.code === field.value ? "opacity-100" : "opacity-0")} />
                                    {article.code}
                                  </CommandItem>
                                ))}
                              </CommandGroup>
                            </Command></PopoverContent></Popover>
                          <FormMessage />
                        </FormItem>
                      )} />
                      <FormField control={form.control} name="quantity" render={({ field }) => (<FormItem> <FormLabel>Quantit├á da Produrre</FormLabel> <FormControl><Input type="number" {...field} /></FormControl> <FormMessage /> </FormItem>)} />
                      <FormField
                        control={form.control}
                        name="deliveryDate"
                        render={({ field }) => (
                          <FormItem className="flex flex-col">
                            <FormLabel>Data Consegna Prevista</FormLabel>
                            <Popover>
                              <div className="relative flex items-center">
                                <FormControl>
                                  <Input
                                    placeholder="gg/mm/aaaa"
                                    value={dateString}
                                    onChange={(e) => {
                                      let value = e.target.value.replace(/\D/g, "");
                                      if (value.length > 8) {
                                        value = value.slice(0, 8);
                                      }
                                      let formattedValue = value;
                                      if (value.length > 4) {
                                        formattedValue = `${value.slice(0, 2)}/${value.slice(2, 4)}/${value.slice(4, 8)}`;
                                      } else if (value.length > 2) {
                                        formattedValue = `${value.slice(0, 2)}/${value.slice(2)}`;
                                      }
                                      setDateString(formattedValue);

                                      if (formattedValue.length === 10) {
                                        const parsedDate = parse(formattedValue, 'dd/MM/yyyy', new Date());
                                        if (isValid(parsedDate)) {
                                          field.onChange(parsedDate);
                                        } else {
                                          field.onChange(undefined);
                                        }
                                      } else {
                                        field.onChange(undefined);
                                      }
                                    }}
                                  />
                                </FormControl>
                                <PopoverTrigger asChild>
                                  <Button
                                    variant={"ghost"}
                                    className="absolute right-1 h-8 w-8 p-0"
                                    aria-label="Apri calendario"
                                  >
                                    <CalendarIcon className="h-4 w-4 text-muted-foreground" />
                                  </Button>
                                </PopoverTrigger>
                              </div>
                              <PopoverContent className="w-auto p-0" align="start">
                                <Calendar
                                  mode="single"
                                  selected={field.value}
                                  onSelect={(date) => {
                                    field.onChange(date);
                                    if (date && isValid(date)) {
                                      setDateString(format(date, 'dd/MM/yyyy'));
                                    } else {
                                      setDateString('');
                                    }
                                  }}
                                  initialFocus
                                />
                              </PopoverContent>
                            </Popover>
                            <FormMessage />
                          </FormItem>
                        )}
                      />
                      <DialogFooter>
                        <DialogClose asChild><Button type="button" variant="outline" disabled={isPending}>Annulla</Button></DialogClose>
                        <Button type="submit" disabled={isPending}>{isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin" /> : null} Salva Impegno</Button>
                      </DialogFooter>
                    </form>
                  </Form>
                </DialogContent>
              </Dialog>
            </div>
          </div>
        </CardHeader>
        <CardContent>
          <div className="overflow-x-auto">
            <Table>
              <TableHeader><TableRow>
                <TableHead>Stato</TableHead><TableHead>Commessa</TableHead><TableHead>Articolo</TableHead>
                <TableHead>Quantit├á</TableHead><TableHead>Data Consegna</TableHead>
                <TableHead className="text-right">Azioni</TableHead>
              </TableRow></TableHeader>
              <TableBody>
                {filteredCommitments.length > 0 ? filteredCommitments.map(c => (
                  <TableRow key={c.id}>
                    <TableCell>
                      <Badge variant={c.status === 'fulfilled' ? 'default' : 'secondary'}>
                        {c.status === 'fulfilled' ? <CheckCircle2 className="mr-2 h-4 w-4" /> : <Circle className="mr-2 h-4 w-4" />}
                        {c.status === 'fulfilled' ? 'Evaso' : 'In Attesa'}
                      </Badge>
                    </TableCell>
                    <TableCell>{c.jobOrderCode}</TableCell><TableCell>{c.articleCode}</TableCell>
                    <TableCell>{c.quantity}</TableCell>
                    <TableCell>{format(parseISO(c.deliveryDate as any), "dd/MM/yyyy")}</TableCell>
                    <TableCell className="text-right space-x-2">
                      {c.status === 'pending' ? (
                        <Button size="sm" disabled={isPending} onClick={() => setDeclarationTarget(c)}>
                          <FileCheck2 className="mr-2 h-4 w-4" />Dichiara
                        </Button>
                      ) : (
                        <AlertDialog>
                          <AlertDialogTrigger asChild><Button size="sm" variant="secondary" disabled={isPending}><Undo2 className="mr-2 h-4 w-4" />Annulla Evasione</Button></AlertDialogTrigger>
                          <AlertDialogContent>
                            <AlertDialogHeader><AlertDialogTitle>Annullare l'evasione?</AlertDialogTitle><AlertDialogDescription>Questa azione riporter├á l'impegno allo stato 'In Attesa' e ripristiner├á lo stock dei materiali precedentemente scaricati (inclusi gli scarti). Sei sicuro?</AlertDialogDescription></AlertDialogHeader>
                            <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => handleRevertFulfillment(c.id)}>S├¼, Annulla Evasione</AlertDialogAction></AlertDialogFooter>
                          </AlertDialogContent>
                        </AlertDialog>
                      )}
                      <AlertDialog>
                        <AlertDialogTrigger asChild><Button size="icon" variant="destructive" disabled={isPending}><Trash2 className="h-4 w-4" /></Button></AlertDialogTrigger>
                        <AlertDialogContent>
                          <AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle><AlertDialogDescription>Questa azione eliminer├á l'impegno. Se ├¿ stato evaso, lo stock NON verr├á ripristinato. Per ripristinare lo stock, usa "Annulla Evasione".</AlertDialogDescription></AlertDialogHeader>
                          <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => handleDelete(c.id)}>S├¼, Elimina</AlertDialogAction></AlertDialogFooter>
                        </AlertDialogContent>
                      </AlertDialog>
                    </TableCell>
                  </TableRow>
                )) : (
                  <TableRow><TableCell colSpan={6} className="h-24 text-center">{searchTerm ? "Nessun impegno trovato per la ricerca." : "Nessun impegno manuale trovato."}</TableCell></TableRow>
                )}
              </TableBody>
            </Table>
          </div>
        </CardContent>
      </Card>

      {declarationTarget && (
        <DeclarationDialog
          isOpen={!!declarationTarget}
          onOpenChange={(open) => !open && setDeclarationTarget(null)}
          commitment={declarationTarget}
          article={initialArticles.find(a => a.code === declarationTarget.articleCode)}
          onDeclare={handleDeclare}
        />
      )}
    </>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import Link from 'next/link';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardHeader, CardTitle, CardDescription, CardContent } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { getOperatorDetailReport } from '@/app/admin/reports/actions';
import { ArrowLeft, User, Clock, Calendar as CalendarIcon, Loader2, Briefcase } from 'lucide-react';
import { format } from 'date-fns';
import { it } from 'date-fns/locale';
import { useSearchParams } from 'next/navigation';

type OperatorDetailReport = Awaited<ReturnType<typeof getOperatorDetailReport>>;

export default function OperatorReportDetailPage({ params }: { params: { operatorId: string } }) {
  const searchParams = useSearchParams();
  const dateFromParams = searchParams.get('date');

  const [report, setReport] = useState<OperatorDetailReport | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [selectedDate, setSelectedDate] = useState<Date | undefined>(
    dateFromParams ? new Date(dateFromParams) : new Date()
  );

  useEffect(() => {
    const fetchReport = async () => {
      if (!selectedDate) return;
      setIsLoading(true);
      const dateStringForServer = selectedDate.toISOString();
      const newReport = await getOperatorDetailReport(params.operatorId, dateStringForServer);
      setReport(newReport);
      setIsLoading(false);
    };

    if (params.operatorId && selectedDate) {
      fetchReport();
    }
  }, [params.operatorId, selectedDate]);
  
  if (isLoading || !report) {
    return (
      <AdminAuthGuard>
        <AppShell>
            <div className="flex items-center justify-center h-64">
              <Loader2 className="h-8 w-8 animate-spin text-primary" />
            </div>
        </AppShell>
      </AdminAuthGuard>
    )
  }

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-6 max-w-2xl mx-auto">
          <Button asChild variant="outline" className="w-fit">
            <Link href="/admin/reports">
              <ArrowLeft className="mr-2 h-4 w-4" />
              Torna ai Report
            </Link>
          </Button>

          <header>
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <User className="h-8 w-8 text-primary" />
              Dettaglio Operatore: {report.operator.nome}
            </h1>
            <p className="text-muted-foreground">Report dettagliato delle attivit├á e delle ore di lavoro.</p>
          </header>

          <Card>
            <CardHeader className="flex-row items-center justify-between">
              <CardTitle>Riepilogo Ore</CardTitle>
              <Popover>
                <PopoverTrigger asChild>
                    <Button variant={"outline"}>
                        <CalendarIcon className="mr-2 h-4 w-4" />
                        {selectedDate ? format(selectedDate, "PPP", { locale: it }) : <span>Scegli una data</span>}
                    </Button>
                </PopoverTrigger>
                <PopoverContent className="w-auto p-0">
                    <Calendar mode="single" selected={selectedDate} onSelect={setSelectedDate} initialFocus />
                </PopoverContent>
              </Popover>
            </CardHeader>
            <CardContent className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 text-sm">
                <div className="flex items-center gap-3 p-4 bg-background rounded-lg border">
                    <Clock className="h-6 w-6 text-primary"/>
                    <div>
                        <p className="text-muted-foreground">Ore Lavorate (Giorno)</p>
                        <p className="font-semibold text-lg">{report.timeToday}</p>
                         <p className="text-xs text-muted-foreground">{report.dateLabels.today}</p>
                    </div>
                </div>
                 <div className="flex items-center gap-3 p-4 bg-background rounded-lg border">
                    <CalendarIcon className="h-6 w-6 text-primary"/>
                    <div>
                        <p className="text-muted-foreground">Ore Lavorate (Settimana)</p>
                        <p className="font-semibold text-lg">{report.timeWeek}</p>
                        <p className="text-xs text-muted-foreground">{report.dateLabels.week}</p>
                    </div>
                </div>
                 <div className="flex items-center gap-3 p-4 bg-background rounded-lg border">
                    <CalendarIcon className="h-6 w-6 text-primary"/>
                    <div>
                        <p className="text-muted-foreground">Ore Lavorate (Mese)</p>
                        <p className="font-semibold text-lg">{report.timeMonth}</p>
                        <p className="text-xs text-muted-foreground">{report.dateLabels.month}</p>
                    </div>
                </div>
            </CardContent>
          </Card>
          
          <Card>
             <CardHeader>
                <CardTitle className="flex items-center gap-3">
                    <Briefcase className="h-6 w-6 text-primary"/>
                    Commesse Lavorate nel Giorno Selezionato
                </CardTitle>
                <CardDescription>Elenco delle commesse a cui l'operatore ha contribuito nel giorno {report.dateLabels.today}.</CardDescription>
            </CardHeader>
            <CardContent>
                 <div className="overflow-x-auto">
                    <Table>
                      <TableHeader>
                        <TableRow>
                          <TableHead>Commessa (PF)</TableHead>
                          <TableHead>Articolo</TableHead>
                          <TableHead>Cliente</TableHead>
                          <TableHead>Fase Lavorata</TableHead>
                          <TableHead>Tempo Impiegato</TableHead>
                        </TableRow>
                      </TableHeader>
                      <TableBody>
                        {report.jobsWorkedOn.length > 0 ? report.jobsWorkedOn.flatMap((job: any) => 
                          (job.phases as any[]).map((phase: any, index: number) => (
                            <TableRow key={`${job.id}-${phase.date}-${phase.name}`}>
                              {index === 0 ? (
                                <>
                                  <TableCell rowSpan={job.phases.length} className="font-medium align-top border-b">{job.id}</TableCell>
                                  <TableCell rowSpan={job.phases.length} className="align-top border-b">{job.details}</TableCell>
                                  <TableCell rowSpan={job.phases.length} className="align-top border-b">{job.cliente}</TableCell>
                                </>
                              ) : null}
                              <TableCell>{phase.name}</TableCell>
                              <TableCell>{phase.time}</TableCell>
                            </TableRow>
                          ))
                        ) : (
                             <TableRow>
                                <TableCell colSpan={5} className="text-center h-24">Nessuna attivit├á registrata per questo operatore nel giorno selezionato.</TableCell>
                            </TableRow>
                        )}
                      </TableBody>
                    </Table>
                  </div>
            </CardContent>
          </Card>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import AdminAuthGuard from '@/components/AdminAuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { useToast } from '@/hooks/use-toast';
import { Timer, Save, Loader2, AlertCircle } from 'lucide-react';
import { getTimeTrackingSettings, saveTimeTrackingSettings, type TimeTrackingSettings } from './actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { Skeleton } from '@/components/ui/skeleton';
import { Form, FormControl, FormDescription, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Input } from '@/components/ui/input';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';

const settingsSchema = z.object({
  minimumPhaseDurationSeconds: z.coerce
    .number()
    .int("Il valore deve essere un numero intero.")
    .min(0, "Il valore non pu├▓ essere negativo.")
    .max(300, "Il valore non pu├▓ superare 300 secondi."),
});

type SettingsFormValues = z.infer<typeof settingsSchema>;

export default function TimeTrackingSettingsPage() {
  const [settings, setSettings] = useState<TimeTrackingSettings>({ 
      minimumPhaseDurationSeconds: 10,
  });
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const { user } = useAuth();
  const { toast } = useToast();

  const form = useForm<SettingsFormValues>({
    resolver: zodResolver(settingsSchema),
    defaultValues: {
      minimumPhaseDurationSeconds: 10,
    },
  });

  const fetchSettings = async () => {
    setIsLoading(true);
    try {
        const data = await getTimeTrackingSettings();
        setSettings(data);
        form.reset(data);
    } catch (error) {
        toast({
            variant: "destructive",
            title: "Errore",
            description: "Impossibile caricare le impostazioni.",
        });
    }
    setIsLoading(false);
  };

  useEffect(() => {
    fetchSettings();
     // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const onSubmit = async (values: SettingsFormValues) => {
    if (!user) return;
    setIsSaving(true);
    const result = await saveTimeTrackingSettings(values, user.uid);
    toast({
      title: result.success ? "Impostazioni Salvate" : "Errore",
      description: result.message,
      variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
      await fetchSettings();
    }
    setIsSaving(false);
  };

  return (
    <AdminAuthGuard>
      <AppShell>
        <div className="space-y-8 max-w-4xl mx-auto">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <Timer className="h-8 w-8 text-primary" />
              Gestione Rilevazione Tempi
            </h1>
            <p className="text-muted-foreground">
              Definisci le regole per la validazione e l'analisi dei tempi di produzione.
            </p>
          </header>

          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)}>
              <Card>
                <CardHeader>
                  <CardTitle>Regole di Validazione Automatica</CardTitle>
                  <CardDescription>
                    Imposta i parametri usati per determinare se i dati cronometrati sono affidabili.
                  </CardDescription>
                </CardHeader>
                <CardContent className="space-y-4">
                  {isLoading ? (
                    <div className="space-y-2">
                      <Skeleton className="h-10 w-full" />
                    </div>
                  ) : (
                    <FormField
                      control={form.control}
                      name="minimumPhaseDurationSeconds"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Soglia minima di durata fase (in secondi)</FormLabel>
                          <FormControl>
                            <Input type="number" placeholder="Es. 10" {...field} />
                          </FormControl>
                          <FormDescription>
                            Una fase completata in meno di questo tempo render├á il calcolo totale per quella commessa "non affidabile".
                          </FormDescription>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  )}
                </CardContent>
                <CardFooter>
                  <Button type="submit" disabled={isSaving || isLoading}>
                    {isSaving ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Save className="mr-2 h-4 w-4" />}
                    Salva Impostazioni
                  </Button>
                </CardFooter>
              </Card>
            </form>
          </Form>
          
           <Alert variant="default" className="border-blue-500/50 bg-blue-500/10 text-blue-900 dark:text-blue-200">
             <AlertCircle className="h-5 w-5 text-blue-600 dark:text-blue-400" />
            <AlertTitle className="text-blue-800 dark:text-blue-300">Come funziona l'affidabilit├á?</AlertTitle>
            <AlertDescription>
             Un tempo di produzione per un articolo ├¿ considerato "affidabile" solo se tutte le sue fasi sono state completate organicamente, senza forzature manuali e rispettando la soglia di tempo minima impostata sopra.
            </AlertDescription>
          </Alert>
        </div>
      </AppShell>
    </AdminAuthGuard>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import * as z from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { useToast } from '@/hooks/use-toast';
import * as XLSX from 'xlsx';

import { type WorkPhaseTemplate, RawMaterialType, type Department } from '@/lib/mock-data';
import { getWorkPhaseTemplates, saveWorkPhaseTemplate, deleteWorkPhaseTemplate, getDepartments, deleteSelectedWorkPhaseTemplates, updatePhasesOrder } from './actions';

import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Checkbox } from '@/components/ui/checkbox';
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle, AlertDialogTrigger } from "@/components/ui/alert-dialog";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage, FormDescription } from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Switch } from '@/components/ui/switch';
import { Workflow, PlusCircle, Edit, Trash2, Download, Save, Loader2, ListOrdered, Check, X, Timer } from 'lucide-react';
import AppShell from '@/components/layout/AppShell';
import AdminAuthGuard from '@/components/AdminAuthGuard';

const materialTypes: RawMaterialType[] = ['BOB', 'TUBI', 'PF3V0', 'GUAINA'];

// Base schema without department enum
const workPhaseSchema = z.object({
  id: z.string().optional(),
  name: z.string().min(3, 'Il nome deve avere almeno 3 caratteri.'),
  description: z.string().min(10, 'La descrizione deve avere almeno 10 caratteri.'),
  departmentCodes: z.array(z.string()).min(1, 'Selezionare almeno un reparto.'),
  type: z.enum(['preparation', 'production', 'quality', 'packaging'], { required_error: 'Specificare il tipo di fase' }),
  tracksTime: z.boolean().default(true).optional(),
  requiresMaterialScan: z.boolean().default(false).optional(),
  requiresMaterialSearch: z.boolean().default(false).optional(),
  requiresMaterialAssociation: z.boolean().default(false).optional(),
  allowedMaterialTypes: z.array(z.string()).optional(),
  isIndependent: z.boolean().default(false).optional(),
});


type WorkPhaseFormValues = z.infer<typeof workPhaseSchema>;

export default function WorkPhaseManagementClientPage() {
  const [phases, setPhases] = useState<WorkPhaseTemplate[]>([]);
  const [departments, setDepartments] = useState<Department[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isDialogOpen, setIsDialogOpen] = useState(false);
  const [editingPhase, setEditingPhase] = useState<WorkPhaseTemplate | null>(null);
  const [selectedRows, setSelectedRows] = useState<string[]>([]);
  const [isOrderChanged, setIsOrderChanged] = useState(false);
  const [isPending, setIsPending] = useState(false);
  const { toast } = useToast();

  const form = useForm<WorkPhaseFormValues>({
    resolver: zodResolver(workPhaseSchema),
    defaultValues: { id: undefined, name: "", description: "", departmentCodes: [], type: 'production', tracksTime: true, requiresMaterialScan: false, requiresMaterialSearch: false, requiresMaterialAssociation: false, allowedMaterialTypes: [], isIndependent: false },
  });
  
  const fetchAllData = async () => {
    setIsLoading(true);
    const [phasesData, departmentsData] = await Promise.all([
      getWorkPhaseTemplates(),
      getDepartments(),
    ]);
    setPhases(phasesData);
    setDepartments(departmentsData);
    setIsOrderChanged(false); // Reset change tracker
    setIsLoading(false);
  };

  useEffect(() => {
    fetchAllData();
  }, []);

  const handleOpenDialog = (phase: WorkPhaseTemplate | null = null) => {
    setEditingPhase(phase);
    if (phase) {
      form.reset({
        id: phase.id,
        name: phase.name,
        description: phase.description,
        departmentCodes: phase.departmentCodes || [],
        type: phase.type || 'production',
        tracksTime: phase.tracksTime !== false,
        requiresMaterialScan: phase.requiresMaterialScan || false,
        requiresMaterialSearch: phase.requiresMaterialSearch || false,
        requiresMaterialAssociation: phase.requiresMaterialAssociation || false,
        allowedMaterialTypes: phase.allowedMaterialTypes || [],
        isIndependent: phase.isIndependent || false,
      });
    } else {
      form.reset({ id: undefined, name: "", description: "", departmentCodes: [], type: 'production', tracksTime: true, requiresMaterialScan: false, requiresMaterialSearch: false, requiresMaterialAssociation: false, allowedMaterialTypes: [], isIndependent: false });
    }
    setIsDialogOpen(true);
  };

  const handleCloseDialog = () => {
    setIsDialogOpen(false);
    setEditingPhase(null);
    form.reset();
  }

  const onSubmit = async (values: WorkPhaseFormValues) => {
    const formData = new FormData();
    if (values.id) formData.append('id', values.id);
    formData.append('name', values.name);
    formData.append('description', values.description);
    values.departmentCodes.forEach(code => formData.append('departmentCodes', code));
    formData.append('type', values.type);
    if (values.tracksTime) formData.append('tracksTime', 'on');
    if (values.type !== 'quality') {
        if (values.requiresMaterialScan) formData.append('requiresMaterialScan', 'on');
        if (values.requiresMaterialSearch) formData.append('requiresMaterialSearch', 'on');
        if (values.requiresMaterialAssociation) formData.append('requiresMaterialAssociation', 'on');
    }
    if (values.isIndependent) formData.append('isIndependent', 'on');
    (values.allowedMaterialTypes || []).forEach(type => formData.append('allowedMaterialTypes', type));


    setIsPending(true);
    const result = await saveWorkPhaseTemplate(formData);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
        await fetchAllData();
        handleCloseDialog();
    }
    setIsPending(false);
  };

  const handleDelete = async (id: string) => {
    setIsPending(true);
    const result = await deleteWorkPhaseTemplate(id);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) await fetchAllData();
    setIsPending(false);
  };

  const handleDeleteSelected = async () => {
    setIsPending(true);
    const result = await deleteSelectedWorkPhaseTemplates(selectedRows);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
        await fetchAllData();
        setSelectedRows([]);
    }
    setIsPending(false);
  };

  const handleSequenceChange = (id: string, newSequence: string) => {
    const sequenceValue = parseInt(newSequence, 10);
    if (!isNaN(sequenceValue)) {
        setPhases(currentPhases =>
            currentPhases.map(phase =>
                phase.id === id ? { ...phase, sequence: sequenceValue } : phase
            )
        );
        setIsOrderChanged(true);
    }
  };

  const handleSaveOrder = async () => {
    setIsPending(true);
    const phasesToUpdate = phases.map(({ id, sequence }) => ({ id, sequence }));
    const result = await updatePhasesOrder(phasesToUpdate);
    toast({
        title: result.success ? "Successo" : "Errore",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });
    if (result.success) {
        await fetchAllData();
    }
    setIsPending(false);
  };
  
  const handleSelectAll = (checked: boolean | 'indeterminate') => {
    setSelectedRows(checked === true ? phases.map(p => p.id) : []);
  };
  
  const handleSelectRow = (id: string) => {
    setSelectedRows(prev => prev.includes(id) ? prev.filter(rowId => rowId !== id) : [...prev, id]);
  };

  const handleExport = () => {
    const departmentNameMap = new Map(departments.map(d => [d.code, d.name]));
    const dataToExport = phases.map(phase => ({
        'Sequenza': phase.sequence,
        'Tipo': phase.type === 'production' ? 'Produzione' : 'Preparazione',
        'Traccia Tempo': phase.tracksTime ? 'S├¼' : 'No',
        'Richiede Scansione Materiale': phase.requiresMaterialScan ? 'S├¼' : 'No',
        'Richiede Associazione Materiale': phase.requiresMaterialAssociation ? 'S├¼' : 'No',
        'Nome Fase': phase.name,
        'Descrizione': phase.description,
        'Reparti': (phase.departmentCodes || []).map(code => departmentNameMap.get(code) || code).join(', '),
    }));
    const ws = XLSX.utils.json_to_sheet(dataToExport);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Fasi Lavorazione");
    XLSX.writeFile(wb, "fasi_lavorazione.xlsx");
  };
  
  const renderLoading = () => (
      <TableRow>
          <TableCell colSpan={11} className="h-24 text-center">
              <div className="flex items-center justify-center gap-2 text-muted-foreground">
                  <Loader2 className="h-5 w-5 animate-spin" />
                  <span>Caricamento fasi...</span>
              </div>
          </TableCell>
      </TableRow>
  );

  return (
    <AdminAuthGuard>
        <AppShell>
            <div className="space-y-6">
            <div className="flex justify-between items-center">
                <header>
                    <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
                    <Workflow className="h-8 w-8 text-primary" />
                    Gestione Fasi di Lavorazione
                    </h1>
                    <p className="text-muted-foreground mt-2">
                    Definisci le fasi "modello" e la loro sequenza per i cicli di lavorazione delle commesse.
                    </p>
                </header>
                <div className="flex items-center gap-2">
                    <Button onClick={handleExport} variant="outline" disabled={isLoading || phases.length === 0}>
                        <Download className="mr-2 h-4 w-4" />
                        Esporta
                    </Button>
                    <Button onClick={() => handleOpenDialog()} disabled={isLoading}>
                    <PlusCircle className="mr-2 h-4 w-4" />
                    Aggiungi
                    </Button>
                </div>
            </div>

            <Card>
                <CardHeader>
                <div className="flex justify-between items-center gap-4 flex-wrap">
                    <div>
                    <CardTitle>Elenco Fasi Standard</CardTitle>
                    <CardDescription>Queste sono le fasi disponibili per la configurazione dei cicli di lavoro.</CardDescription>
                    </div>
                    <div className="flex items-center gap-2">
                    {isOrderChanged && (
                        <Button onClick={handleSaveOrder} disabled={isPending}>
                        {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <ListOrdered className="mr-2 h-4 w-4" />}
                        Salva Ordine
                        </Button>
                    )}
                    {selectedRows.length > 0 && (
                        <AlertDialog>
                            <AlertDialogTrigger asChild>
                            <Button variant="destructive" disabled={isPending}>
                                {isPending ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Trash2 className="mr-2 h-4 w-4" />}
                                Elimina ({selectedRows.length})
                            </Button>
                            </AlertDialogTrigger>
                            <AlertDialogContent>
                                <AlertDialogHeader>
                                    <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                    <AlertDialogDescription>
                                        Questa azione non pu├▓ essere annullata. Verranno eliminate definitivamente {selectedRows.length} fasi.
                                    </AlertDialogDescription>
                                </AlertDialogHeader>
                                <AlertDialogFooter>
                                    <AlertDialogCancel>Annulla</AlertDialogCancel>
                                    <AlertDialogAction onClick={handleDeleteSelected}>Continua</AlertDialogAction>
                                </AlertDialogFooter>
                            </AlertDialogContent>
                        </AlertDialog>
                    )}
                    </div>
                </div>
                </CardHeader>
                <CardContent>
                <div className="overflow-x-auto">
                    <Table>
                    <TableHeader>
                        <TableRow>
                        <TableHead padding="checkbox">
                            <Checkbox
                                checked={!isLoading && selectedRows.length > 0 && selectedRows.length === phases.length ? true : !isLoading && selectedRows.length > 0 ? 'indeterminate' : false}
                                onCheckedChange={handleSelectAll}
                                aria-label="Seleziona tutte"
                                disabled={isLoading}
                            />
                        </TableHead>
                        <TableHead className="w-[100px]">Sequenza</TableHead>
                        <TableHead>Nome Fase</TableHead>
                        <TableHead>Tipo</TableHead>
                        <TableHead>Traccia Tempo</TableHead>
                        <TableHead>Scansione Mat.</TableHead>
                        <TableHead>Associa Mat.</TableHead>
                        <TableHead>Ricerca Mat.</TableHead>
                        <TableHead>Descrizione</TableHead>
                        <TableHead>Reparti</TableHead>
                        <TableHead className="text-right">Azioni</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {isLoading ? renderLoading() : phases.length > 0 ? (
                        phases.map((phase) => (
                            <TableRow key={phase.id} data-state={selectedRows.includes(phase.id) && "selected"}>
                            <TableCell padding="checkbox">
                                <Checkbox
                                    checked={selectedRows.includes(phase.id)}
                                    onCheckedChange={() => handleSelectRow(phase.id)}
                                    aria-label={`Seleziona la fase ${phase.name}`}
                                />
                            </TableCell>
                            <TableCell>
                                <Input
                                    type="number"
                                    value={phase.sequence}
                                    onChange={(e) => handleSequenceChange(phase.id, e.target.value)}
                                    className="w-16 h-8 text-center"
                                />
                            </TableCell>
                            <TableCell className="font-medium">{phase.name}</TableCell>
                            <TableCell>
                                <Badge variant={phase.type === 'production' ? 'default' : phase.type === 'quality' ? 'secondary' : phase.type === 'packaging' ? 'outline' : 'destructive'}>
                                {phase.type === 'production' ? 'Produzione' : phase.type === 'quality' ? 'Qualit├á' : phase.type === 'packaging' ? 'Packaging' : 'Preparazione'}
                                </Badge>
                            </TableCell>
                            <TableCell className="text-center">
                                {phase.tracksTime !== false ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                             <TableCell className="text-center">
                                {phase.requiresMaterialScan ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                            <TableCell className="text-center">
                                {phase.requiresMaterialAssociation ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                             <TableCell className="text-center">
                                {phase.requiresMaterialSearch ? <Check className="h-5 w-5 text-green-500" /> : <X className="h-5 w-5 text-muted-foreground" />}
                            </TableCell>
                            <TableCell className="max-w-sm truncate">{phase.description}</TableCell>
                            <TableCell>
                                <div className="flex flex-wrap gap-1">
                                    {(phase.departmentCodes || []).map(code => (
                                        <Badge key={code} variant="secondary">{(departments.find(d => d.code === code))?.name || code}</Badge>
                                    ))}
                                </div>
                            </TableCell>
                            <TableCell className="text-right space-x-2">
                                <Button variant="outline" size="icon" onClick={() => handleOpenDialog(phase)}>
                                <Edit className="h-4 w-4" />
                                </Button>
                                <AlertDialog>
                                <AlertDialogTrigger asChild>
                                    <Button variant="destructive" size="icon">
                                    <Trash2 className="h-4 w-4" />
                                    </Button>
                                </AlertDialogTrigger>
                                <AlertDialogContent>
                                    <AlertDialogHeader>
                                    <AlertDialogTitle>Sei sicuro?</AlertDialogTitle>
                                    <AlertDialogDescription>
                                        Questa azione non pu├▓ essere annullata. La fase verr├á eliminata.
                                    </AlertDialogDescription>
                                    </AlertDialogHeader>
                                    <AlertDialogFooter>
                                    <AlertDialogCancel>Annulla</AlertDialogCancel>
                                    <AlertDialogAction onClick={() => handleDelete(phase.id)}>Continua</AlertDialogAction>
                                    </AlertDialogFooter>
                                </AlertDialogContent>
                                </AlertDialog>
                            </TableCell>
                            </TableRow>
                        ))
                        ) : (
                        <TableRow>
                            <TableCell colSpan={11} className="text-center h-24">Nessuna fase definita.</TableCell>
                        </TableRow>
                        )}
                    </TableBody>
                    </Table>
                </div>
                </CardContent>
            </Card>
            

            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
            <DialogContent className="sm:max-w-lg" onInteractOutside={(e) => {if (!isPending) e.preventDefault();}} onEscapeKeyDown={(e) => {if (!isPending) handleCloseDialog();}}>
                <DialogHeader>
                <DialogTitle>{editingPhase ? "Modifica Fase" : "Aggiungi Nuova Fase"}</DialogTitle>
                <DialogDescription>
                    {editingPhase ? "Modifica i dettagli della fase." : "Compila i campi per aggiungere una nuova fase standard."}
                </DialogDescription>
                </DialogHeader>
                <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 py-4 max-h-[70vh] overflow-y-auto pr-4">
                    <FormField control={form.control} name="name" render={({ field }) => (
                    <FormItem>
                        <FormLabel>Nome Fase</FormLabel>
                        <FormControl><Input placeholder="Es. Saldatura Manuale" {...field} /></FormControl>
                        <FormMessage />
                    </FormItem>
                    )} />
                    <FormField control={form.control} name="description" render={({ field }) => (
                    <FormItem>
                        <FormLabel>Descrizione</FormLabel>
                        <FormControl><Textarea placeholder="Descrivi lo scopo e le attivit├á principali di questa fase." {...field} /></FormControl>
                        <FormMessage />
                    </FormItem>
                    )} />
                    <FormField
                        control={form.control}
                        name="type"
                        render={({ field }) => (
                        <FormItem className="space-y-3">
                            <FormLabel>Tipo di Fase</FormLabel>
                            <FormControl>
                            <RadioGroup
                                onValueChange={(value) => {
                                  field.onChange(value);
                                  const isTimeTracked = value === 'preparation' || value === 'production';
                                  form.setValue('tracksTime', isTimeTracked);
                                }}
                                defaultValue={field.value}
                                className="flex flex-col space-y-1"
                            >
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="preparation" /></FormControl>
                                    <FormLabel className="font-normal">Preparazione</FormLabel>
                                </FormItem>
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="production" /></FormControl>
                                    <FormLabel className="font-normal">Produzione</FormLabel>
                                </FormItem>
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="quality" /></FormControl>
                                    <FormLabel className="font-normal">Controllo Qualit├á</FormLabel>
                                </FormItem>
                                <FormItem className="flex items-center space-x-3 space-y-0">
                                    <FormControl><RadioGroupItem value="packaging" /></FormControl>
                                    <FormLabel className="font-normal">Packaging</FormLabel>
                                </FormItem>
                            </RadioGroup>
                            </FormControl>
                            <FormMessage />
                        </FormItem>
                        )}
                    />
                    <FormField
                      control={form.control}
                      name="tracksTime"
                      render={({ field }) => (
                      <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                          <div className="space-y-0.5">
                          <FormLabel className="text-base flex items-center gap-2">
                              <Timer className="h-4 w-4" />
                              Abilita Conteggio Tempo
                          </FormLabel>
                          <FormDescription>
                              Se attivo, il tempo speso in questa fase verr├á conteggiato.
                          </FormDescription>
                          </div>
                          <FormControl>
                          <Switch
                              checked={field.value}
                              onCheckedChange={field.onChange}
                          />
                          </FormControl>
                      </FormItem>
                      )}
                    />
                     <FormField
                      control={form.control}
                      name="isIndependent"
                      render={({ field }) => (
                      <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                          <div className="space-y-0.5">
                          <FormLabel className="text-base">
                              Lavorazione Indipendente
                          </FormLabel>
