}

"use client";

import React, { useState, useEffect, useRef, useCallback } from 'react';
import Image from 'next/image';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';

import { login } from '@/lib/auth';
import { useAuth } from '@/components/auth/AuthProvider';
import { useCameraStream } from '@/hooks/use-camera-stream';

import { useToast } from '@/hooks/use-toast';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from '@/components/ui/form';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { QrCode, Lock, LogIn, User, Loader2, KeyRound, AlertTriangle, Clock, ScanLine, Download, PackagePlus, Camera, TestTube } from 'lucide-react';


// Add type for the install prompt event
interface BeforeInstallPromptEvent extends Event {
    readonly platforms: Array<string>;
    readonly userChoice: Promise<{
        outcome: 'accepted' | 'dismissed';
        platform: string;
    }>;
    prompt(): Promise<void>;
}


const manualLoginSchema = z.object({
  username: z.string().min(1, { message: "Il nome utente ├¿ obbligatorio." }),
  password: z.string().min(1, { message: "La password ├¿ obbligatoria." }),
});

type LoginStep = 'initial' | 'camera' | 'logging_in' | 'manual_login';

export default function LoginForm() {
    const [step, setStep] = useState<LoginStep>('initial');
    const [isScanning, setIsScanning] = useState(false);
    const videoRef = useRef<HTMLVideoElement>(null);
    const { hasPermission: hasCameraPermission } = useCameraStream(step === 'camera', videoRef);

    const { toast } = useToast();
    const { user, operator, loading: authLoading } = useAuth();

    const manualForm = useForm<z.infer<typeof manualLoginSchema>>({
        resolver: zodResolver(manualLoginSchema),
        defaultValues: { username: "", password: "" },
    });

    const performLogin = useCallback(async (username: string, password_used: string) => {
        setStep('logging_in');
        try {
            await login(username, password_used);
            // On success, the AuthProvider's onAuthStateChanged listener will handle the redirect.
        } catch (error) {
            localStorage.removeItem('login_redirect_path');
            const errorMessage = error instanceof Error ? error.message : "Credenziali non valide o utente non trovato.";
            toast({
                title: "Accesso Fallito",
                description: errorMessage,
                variant: "destructive",
            });
            setStep('manual_login');
        }
    }, [toast]);
    
    const handleQrLoginClick = (targetPath: string | null) => {
      if (targetPath) {
        localStorage.setItem('login_redirect_path', targetPath);
      } else {
        localStorage.removeItem('login_redirect_path');
      }
      setStep('camera');
    };
    
    const triggerScan = async () => {
        if (typeof window === 'undefined' || !('BarcodeDetector' in window)) {
          toast({ variant: 'destructive', title: 'Funzionalit├á non Supportata', description: 'Il tuo browser non supporta la scansione dei codici a barre.' });
          return;
        }

        if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
            toast({ variant: 'destructive', title: 'Fotocamera non Pronta', description: 'Attendere che il video sia attivo.' });
            return;
        }

        setIsScanning(true);
        toast({ title: 'Scansione...', description: 'Alla ricerca di un codice nel frame.' });
        
        try {
            const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code'] });
            const barcodes = await barcodeDetector.detect(videoRef.current);

            if (barcodes.length > 0) {
                setStep('initial'); // Stop the camera
                const [username, password] = barcodes[0].rawValue.split('@');
                if (username && password) {
                     performLogin(username, password);
                } else {
                    toast({
                        variant: 'destructive',
                        title: 'Dati QR non Validi',
                        description: 'Il formato del QR code per il login non ├¿ corretto.',
                    });
                    setStep('initial');
                }
            } else {
                toast({ variant: 'destructive', title: 'Nessun Codice Trovato', description: 'Assicurati che il codice sia ben visibile e riprova.' });
            }
        } catch (error) {
            toast({ variant: 'destructive', title: 'Errore di Scansione', description: 'Impossibile processare l\'immagine.' });
        } finally {
            setIsScanning(false);
        }
    };


    const onManualSubmit = (values: z.infer<typeof manualLoginSchema>) => {
        localStorage.removeItem('login_redirect_path');
        performLogin(values.username, values.password);
    };

    const renderStep = () => {
        switch (step) {
            case 'initial':
                return (
                    <>
                        <CardHeader className="items-center text-center">
                            <Image src="/logo.png" alt="PFXcan Logo" width={150} height={100} unoptimized={true} priority={true} />
                            <CardTitle className="text-2xl font-headline">Benvenuto in PFXcan</CardTitle>
                             <CardDescription className="text-muted-foreground">Seleziona una modalit├á di accesso.</CardDescription>
                        </CardHeader>
                        <CardContent className="flex flex-col gap-4">
                            <Button onClick={() => handleQrLoginClick(null)} size="lg" className="h-14 text-lg">
                               <QrCode className="mr-3 h-6 w-6" />
                                Accesso Standard (QR)
                            </Button>

                             <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                                <Button variant="secondary" className="h-20 flex-col gap-1 text-secondary-foreground opacity-50 cursor-not-allowed" disabled>
                                    <Clock className="h-6 w-6" />
                                    Timbratura
                                </Button>
                                <Button onClick={() => handleQrLoginClick('/scan-job')} className="h-20 flex-col gap-1 bg-green-600 text-white hover:bg-green-700">
                                    <ScanLine className="h-6 w-6" />
                                    Produzione
                                </Button>
                                 <Button onClick={() => handleQrLoginClick('/material-loading')} className="h-20 flex-col gap-1 bg-amber-500 text-white hover:bg-amber-600">
                                    <PackagePlus className="h-6 w-6" />
                                    Carico Merce
                                </Button>
                            </div>
                            
                            <div className="relative flex py-2 items-center">
                                <div className="flex-grow border-t border-muted-foreground/20"></div>
                                <span className="flex-shrink mx-4 text-xs text-muted-foreground">OPPURE</span>
                                <div className="flex-grow border-t border-muted-foreground/20"></div>
                            </div>

                            <Button onClick={() => setStep('manual_login')} variant="outline">
                                <KeyRound className="mr-2 h-4 w-4" />
                                Accedi con Password
                            </Button>
                        </CardContent>
                    </>
                );
            case 'camera':
                return (
                    <div>
                         <CardHeader>
                            <CardTitle className="text-center font-headline">Scansione QR Code</CardTitle>
                            <CardDescription className="text-center">Inquadra il QR code e premi il pulsante per scansionare.</CardDescription>
                        </CardHeader>
                        <CardContent className="relative grid place-items-center aspect-square bg-black rounded-lg overflow-hidden">
                             <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
                             <div className="absolute inset-0 grid place-items-center pointer-events-none">
                                <div className="w-2/3 h-2/3 relative">
                                    <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                                    <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                                    <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                                    <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                                    <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                                </div>
                             </div>
                             {hasCameraPermission === false && (
                                <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                                    <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                                    <p className="text-destructive-foreground font-semibold">Accesso alla fotocamera negato</p>
                                    <p className="text-sm text-muted-foreground mt-2">Controlla i permessi del browser per continuare.</p>
                                </div>
                            )}
                        </CardContent>
                        <CardFooter className="pt-6 flex flex-col gap-2">
                             <Button onClick={triggerScan} disabled={isScanning || !hasCameraPermission} className="w-full h-14">
                                {isScanning ? <Loader2 className="h-6 w-6 animate-spin" /> : <Camera className="h-6 w-6" />}
                                <span className="ml-2 text-lg">{isScanning ? 'Scansionando...' : 'Scansiona'}</span>
                             </Button>
                            <Button variant="outline" className="w-full" onClick={() => setStep('initial')}>Annulla</Button>
                        </CardFooter>
                    </div>
                );
            case 'manual_login':
                 return (
                     <div>
                        <Form {...manualForm}>
                            <form onSubmit={manualForm.handleSubmit(onManualSubmit)}>
                                 <CardHeader className="items-center text-center">
                                    <Image src="/logo.png" alt="PFXcan Logo" width={120} height={80} unoptimized={true} />
                                    <CardTitle>Accesso Manuale</CardTitle>
                                    <CardDescription className="text-muted-foreground">Inserisci le tue credenziali.</CardDescription>
                                 </CardHeader>
                                <CardContent className="space-y-6">
                                    <FormField control={manualForm.control} name="username" render={({ field }) => ( <FormItem> <FormLabel className="flex items-center"><User className="mr-2 h-5 w-5" />Nome Utente</FormLabel> <FormControl><Input placeholder="Es. Daniel" {...field} /></FormControl> <FormMessage /> </FormItem> )} />
                                    <FormField control={manualForm.control} name="password" render={({ field }) => ( <FormItem> <FormLabel className="flex items-center"><Lock className="mr-2 h-5 w-5" />Password</FormLabel> <FormControl><Input type="password" placeholder="ÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇóÔÇó" {...field} /></FormControl> <FormMessage /> </FormItem> )} />
                                </CardContent>
                                <CardFooter className="flex-col gap-4">
                                    <Button type="submit" className="w-full" disabled={authLoading}>
                                        {authLoading ? <Loader2 className="mr-2 h-5 w-5 animate-spin" /> : <LogIn className="mr-2 h-5 w-5" />}
                                        {authLoading ? "Verifica..." : "Accedi"}
                                    </Button>
                                    <Button variant="link" size="sm" onClick={() => setStep('initial')}>Torna all'accesso rapido</Button>
                                </CardFooter>
                            </form>
                        </Form>
                     </div>
                 );
            case 'logging_in':
                return (
                     <div className="flex flex-col items-center justify-center p-12 gap-4 aspect-video">
                        <Loader2 className="h-16 w-16 animate-spin text-primary" />
                        <p className="text-xl font-semibold">Accesso in corso...</p>
                    </div>
                );
        }
    };

    return (
        <>
            <Card className="w-full max-w-md shadow-xl border-border/50 bg-card overflow-hidden">
                {renderStep()}
            </Card>
        </>
    );
}

"use client";

import React, { useState, useRef, useCallback, useEffect, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useRouter } from 'next/navigation';
import { format } from 'date-fns';

import AuthGuard from '@/components/AuthGuard';
import AppShell from '@/components/layout/AppShell';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from '@/components/ui/switch';
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { getRawMaterialByCode } from '@/app/scan-job/actions';
import { getPackagingItems, registerInventoryBatch } from './actions';
import type { RawMaterial, Packaging } from '@/lib/mock-data';
import { Warehouse, QrCode, Loader2, Camera, AlertTriangle, ArrowLeft, Weight, Archive, Send, Check } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Alert, AlertTitle, AlertDescription } from '@/components/ui/alert';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { useCameraStream } from '@/hooks/use-camera-stream';
import { formatDisplayStock } from '@/lib/utils';

const inventoryFormSchema = z.object({
  materialId: z.string().min(1),
  lotto: z.string().optional(),
  inputQuantity: z.coerce.number().positive("La quantit├á deve essere un numero positivo."),
  packagingId: z.string().optional(),
  operatorId: z.string(),
  operatorName: z.string(),
  inputUnit: z.enum(['n', 'mt', 'kg']),
});
type InventoryFormValues = z.infer<typeof inventoryFormSchema>;

type Step = 'scan_material' | 'form' | 'saving' | 'success';

export default function InventoryPage() {
  const { operator, loading: authLoading } = useAuth();
  const router = useRouter();
  const { toast } = useToast();

  const [step, setStep] = useState<Step>('scan_material');
  const [scannedMaterial, setScannedMaterial] = useState<RawMaterial | null>(null);
  const [packagingItems, setPackagingItems] = useState<Packaging[]>([]);
  const [isCapturing, setIsCapturing] = useState(false);
  const [isLottoScanOpen, setIsLottoScanOpen] = useState(false);
  
  const videoRef = useRef<HTMLVideoElement>(null);
  const { hasPermission: hasCameraPermission } = useCameraStream(step === 'scan_material' || isLottoScanOpen, videoRef);

  const form = useForm<InventoryFormValues>({
    resolver: zodResolver(inventoryFormSchema),
  });
  
  const selectedPackagingId = form.watch('packagingId');
  const enteredQuantity = form.watch('inputQuantity') || 0;
  const inputUnit = form.watch('inputUnit');
  
  const calculatedNetWeight = useMemo(() => {
    if (!scannedMaterial || !enteredQuantity) return 0;
    
    const selectedTara = packagingItems.find(p => p.id === selectedPackagingId)?.weightKg || 0;

    if (inputUnit === 'kg') {
        return (enteredQuantity || 0) - selectedTara;
    } 

    const factor = (inputUnit === 'mt')
        ? (scannedMaterial.rapportoKgMt || scannedMaterial.conversionFactor || 0)
        : (scannedMaterial.conversionFactor || 0);

    return (enteredQuantity * factor);
  }, [scannedMaterial, enteredQuantity, inputUnit, packagingItems, selectedPackagingId]);

  useEffect(() => {
    if (!authLoading && operator && !operator.canAccessInventory) {
      toast({
        variant: "destructive",
        title: "Accesso Negato",
        description: "Non hai i permessi per accedere alla pagina Inventario."
      });
      router.replace('/dashboard');
    }
  }, [operator, authLoading, router, toast]);

  useEffect(() => {
    getPackagingItems().then(setPackagingItems);
  }, []);
  
  const handleMaterialScanned = useCallback(async (code: string) => {
      setIsLottoScanOpen(false);
      const result = await getRawMaterialByCode(code.trim());
      if ('error' in result) {
          toast({ variant: 'destructive', title: result.title || "Errore", description: result.error });
          setStep('scan_material');
      } else {
          setScannedMaterial(result);
           if (operator) {
              form.reset({
                materialId: result.id,
                lotto: '',
                packagingId: 'none',
                operatorId: operator.id,
                operatorName: operator.nome,
                inputUnit: result.unitOfMeasure,
                inputQuantity: undefined,
              });
            }
          setStep('form');
      }
  }, [toast, form, operator]);

  const handleLottoScanned = useCallback((code: string) => {
    form.setValue('lotto', code.trim());
    setIsLottoScanOpen(false);
    toast({ title: "Lotto Scansionato", description: `Lotto "${code.trim()}" inserito.` });
  }, [form, toast]);

  const triggerScan = async (onScan: (code: string) => void) => {
    if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
        toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
        return;
    }
    if (!('BarcodeDetector' in window)) {
        toast({ variant: 'destructive', title: 'Funzionalit├á non supportata.' });
        return;
    }

    setIsCapturing(true);
    try {
        const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13', 'code_39'] });
        const barcodes = await barcodeDetector.detect(videoRef.current);
        if (barcodes.length > 0) {
            onScan(barcodes[0].rawValue);
        } else {
            toast({ variant: 'destructive', title: 'Nessun codice trovato.' });
        }
    } catch (error) {
        toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
    } finally {
        setIsCapturing(false);
    }
  };

  const onSubmit = async (values: InventoryFormValues) => {
    if (!operator || !scannedMaterial) {
      toast({ variant: "destructive", title: "Errore", description: "Dati operatore o materiale mancanti." });
      return;
    }
    
    setStep('saving');
    const formData = new FormData();
    Object.entries(values).forEach(([key, value]) => {
      if (value !== undefined) formData.append(key, String(value));
    });
    
    const result = await registerInventoryBatch(formData);

    toast({
        title: result.success ? "Inventario Registrato" : "Operazione Fallita",
        description: result.message,
        variant: result.success ? "default" : "destructive",
    });

    if (result.success) {
      setStep('success');
    } else {
      setStep('form');
    }
  };
  
  const resetFlow = () => {
    setScannedMaterial(null);
    form.reset();
    setStep('scan_material');
  };

  if (authLoading || !operator) {
    return <AppShell><div className="flex items-center justify-center h-full"><Loader2 className="h-12 w-12 animate-spin text-primary" /></div></AppShell>;
  }

  return (
    <AuthGuard>
      <AppShell>
        <div className="space-y-8 max-w-2xl mx-auto">
          <header className="space-y-2">
            <h1 className="text-3xl font-bold font-headline tracking-tight flex items-center gap-3">
              <Warehouse className="h-8 w-8 text-primary" />
              Registrazione Inventario
            </h1>
            <p className="text-muted-foreground">
              Scansiona un materiale e registra il peso per aggiornare l'inventario.
            </p>
          </header>

          <Card>
             {step === 'scan_material' && (
                <>
                 <CardHeader>
                    <CardTitle>1. Scansione Materia Prima</CardTitle>
                    <CardDescription>Inquadra il codice a barre o QR code del materiale da inventariare.</CardDescription>
                </CardHeader>
                <CardContent>
                    <div className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden">
                       <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
                        {hasCameraPermission === false && (
                             <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                               <Alert variant="destructive">
                                  <AlertTriangle className="h-4 w-4" />
                                  <AlertTitle>Accesso Fotocamera Negato</AlertTitle>
                                  <AlertDescription>Controlla i permessi del browser per continuare.</AlertDescription>
                                </Alert>
                            </div>
                        )}
                        {hasCameraPermission && (
                             <div className="absolute inset-0 grid place-items-center pointer-events-none">
                                <div className="w-5/6 h-2/5 relative">
                                    <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                                    <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                                    <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                                    <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                                    <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                                </div>
                            </div>
                        )}
                    </div>
                </CardContent>
                <CardFooter>
                    <Button onClick={() => triggerScan(handleMaterialScanned)} disabled={isCapturing || !hasCameraPermission} className="w-full h-12">
                        {isCapturing ? <Loader2 className="h-5 w-5 animate-spin"/> : <Camera className="h-5 w-5" />}
                        <span className="ml-2">{isCapturing ? 'Scansionando...' : 'Scansiona Materiale'}</span>
                    </Button>
                </CardFooter>
                </>
            )}

            {step === 'form' && scannedMaterial && (
                <Form {...form}>
                    <form onSubmit={form.handleSubmit(onSubmit)}>
                        <CardHeader>
                            <CardTitle>2. Inserimento Dati</CardTitle>
                            <CardDescription>
                                Inserisci i dati per il materiale: <span className="font-bold text-primary">{scannedMaterial.code}</span>
                            </CardDescription>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            <FormField
                              control={form.control}
                              name="lotto"
                              render={({ field }) => (
                                <FormItem>
                                  <FormLabel>Numero Lotto (Opzionale)</FormLabel>
                                  <div className="flex items-center gap-2">
                                    <FormControl>
                                      <Input placeholder="Scansiona o digita il lotto" {...field} />
                                    </FormControl>
                                    <Button type="button" variant="outline" size="icon" onClick={() => setIsLottoScanOpen(true)}>
                                      <QrCode className="h-5 w-5" />
                                    </Button>
                                  </div>
                                  <FormMessage />
                                </FormItem>
                              )}
                            />
                            
                             <FormField
                                control={form.control}
                                name="inputUnit"
                                render={({ field }) => (
                                <FormItem>
                                     <div className="flex items-center space-x-2 rounded-lg border p-3 justify-center">
                                        <Label htmlFor="unit-switch">{scannedMaterial.unitOfMeasure.toUpperCase()}</Label>
                                        <Switch
                                        id="unit-switch"
                                        checked={field.value === 'kg'}
                                        onCheckedChange={(checked) => field.onChange(checked ? 'kg' : scannedMaterial.unitOfMeasure)}
                                        />
                                        <Label htmlFor="unit-switch">KG</Label>
                                    </div>
                                </FormItem>
                                )}
                            />

                             <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                <FormField control={form.control} name="inputQuantity" render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="flex items-center"><Weight className="mr-2 h-4 w-4"/>
                                          {inputUnit === 'kg' ? 'Quantit├á Lorda (KG)' : `Quantit├á Inserita (${scannedMaterial.unitOfMeasure.toUpperCase()})`}
                                        </FormLabel>
                                        <FormControl><Input type="number" step="any" placeholder="Es. 15.5" {...field} value={field.value ?? ''} /></FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )} />
                                <FormField control={form.control} name="packagingId" render={({ field }) => (
                                    <FormItem>
                                        <FormLabel className="flex items-center"><Archive className="mr-2 h-4 w-4" />Tara (Imballo)</FormLabel>
                                        <Select onValueChange={field.onChange} defaultValue={field.value}>
                                            <FormControl><SelectTrigger><SelectValue placeholder="Nessuna" /></SelectTrigger></FormControl>
                                            <SelectContent>
                                                <SelectItem value="none">Nessuna Tara (0.00 kg)</SelectItem>
                                                {packagingItems.map(item => (
                                                    <SelectItem key={item.id} value={item.id}>{item.name} ({item.weightKg.toFixed(3)} kg)</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                        <FormMessage />
                                    </FormItem>
                                )} />
                            </div>

                            <div className="p-4 rounded-lg border bg-muted">
                                <Label className="text-muted-foreground">Peso Netto Calcolato (KG)</Label>
                                <p className="text-2xl font-bold text-primary">{calculatedNetWeight >= 0 ? formatDisplayStock(calculatedNetWeight, 'kg') : '---'}</p>
                            </div>

                        </CardContent>
                        <CardFooter className="justify-between">
                            <Button type="button" variant="outline" onClick={resetFlow}><ArrowLeft className="mr-2 h-4 w-4" />Annulla</Button>
                            <Button type="submit" disabled={calculatedNetWeight < 0 || form.formState.isSubmitting}>
                                {form.formState.isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Send className="mr-2 h-4 w-4" />}
                                Salva Registrazione
                            </Button>
                        </CardFooter>
                    </form>
                </Form>
            )}

            {step === 'saving' && (
                <CardContent className="flex flex-col items-center justify-center py-16 gap-4">
                    <Loader2 className="h-16 w-16 animate-spin text-primary" />
                    <p className="text-muted-foreground">Salvataggio in corso...</p>
                </CardContent>
            )}

            {step === 'success' && (
                <CardContent className="flex flex-col items-center justify-center py-16 gap-4">
                    <div className="bg-green-100 p-4 rounded-full"><Check className="h-12 w-12 text-green-600" /></div>
                    <CardTitle>Inventario Registrato</CardTitle>
                    <CardDescription>La registrazione ├¿ stata inviata per l'approvazione.</CardDescription>
                    <Button onClick={resetFlow} className="mt-4">Registra Altro</Button>
                </CardContent>
            )}
          </Card>
        </div>

        <Dialog open={isLottoScanOpen} onOpenChange={setIsLottoScanOpen}>
          <DialogContent>
            <DialogHeader><DialogTitle>Scansiona Codice Lotto</DialogTitle></DialogHeader>
            <div className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden my-4">
              <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
              <div className="absolute inset-0 grid place-items-center pointer-events-none">
                <div className="w-5/6 h-2/5 relative">
                  <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                  <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                  <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                  <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                  <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                </div>
              </div>
            </div>
            <DialogFooter>
              <Button onClick={() => triggerScan(handleLottoScanned)} disabled={isCapturing || !hasCameraPermission} className="w-full">
                {isCapturing ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Camera className="mr-2 h-4 w-4" />}
                {isCapturing ? 'Scansionando...' : 'Scansiona Lotto'}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </AppShell>
    </AuthGuard>
  );
}

"use client";

import React, { useState, useRef, useCallback, useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useRouter } from 'next/navigation';
import { format } from 'date-fns';

import AuthGuard from '@/components/AuthGuard';
import AppShell from '@/components/layout/AppShell';
import OperatorNavMenu from '@/components/operator/OperatorNavMenu';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle, CardFooter } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Switch } from '@/components/ui/switch';
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { addBatchToRawMaterial, reportNonConformity, getPackagingItems, getOpenPurchaseOrdersForMaterial } from './actions';
import { getRawMaterialByCode } from '@/app/scan-job/actions';
import type { RawMaterial, Packaging, PurchaseOrder } from '@/lib/mock-data';
import { QrCode, AlertTriangle, Boxes, Send, Loader2, Package, Barcode, PlayCircle, Weight, Check, X, ArrowLeft, ThumbsDown, ThumbsUp, MessageSquare, Camera, Archive, TestTube, Truck, ClipboardList, Calendar } from 'lucide-react';
import { useCameraStream } from '@/hooks/use-camera-stream';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';

const batchFormSchema = z.object({
  materialId: z.string().min(1),
  lotto: z.string().min(1, "Il lotto ├¿ obbligatorio."),
  date: z.string().refine((val) => !isNaN(Date.parse(val)), { message: "Data non valida"}),
  ddt: z.string().optional(),
  quantity: z.coerce.number().positive("La quantit├á deve essere un numero positivo."),
  packagingId: z.string().optional(),
  unit: z.enum(['n', 'kg', 'mt']),
  purchaseOrderId: z.string().optional(),
});
type BatchFormValues = z.infer<typeof batchFormSchema>;

const ncReportFormSchema = z.object({
    quantity: z.coerce.number().positive("La quantit├á ├¿ obbligatoria."),
    reason: z.string(),
    notes: z.string().optional(),
});
type NcReportFormValues = z.infer<typeof ncReportFormSchema>;

type Step = 'scan_material' | 'select_order' | 'validate' | 'scan_lotto' | 'enter_quantity' | 'saving' | 'success';

// New isolated component for scanning UI
const ScanUI = ({ title, onScan, onCancel }: { title: string, onScan: (code: string) => void, onCancel: () => void }) => {
    const videoRef = useRef<HTMLVideoElement>(null);
    const { hasPermission } = useCameraStream(true, videoRef);
    const [isCapturing, setIsCapturing] = useState(false);
    const { toast } = useToast();

    const triggerScan = async () => {
        if (!videoRef.current || videoRef.current.readyState < 2) {
            toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
            return;
        }
        if (!('BarcodeDetector' in window)) {
            toast({ variant: 'destructive', title: 'Funzionalit├á non supportata.' });
            return;
        }

        setIsCapturing(true);
        try {
            const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13'] });
            const barcodes = await barcodeDetector.detect(videoRef.current);
            if (barcodes.length > 0) {
                onScan(barcodes[0].rawValue);
            } else {
                toast({ variant: 'destructive', title: 'Nessun codice trovato.' });
            }
        } catch (error) {
            toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
        } finally {
            setIsCapturing(false);
        }
    };

    return (
        <div className="text-center space-y-4">
            <h3 className="text-xl font-semibold">{title}</h3>
            <div className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden">
                <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
                {hasPermission === false ? (
                     <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                        <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                        <p className="text-destructive-foreground font-semibold">Accesso alla fotocamera negato</p>
                        <p className="text-sm text-muted-foreground mt-2">Controlla i permessi del browser per continuare.</p>
                    </div>
                ) : (
                    <div className="absolute inset-0 grid place-items-center pointer-events-none">
                        <div className="w-5/6 h-2/5 relative">
                            <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-primary rounded-tl-lg"></div>
                            <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-primary rounded-tr-lg"></div>
                            <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-primary rounded-bl-lg"></div>
                            <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-primary rounded-br-lg"></div>
                            <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                        </div>
                    </div>
                )}
            </div>
            <div className="flex flex-col gap-2">
                <Button onClick={triggerScan} disabled={isCapturing || !hasPermission} className="w-full h-12">
                    {isCapturing ? <Loader2 className="h-5 w-5 animate-spin" /> : <Camera className="h-5 w-5" />}
                    <span className="ml-2">{isCapturing ? 'Scansionando...' : 'Scansiona Ora'}</span>
                </Button>
                <Button variant="outline" onClick={onCancel}>Annulla</Button>
            </div>
        </div>
    );
};


export default function MaterialLoadingPage() {
    const { operator, loading: authLoading } = useAuth();
    const router = useRouter();
    const { toast } = useToast();

    const [step, setStep] = useState<Step>('scan_material');
    const [scannedMaterial, setScannedMaterial] = useState<RawMaterial | null>(null);
    const [openOrders, setOpenOrders] = useState<PurchaseOrder[]>([]);
    const [selectedOrder, setSelectedOrder] = useState<PurchaseOrder | null>(null);
    const [scannedLotto, setScannedLotto] = useState<string | null>(null);
    const [packagingItems, setPackagingItems] = useState<Packaging[]>([]);
    const [showNCReport, setShowNCReport] = useState(false);
    const [inputUnit, setInputUnit] = useState<'primary' | 'kg'>('primary');
    const [isLoadingOrders, setIsLoadingOrders] = useState(false);
    
    useEffect(() => {
        if (!authLoading && operator) {
            const allowedAccessReparti = ['MAG', 'Collaudo'];
            const hasAccess = operator.role === 'supervisor' || 
                              (Array.isArray(operator.reparto) 
                                ? operator.reparto.some(r => allowedAccessReparti.includes(r)) 
                                : allowedAccessReparti.includes(operator.reparto));
            
            if (!hasAccess) {
                toast({ variant: 'destructive', title: 'Accesso Negato', description: 'Non hai i permessi per accedere a questa pagina.' });
                router.replace('/dashboard');
            }
        }
    }, [operator, authLoading, router, toast]);
    
    useEffect(() => {
        if (scannedMaterial) {
            setInputUnit('primary'); 
        }
    }, [scannedMaterial]);

    useEffect(() => {
        if (step === 'enter_quantity') {
            getPackagingItems().then(setPackagingItems);
        }
    }, [step]);

    const form = useForm<BatchFormValues>({
        resolver: zodResolver(batchFormSchema),
        defaultValues: { date: format(new Date(), 'yyyy-MM-dd'), ddt: 'CARICO_RAPIDO' },
    });
    
    const ncForm = useForm<NcReportFormValues>();

    const selectedPackagingId = form.watch('packagingId');
    const enteredQuantity = form.watch('quantity');
    
     const calculatedGrossWeight = React.useMemo(() => {
        if (!scannedMaterial || !enteredQuantity) return 0;
        
        const numEnteredQuantity = parseFloat(String(enteredQuantity));
        if (isNaN(numEnteredQuantity)) return 0;

        const selectedTara = packagingItems.find(p => p.id === selectedPackagingId)?.weightKg || 0;
        let netWeightKg = 0;

        if (inputUnit === 'kg') {
            netWeightKg = numEnteredQuantity;
        } else { 
            if (scannedMaterial.conversionFactor && scannedMaterial.conversionFactor > 0) {
                netWeightKg = numEnteredQuantity * scannedMaterial.conversionFactor;
            } else if (scannedMaterial.unitOfMeasure === 'kg') {
                netWeightKg = numEnteredQuantity;
            }
        }

        return netWeightKg + selectedTara;
    }, [scannedMaterial, enteredQuantity, inputUnit, packagingItems, selectedPackagingId]);

    
    const handleMaterialScanned = useCallback(async (code: string) => {
        const result = await getRawMaterialByCode(code.trim());
        if ('error' in result) {
            toast({ variant: 'destructive', title: result.title || "Errore", description: result.error });
        } else {
            setScannedMaterial(result);
            form.setValue('materialId', result.id);
            form.setValue('unit', result.unitOfMeasure);
            setInputUnit('primary');
            
            // Fetch open orders for this material
            setIsLoadingOrders(true);
            setStep('select_order');
            try {
                const orders = await getOpenPurchaseOrdersForMaterial(result.code);
                setOpenOrders(orders);
            } catch (error) {
                console.error("Search error:", error);
                toast({ variant: 'destructive', title: "Errore di Ricerca", description: "Si ├¿ verificato un problema durante la ricerca degli ordini." });
            } finally {
                setIsLoadingOrders(false);
            }
        }
    }, [toast, form]);

    const handleSelectOrder = (order: PurchaseOrder | null) => {
        setSelectedOrder(order);
        if (order) {
            form.setValue('purchaseOrderId', order.id);
            form.setValue('ddt', order.orderNumber);
            // Propose remaining quantity
            const remaining = order.quantity - (order.receivedQuantity || 0);
            form.setValue('quantity', remaining > 0 ? remaining : 0);
        } else {
            form.setValue('purchaseOrderId', undefined);
            form.setValue('quantity', 0);
        }
        setStep('validate');
    };

    const handleLottoScanned = (code: string) => {
        setScannedLotto(code.trim());
        form.setValue('lotto', code.trim());
        setStep('enter_quantity');
    };

    async function onFinalSubmit(values: BatchFormValues) {
        setStep('saving');
        const formData = new FormData();
        Object.entries(values).forEach(([key, value]) => {
          if (value !== undefined) formData.append(key, String(value));
        });

        const finalUnit = inputUnit === 'primary' ? scannedMaterial?.unitOfMeasure : 'kg';
        formData.set('unit', finalUnit || 'n');


        const result = await addBatchToRawMaterial(formData);
        toast({
            title: result.success ? "Carico Registrato" : "Errore",
            description: result.message,
            variant: result.success ? "default" : "destructive",
        });

        if (result.success) {
            setStep('success');
        } else {
            setStep('enter_quantity'); 
        }
    };
    
    const handleNonConformityReport = async (values: NcReportFormValues) => {
        if (!scannedMaterial || !operator) return;

        const result = await reportNonConformity({
            materialId: scannedMaterial.id,
            materialCode: scannedMaterial.code,
            lotto: scannedLotto || 'NC_DA_CONVALIDA',
            quantity: values.quantity,
            reason: values.reason,
            notes: values.notes,
            operatorId: operator.id,
            operatorName: operator.nome,
        });

        if (result.success) {
            toast({
                title: "Segnalazione Inviata",
                description: `La NC ├¿ stata registrata e il materiale ├¿ in attesa di revisione.`,
            });
            resetFlow();
        } else {
             toast({
                variant: "destructive",
                title: "Errore Segnalazione",
                description: result.message,
            });
        }
    };

    const resetFlow = () => {
        setScannedMaterial(null);
        setScannedLotto(null);
        setSelectedOrder(null);
        setOpenOrders([]);
        setShowNCReport(false);
        ncForm.reset();
        form.reset({ date: format(new Date(), 'yyyy-MM-dd'), ddt: 'CARICO_RAPIDO' });
        setStep('scan_material');
    };

    if (authLoading || !operator) {
        return <AppShell><div className="flex items-center justify-center h-full"><Loader2 className="h-12 w-12 animate-spin text-primary" /></div></AppShell>;
    }
    
    const filteredPackagingItems = scannedMaterial
        ? packagingItems.filter(item => item.associatedTypes?.includes(scannedMaterial.type))
        : [];
    
    return (
        <AuthGuard>
            <AppShell>
                <div className="space-y-6 max-w-xl mx-auto">
                    <OperatorNavMenu />
                     <Card>
                        <CardHeader>
                            <CardTitle className="flex items-center gap-3"><Package className="h-7 w-7 text-primary" /> Carico Merce Rapido</CardTitle>
                            <CardDescription>Segui i passaggi per registrare un nuovo lotto di materiale in ingresso.</CardDescription>
                        </CardHeader>
                        
                        <CardContent>
                            <ol className="relative flex items-center justify-between w-full text-sm font-medium text-center text-gray-500 dark:text-gray-400">
                                {['Materiale', 'Ordine', 'Convalida', 'Lotto', 'Q.t├á'].map((title, index) => {
                                    const stepNames: Step[] = ['scan_material', 'select_order', 'validate', 'scan_lotto', 'enter_quantity', 'saving', 'success'];
                                    const stepIndex = stepNames.indexOf(step);
                                    const isCompleted = stepIndex > index || step === 'saving' || step === 'success';
                                    const isActive = stepIndex === index;

                                    return (
                                        <li key={title} className={`flex items-center ${index < 4 ? 'w-full' : ''} ${isCompleted ? 'text-primary dark:text-primary after:border-primary dark:after:border-primary' : ''} after:content-[''] after:w-full after:h-1 after:border-b after:border-gray-200 after:border-1 after:inline-block dark:after:border-gray-700`}>
                                            <span className={`flex items-center justify-center w-8 h-8 sm:w-10 sm:h-10 ${isActive || isCompleted ? 'bg-primary/20' : 'bg-muted'} rounded-full shrink-0`}>
                                                {isCompleted ? <Check className="w-4 h-4 sm:w-5 sm:h-5 text-primary" /> : <span className={`${isActive ? 'text-primary' : 'text-muted-foreground'}`}>{index + 1}</span>}
                                            </span>
                                        </li>
                                    );
                                })}
                            </ol>
                            
                            <div className="mt-8">
                                {step === 'scan_material' && (
                                    <ScanUI title="1. Scansiona il Codice Materiale" onScan={handleMaterialScanned} onCancel={resetFlow} />
                                )}

                                {step === 'select_order' && (
                                    <div className="space-y-4">
                                        <h3 className="text-xl font-semibold text-center">2. Seleziona Ordine Fornitore</h3>
                                        <p className="text-center text-sm text-muted-foreground">Materiale: <span className="font-bold">{scannedMaterial?.code}</span></p>
                                        
                                        {isLoadingOrders ? (
                                            <div className="py-10 text-center"><Loader2 className="h-10 w-10 animate-spin mx-auto text-primary"/></div>
                                        ) : (
                                            <div className="space-y-2">
                                                {openOrders.length > 0 ? (
                                                    openOrders.map(order => {
                                                        const remaining = order.quantity - (order.receivedQuantity || 0);
                                                        return (
                                                            <Button 
                                                                key={order.id} 
                                                                variant="outline" 
                                                                className="w-full h-auto p-4 flex flex-col items-start gap-1 text-left hover:border-primary"
                                                                onClick={() => handleSelectOrder(order)}
                                                            >
                                                                <div className="flex justify-between w-full font-bold">
                                                                    <span>Ordine: {order.orderNumber}</span>
                                                                    <Badge variant="secondary">{format(new Date(order.expectedDeliveryDate), 'dd/MM/yyyy')}</Badge>
                                                                </div>
                                                                <div className="text-sm text-muted-foreground flex justify-between w-full">
                                                                    <span>Fornitore: {order.supplierName || 'N/D'}</span>
                                                                    <span className="text-primary font-semibold">Residuo: {remaining} {order.unitOfMeasure.toUpperCase()}</span>
                                                                </div>
                                                            </Button>
                                                        );
                                                    })
                                                ) : (
                                                    <Alert>
                                                        <AlertTriangle className="h-4 w-4" />
                                                        <AlertTitle>Nessun Ordine Trovato</AlertTitle>
                                                        <AlertDescription>Non ci sono ordini pendenti per questo materiale. Puoi procedere con un carico libero.</AlertDescription>
                                                    </Alert>
                                                )}
                                                <Button variant="ghost" className="w-full mt-4" onClick={() => handleSelectOrder(null)}>
                                                    Procedi senza ordine (Carico Libero)
                                                </Button>
                                            </div>
                                        )}
                                    </div>
                                )}

                                {step === 'validate' && (
                                     <div className="text-center space-y-4">
                                        <h3 className="text-xl font-semibold">3. Convalida / Segnala Merce</h3>
                                        <p className="text-muted-foreground">Il materiale ricevuto ├¿ conforme?</p>
                                        <div className="flex justify-center gap-4 pt-4">
                                            <Button onClick={() => setStep('scan_lotto')} className="h-24 w-32 flex-col gap-2 bg-green-600 hover:bg-green-700 text-lg">
                                                <ThumbsUp className="h-8 w-8" />
                                                OK
                                            </Button>
                                            <Button onClick={() => setShowNCReport(true)} variant="destructive" className="h-24 w-32 flex-col gap-2 text-lg">
                                                <ThumbsDown className="h-8 w-8" />
                                                NC
                                            </Button>
                                        </div>
                                        
                                        {showNCReport && (
                                            <Card className="mt-6 text-left p-4 border-destructive">
                                            <Form {...ncForm}>
                                              <form onSubmit={ncForm.handleSubmit(handleNonConformityReport)} className="space-y-4">
                                                <CardHeader className="p-2">
                                                  <CardTitle className="text-base">Segnala Non Conformit├á</CardTitle>
                                                  <CardDescription>Specifica il problema e la quantit├á.</CardDescription>
                                                </CardHeader>
                                                <CardContent className="p-2 space-y-4">
                                                  <FormField
                                                      control={ncForm.control}
                                                      name="reason"
                                                      render={({ field }) => (
                                                          <FormItem>
                                                              <FormLabel>Motivo della Non Conformit├á</FormLabel>
                                                              <div className="grid grid-cols-1 sm:grid-cols-3 gap-2">
                                                                  <Button type="button" variant={field.value === 'Codifica Errata' ? 'default' : 'outline'} onClick={() => field.onChange('Codifica Errata')}>Codifica Errata</Button>
                                                                  <Button type="button" variant={field.value === 'Dimensioni Errate' ? 'default' : 'outline'} onClick={() => field.onChange('Dimensioni Errate')}>Dimensioni Errate</Button>
                                                                  <Button type="button" variant={field.value === 'Altro' ? 'default' : 'outline'} onClick={() => field.onChange('Altro')}>Altro</Button>
                                                              </div>
                                                              <FormMessage />
                                                          </FormItem>
                                                      )}
                                                  />

                                                  <FormField
                                                      control={ncForm.control}
                                                      name="quantity"
                                                      render={({ field }) => (
                                                          <FormItem>
                                                              <FormLabel>Quantit├á NC ({scannedMaterial?.unitOfMeasure.toUpperCase()})</FormLabel>
                                                              <FormControl><Input type="number" step="any" placeholder="Es. 10.5" {...field} value={field.value ?? ''} /></FormControl>
                                                              <FormMessage />
                                                          </FormItem>
                                                      )}
                                                  />

                                                  <FormField
                                                      control={ncForm.control}
                                                      name="notes"
                                                      render={({ field }) => (
                                                          <FormItem>
                                                              <FormLabel>Note Aggiuntive (Opzionale)</FormLabel>
                                                              <FormControl><Input placeholder="Aggiungi dettagli..." {...field} /></FormControl>
                                                              <FormMessage />
                                                          </FormItem>
                                                      )}
                                                  />
                                                </CardContent>
                                                <CardFooter className="p-2">
                                                  <Button type="submit" className="w-full" variant="destructive" disabled={ncForm.formState.isSubmitting}>
                                                    {ncForm.formState.isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : <Send className="mr-2 h-4 w-4" />}
                                                    Invia Segnalazione
                                                  </Button>
                                                </CardFooter>
                                              </form>
                                            </Form>
                                          </Card>
                                        )}
                                    </div>
                                )}

                                {step === 'scan_lotto' && (
                                    <ScanUI title="4. Scansiona il Codice del Lotto" onScan={handleLottoScanned} onCancel={resetFlow} />
                                )}

                                {step === 'enter_quantity' && scannedMaterial && (
                                    <div>
                                        <h3 className="text-xl font-semibold text-center mb-4">5. Inserisci Quantit├á Ricevuta</h3>
                                         <Form {...form}>
                                            <form onSubmit={form.handleSubmit(onFinalSubmit)} className="space-y-6 text-left">
                                                <div className="p-3 bg-muted rounded-md text-sm space-y-1">
                                                    <p>Materiale: <span className="font-bold">{scannedMaterial?.code}</span></p>
                                                    <p>Lotto: <span className="font-bold">{scannedLotto}</span></p>
                                                    {selectedOrder && (
                                                        <p className="text-primary font-semibold flex items-center gap-2"><Truck className="h-4 w-4"/> Ordine: {selectedOrder.orderNumber}</p>
                                                    )}
                                                </div>
                                                
                                                {scannedMaterial.unitOfMeasure !== 'kg' && (
                                                    <div className="flex items-center space-x-2 rounded-lg border p-3 justify-center">
                                                        <Label htmlFor="unit-switch">{scannedMaterial.unitOfMeasure.toUpperCase()}</Label>
                                                        <Switch
                                                        id="unit-switch"
                                                        checked={inputUnit === 'kg'}
                                                        onCheckedChange={(checked) => setInputUnit(checked ? 'kg' : 'primary')}
                                                        />
                                                        <Label htmlFor="unit-switch">KG</Label>
                                                    </div>
                                                )}

                                                 <FormField control={form.control} name="quantity" render={({ field }) => (
                                                    <FormItem>
                                                        <FormLabel>
                                                            {inputUnit === 'kg' ? 'Quantit├á Netta (KG)' : `Quantit├á Netta (${scannedMaterial?.unitOfMeasure.toUpperCase()})`}
                                                        </FormLabel>
                                                        <FormControl><Input type="number" step="any" placeholder="Es. 500" {...field} value={field.value ?? ''} autoFocus /></FormControl>
                                                        <FormMessage />
                                                        {selectedOrder && inputUnit === 'primary' && (
                                                            <p className="text-xs text-muted-foreground italic">Quantit├á proposta basata sul residuo dell'ordine.</p>
                                                        )}
                                                    </FormItem>
                                                )} />

                                                <FormField
                                                  control={form.control}
                                                  name="packagingId"
                                                  render={({ field }) => (
                                                    <FormItem>
                                                      <FormLabel className="flex items-center"><Archive className="mr-2 h-4 w-4" />Imballo (Tara)</FormLabel>
                                                      <Select onValueChange={field.onChange} defaultValue={field.value}>
                                                        <FormControl><SelectTrigger><SelectValue placeholder="Seleziona un imballo..." /></SelectTrigger></FormControl>
                                                        <SelectContent>
                                                            <SelectItem value="none">Nessuna Tara (0.00 kg)</SelectItem>
                                                            {filteredPackagingItems.map(item => (
                                                                <SelectItem key={item.id} value={item.id}>
                                                                    {item.name} ({item.weightKg} kg)
                                                                </SelectItem>
                                                            ))}
                                                        </SelectContent>
                                                      </Select>
                                                      <FormMessage />
                                                    </FormItem>
                                                  )}
                                                />
                                                <div className="p-4 rounded-lg border bg-muted">
                                                    <Label className="text-muted-foreground">Peso Lordo Calcolato (KG)</Label>
                                                    <p className="text-2xl font-bold text-primary">{calculatedGrossWeight > 0 ? calculatedGrossWeight.toFixed(3) : '---'}</p>
                                                </div>
                                                
                                                <Button type="submit" className="w-full h-12 text-lg">Registra Carico</Button>
                                            </form>
                                        </Form>
                                    </div>
                                )}
                                {step === 'saving' && (
                                    <div className="text-center py-8">
                                        <Loader2 className="h-12 w-12 animate-spin text-primary mx-auto" />
                                        <p className="mt-4 text-muted-foreground">Registrazione in corso...</p>
                                    </div>
                                )}
                                  {step === 'success' && (
                                    <div className="text-center py-8 space-y-4">
                                        <Check className="h-16 w-16 text-green-500 bg-green-500/10 rounded-full p-2 mx-auto" />
                                        <h3 className="text-xl font-semibold">Carico Registrato con Successo!</h3>
                                        <p className="text-sm text-muted-foreground">Lo stock ├¿ stato aggiornato e l'ordine ├¿ stato processato.</p>
                                        <Button onClick={resetFlow} className="w-full h-12 text-lg">Carica un Altro Materiale</Button>
                                    </div>
                                 )}
                            </div>
                        </CardContent>

                        <CardFooter className="flex-col gap-4">
                           {step !== 'success' && step !== 'scan_material' && (
                            <div className="w-full flex justify-between items-center">
                                <Button variant="ghost" onClick={resetFlow}><ArrowLeft className="mr-2 h-4 w-4"/>Ricomincia</Button>
                            </div>
                           )}
                        </CardFooter>
                     </Card>
                </div>
            </AppShell>
        </AuthGuard>
    );
}

"use client";

import React, { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { FileLock, Check, Loader2 } from 'lucide-react';
import { type Operator } from '@/lib/mock-data';
import { useAuth } from '@/components/auth/AuthProvider';
import { useToast } from "@/hooks/use-toast";
import { signPrivacyPolicy, getPrivacyPolicyContent } from './actions';
import { Skeleton } from '@/components/ui/skeleton';

interface PrivacyFormProps {
    operator: Operator;
}

export default function PrivacyForm({ operator }: PrivacyFormProps) {
    const { refetchOperator } = useAuth();
    const [privacyAccepted, setPrivacyAccepted] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [policyContent, setPolicyContent] = useState('');
    const [isLoadingPolicy, setIsLoadingPolicy] = useState(true);
    const { toast } = useToast();
    const router = useRouter();

    const isSigned = !!operator.privacySigned;

    useEffect(() => {
        setPrivacyAccepted(isSigned);
    }, [isSigned]);

    useEffect(() => {
        async function fetchPolicy() {
            try {
                const content = await getPrivacyPolicyContent();
                setPolicyContent(content);
            } catch (error) {
                toast({
                    variant: "destructive",
                    title: "Errore",
                    description: "Impossibile caricare l'informativa sulla privacy.",
                });
            } finally {
                setIsLoadingPolicy(false);
            }
        }
        fetchPolicy();
    }, [toast]);
  
    const handleSaveSignature = async () => {
        if (!operator) {
            toast({
                variant: "destructive",
                title: "Errore",
                description: "Dati operatore non trovati. Impossibile salvare la firma.",
            });
            return;
        }

        setIsSubmitting(true);
        const result = await signPrivacyPolicy(operator.id);

        if (result.success) {
            toast({
                title: "Firma Salvata",
                description: "Grazie per aver accettato. Verrai reindirizzato alla dashboard.",
            });
            await refetchOperator();
            router.push('/dashboard');
        } else {
            toast({
                variant: "destructive",
                title: "Errore",
                description: result.message,
            });
        }
        setIsSubmitting(false);
    };

    return (
        <Card className="shadow-lg">
            <CardHeader>
              <div className="flex items-center space-x-3">
                <FileLock className="h-8 w-8 text-primary" />
                <div>
                  <CardTitle className="text-xl font-headline mb-1">Informativa sulla Privacy e Riservatezza</CardTitle>
                  <CardDescription>
                    {isSigned 
                      ? "Hai gi├á accettato l'informativa." 
                      : "Presa visione obbligatoria per l'utilizzo dell'applicazione."
                    }
                  </CardDescription>
                </div>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="p-4 border rounded-md bg-background/50 text-sm text-muted-foreground space-y-3 prose dark:prose-invert max-w-none">
                {isLoadingPolicy ? (
                    <div className="space-y-2">
                        <Skeleton className="h-6 w-3/4" />
                        <Skeleton className="h-4 w-full" />
                        <Skeleton className="h-4 w-full" />
                        <Skeleton className="h-4 w-5/6" />
                    </div>
                ) : (
                    <div dangerouslySetInnerHTML={{ __html: policyContent }} />
                )}
              </div>
              <div className="flex items-center space-x-2 pt-4">
                 <Checkbox 
                    id="privacy" 
                    checked={privacyAccepted} 
                    onCheckedChange={(checked) => setPrivacyAccepted(checked as boolean)}
                    disabled={isSigned}
                />
                <Label htmlFor="privacy" className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70">
                  Dichiaro di aver letto e compreso l'informativa sulla privacy.
                </Label>
              </div>
            </CardContent>
            <CardFooter>
               {isSigned ? (
                <div className="w-full text-center text-green-500 font-semibold flex items-center justify-center">
                    <Check className="mr-2 h-5 w-5"/>
                    Informativa accettata e firmata.
                </div>
               ) : (
                <Button 
                    className="w-full"
                    onClick={handleSaveSignature}
                    disabled={!privacyAccepted || isSubmitting || isLoadingPolicy}
                >
                    {isSubmitting ? <Loader2 className="mr-2 h-4 w-4 animate-spin"/> : null}
                    Salva Firma e Accetta
                </Button>
               )}
            </CardFooter>
        </Card>
    );
}

"use client";

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import { useToast } from "@/hooks/use-toast";
import { useAuth } from '@/components/auth/AuthProvider';
import { useCameraStream } from '@/hooks/use-camera-stream';

import type { JobOrder, JobPhase, RawMaterial, ActiveMaterialSessionData, RawMaterialType, Packaging, MaterialConsumption } from '@/lib/mock-data';
import { findLastWeightForLotto, logTubiGuainaWithdrawal, getRawMaterialByCode, startMaterialSessionInJob } from './actions';
import { getPackagingItems } from '../inventory/actions';
import { getLotInfoForMaterial, type LotInfo } from '../admin/raw-material-management/actions';

import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from "@/components/ui/dialog";
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Badge } from '@/components/ui/badge';
import { QrCode, Loader2, Weight, Archive, Send, Barcode, Play, Camera, AlertTriangle, Boxes, Info } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Switch } from '@/components/ui/switch';
import { formatDisplayStock } from '@/lib/utils';

const formSchema = z.object({
  material: z.custom<RawMaterial>().nullable(),
  lotto: z.string().optional(),
  ddt: z.string().optional(),
  openingWeightManual: z.coerce.number().min(0, "Il peso non pu├▓ essere negativo.").optional(),
  quantityToWithdraw: z.coerce.number().optional(),
  packagingId: z.string().optional(),
});

type FormValues = z.infer<typeof formSchema>;
type ScanType = 'material' | 'lotto' | null;

interface MaterialAssociationDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  phase: JobPhase;
  job: JobOrder | null;
  onSessionStart: (sessionData: Omit<ActiveMaterialSessionData, 'category'>, type: RawMaterialType) => void;
  onWithdrawalComplete: () => void;
}

export default function MaterialAssociationDialog({
  isOpen,
  onOpenChange,
  phase,
  job,
  onSessionStart,
  onWithdrawalComplete,
}: MaterialAssociationDialogProps) {
  const { toast } = useToast();
  const { operator } = useAuth();
  
  const [isProcessing, setIsProcessing] = useState(false);
  const [scanType, setScanType] = useState<ScanType>(null);
  const [inputUnit, setInputUnit] = useState<'primary' | 'kg'>('primary');
  const [packagingItems, setPackagingItems] = useState<Packaging[]>([]);
  const [lotAvailability, setLotAvailability] = useState<LotInfo | null>(null);

  const videoRef = React.useRef<HTMLVideoElement>(null);
  const { hasPermission } = useCameraStream(!!scanType, videoRef);

  const form = useForm<FormValues>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      material: null,
      lotto: "",
      ddt: "",
      openingWeightManual: undefined,
      quantityToWithdraw: undefined,
      packagingId: 'none'
    },
  });

  const selectedMaterial = form.watch('material');
  const lottoValue = form.watch('lotto');

  useEffect(() => {
    getPackagingItems().then(setPackagingItems);
  }, []);

  useEffect(() => {
    if (selectedMaterial) {
      setInputUnit('primary');
    }
  }, [selectedMaterial]);

  const updateLotInfo = useCallback(async (materialId: string, lotto: string) => {
      const lots = await getLotInfoForMaterial(materialId);
      const matched = lots.find(l => l.lotto === lotto);
      setLotAvailability(matched || null);
  }, []);

  useEffect(() => {
    if (lottoValue && lottoValue.length >= 3 && selectedMaterial) {
        const timer = setTimeout(async () => {
            const lottoData = await findLastWeightForLotto(selectedMaterial.id, lottoValue);
            await updateLotInfo(selectedMaterial.id, lottoValue);
            
            if (lottoData && lottoData.material) {
                form.setValue('openingWeightManual', lottoData.netWeight);
                form.setValue('ddt', 'Storico Lotto');
                form.setValue('packagingId', lottoData.packagingId || 'none');
            }
        }, 800);
        return () => clearTimeout(timer);
    } else {
        setLotAvailability(null);
    }
  }, [lottoValue, selectedMaterial, form, updateLotInfo]);

  const handleMaterialSelect = (material: RawMaterial) => {
    form.setValue('material', material);
  };
  
  const handleScanTrigger = (type: ScanType) => {
    setScanType(type);
  };

  const triggerScan = async () => {
    if (!videoRef.current || videoRef.current.paused || videoRef.current.readyState < 2) {
      toast({ variant: 'destructive', title: 'Fotocamera non pronta.' });
      return;
    }
    if (!('BarcodeDetector' in window)) {
        toast({ variant: 'destructive', title: 'Funzionalit├á non supportata.' });
        return;
    }

    setIsProcessing(true);
    try {
        const barcodeDetector = new (window as any).BarcodeDetector({ formats: ['qr_code', 'code_128', 'ean_13', 'code_39'] });
        const barcodes = await barcodeDetector.detect(videoRef.current);
        if (barcodes.length > 0) {
            await handleScan(barcodes[0].rawValue);
        } else {
            toast({ variant: 'destructive', title: 'Nessun codice trovato.' });
        }
    } catch (error) {
        toast({ variant: 'destructive', title: 'Errore durante la scansione.' });
    } finally {
        setIsProcessing(false);
    }
  };

  const handleScan = useCallback(async (scannedValue: string) => {
    if (scanType === 'material') {
      const materialResult = await getRawMaterialByCode(scannedValue);
      if ('error' in materialResult) {
        toast({ variant: 'destructive', title: materialResult.title, description: materialResult.error });
      } else {
        handleMaterialSelect(materialResult);
      }
    } else if (scanType === 'lotto') {
      const lottoData = await findLastWeightForLotto(selectedMaterial?.id, scannedValue);
      if (lottoData?.material) {
        handleMaterialSelect(lottoData.material);
        form.setValue('lotto', scannedValue);
        form.setValue('openingWeightManual', lottoData.netWeight);
        form.setValue('ddt', 'Storico Lotto');
        form.setValue('packagingId', lottoData.packagingId || 'none');
        await updateLotInfo(lottoData.material.id, scannedValue);
      } else {
        form.setValue('lotto', scannedValue);
        toast({ title: 'Lotto Nuovo', description: 'Nessuno storico trovato. Inserire il peso manualmente.' });
      }
    }
    setScanType(null); 
  }, [scanType, form, toast, selectedMaterial, updateLotInfo]);

  const onAvviaSessione = async () => {
    const values = form.getValues();
    if (!selectedMaterial || !job || !operator) return;

    const openingWeight = values.openingWeightManual;
    if (openingWeight === undefined || openingWeight === null) {
        toast({ variant: 'destructive', title: 'Peso Mancante', description: 'Inserire il peso di apertura.' });
        return;
    }

    setIsProcessing(true);
    const selectedPackaging = packagingItems.find(p => p.id === values.packagingId);

    let associatedJobsForSession: { jobId: string; jobOrderPF: string }[] = [];
    if (job.id.startsWith('group-') && job.jobOrderIds && job.jobOrderPFs) {
        associatedJobsForSession = job.jobOrderIds.map((id, index) => ({
            jobId: id,
            jobOrderPF: job.jobOrderPFs![index]
        }));
    } else {
        associatedJobsForSession = [{ jobId: job.id, jobOrderPF: job.ordinePF }];
    }

    const consumption: MaterialConsumption = {
        materialId: selectedMaterial.id,
        materialCode: selectedMaterial.code,
        grossOpeningWeight: openingWeight + (selectedPackaging?.weightKg || 0),
        netOpeningWeight: openingWeight,
        lottoBobina: values.lotto || '',
        packagingId: values.packagingId || 'none',
        tareWeight: selectedPackaging?.weightKg || 0,
    };

    const registerResult = await startMaterialSessionInJob(job.id, phase.id, consumption);

    if (registerResult.success) {
        onSessionStart({
            materialId: selectedMaterial.id,
            materialCode: selectedMaterial.code,
            grossOpeningWeight: consumption.grossOpeningWeight!,
            netOpeningWeight: consumption.netOpeningWeight!,
            originatorJobId: job.id,
            associatedJobs: associatedJobsForSession,
            packagingId: consumption.packagingId,
            tareWeight: consumption.tareWeight,
            lotto: consumption.lottoBobina,
        }, selectedMaterial.type);
    } else {
        toast({ variant: 'destructive', title: 'Errore', description: registerResult.message });
    }
    setIsProcessing(false);
  };
  
  const onPrelevaMateriale = async (values: FormValues) => {
      if (!selectedMaterial || !job || !operator || !values.quantityToWithdraw) return;
      setIsProcessing(true);
      const formData = new FormData();
      formData.append('materialId', selectedMaterial.id);
      formData.append('operatorId', operator.id);
      formData.append('jobId', job.id);
      formData.append('jobOrderPF', job.ordinePF);
      formData.append('phaseId', phase.id);
      formData.append('quantity', String(values.quantityToWithdraw));
      formData.append('unit', inputUnit === 'kg' ? 'kg' : selectedMaterial.unitOfMeasure);
      formData.append('lotto', values.lotto || '');
      
      const result = await logTubiGuainaWithdrawal(formData);
      toast({
          title: result.success ? 'Prelievo Registrato' : 'Errore',
          description: result.message,
          variant: result.success ? 'default' : 'destructive',
      });
      if (result.success) {
          onWithdrawalComplete();
      }
      setIsProcessing(false);
  };
  
  const renderScanView = () => (
    <div>
        <div className="relative grid place-items-center aspect-video bg-black rounded-lg overflow-hidden my-4">
            <video ref={videoRef} className="w-full h-full object-cover" autoPlay muted playsInline />
            {hasPermission === false && (
                <div className="absolute inset-0 bg-black/80 flex flex-col items-center justify-center text-center p-4">
                    <AlertTriangle className="h-12 w-12 text-destructive mb-4" />
                    <p className="text-white font-semibold">Accesso Fotocamera Negato</p>
                </div>
            )}
            <div className="absolute inset-0 grid place-items-center pointer-events-none">
                <div className="w-5/6 h-2/5 border-2 border-primary/50 rounded-lg relative">
                    <div className="absolute w-full top-1/2 -translate-y-1/2 h-0.5 bg-red-500/80 shadow-[0_0_4px_1px_#ef4444]"></div>
                </div>
            </div>
        </div>
        <div className="flex flex-col gap-2">
            <Button onClick={triggerScan} disabled={isProcessing || !hasPermission} className="w-full h-12">
                {isProcessing ? <Loader2 className="h-4 w-4 animate-spin"/> : <Camera className="mr-2 h-4 w-4" />}
                Scansiona Ora
            </Button>
             <Button variant="outline" onClick={() => setScanType(null)}>Indietro</Button>
        </div>
    </div>
  );

  const renderForm = () => {
    const isBobina = phase.name.toUpperCase().includes("TRECCIA") || phase.name.toUpperCase().includes("CORDA") || selectedMaterial?.type === 'BOB' || selectedMaterial?.type === 'PF3V0';

    return (
     <Form {...form}>
        <form className="h-full flex flex-col overflow-hidden" onSubmit={(e) => e.preventDefault()}>
          <ScrollArea className="flex-1 px-6 py-2">
            <div className="space-y-4">
              {selectedMaterial ? (
                  <div className="p-4 border rounded-lg bg-muted/50 border-primary/20 space-y-4">
                      <div className="text-center">
                        <p className="font-black text-xl tracking-tight">{selectedMaterial.code}</p>
                        <p className="text-[10px] text-muted-foreground uppercase font-bold tracking-widest">{selectedMaterial.description}</p>
                      </div>
                      
                      <div className="grid grid-cols-2 gap-2">
                        <div className="p-2 rounded-md bg-background border flex flex-col items-center justify-center text-center">
                            <Label className="text-[8px] uppercase font-black text-muted-foreground">Totale Magazzino</Label>
                            <p className="text-sm font-black text-primary leading-tight">
                                {formatDisplayStock(selectedMaterial.currentStockUnits, selectedMaterial.unitOfMeasure)} {selectedMaterial.unitOfMeasure.toUpperCase()}
                            </p>
                            <p className="text-[9px] font-bold text-muted-foreground">
                                ({formatDisplayStock(selectedMaterial.currentWeightKg, 'kg')} KG)
                            </p>
                        </div>

                        <div className={cn(
                            "p-2 rounded-md border flex flex-col items-center justify-center text-center transition-all",
                            lotAvailability ? "bg-primary/10 border-primary/40" : "bg-muted border-dashed opacity-50"
                        )}>
                            <Label className="text-[8px] uppercase font-black text-muted-foreground">Stock Lotto Attivo</Label>
                            {lotAvailability ? (
                                <>
                                    <p className="text-sm font-black text-primary leading-tight">
                                        {formatDisplayStock(lotAvailability.available, selectedMaterial.unitOfMeasure)} {selectedMaterial.unitOfMeasure.toUpperCase()}
                                    </p>
                                    <p className="text-[9px] font-bold text-primary/70">Lotto: {lotAvailability.lotto}</p>
                                </>
                            ) : (
                                <p className="text-[10px] font-bold text-muted-foreground italic">Nessun Lotto</p>
                            )}
                        </div>
                      </div>
                  </div>
              ) : <Alert><AlertDescription>Scansiona un materiale o un lotto per iniziare.</AlertDescription></Alert>}

              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                  <Button type="button" onClick={() => handleScanTrigger('material')} className="w-full h-12">
                      <QrCode className="mr-2 h-4 w-4" /> Materiale
                  </Button>
                   <Button type="button" onClick={() => handleScanTrigger('lotto')} className="w-full h-12" variant="secondary">
                      <Barcode className="mr-2 h-4 w-4" /> Lotto
                  </Button>
              </div>
              
              {selectedMaterial && (
                <div className="space-y-4">
                    <FormField control={form.control} name="lotto" render={({field}) => (
                        <FormItem>
                            <FormLabel className="font-bold text-xs uppercase text-muted-foreground">Numero Lotto Scansionato</FormLabel>
                            <FormControl><Input {...field} value={field.value ?? ''} placeholder="Scansiona o digita il lotto" className="font-mono font-bold border-primary/30" /></FormControl>
                        </FormItem>
                    )}/>

                    {lotAvailability && (
                        <Alert className="bg-green-500/10 border-green-500/30 py-2 animate-in fade-in slide-in-from-top-1">
                            <div className="flex items-center gap-3">
                                <Boxes className="h-5 w-5 text-green-600" />
                                <div>
                                    <AlertTitle className="text-xs font-bold text-green-700 uppercase">Lotto {lotAvailability.lotto} Riconosciuto</AlertTitle>
                                    <AlertDescription className="text-sm font-black text-green-600">
                                        Disponibilit├á: {formatDisplayStock(lotAvailability.available, selectedMaterial.unitOfMeasure)} {selectedMaterial.unitOfMeasure.toUpperCase()}
                                    </AlertDescription>
                                </div>
                            </div>
                        </Alert>
                    )}

                    <FormField control={form.control} name="ddt" render={({field}) => (
                        <FormItem>
                            <FormLabel className="font-bold text-xs uppercase text-muted-foreground">DDT / Origine</FormLabel>
                            <FormControl><Input {...field} value={field.value ?? ''} className="text-xs h-8" /></FormControl>
                        </FormItem>
                    )}/>

                    <div className="space-y-4 border-t pt-4">
                        {isBobina ? (
                            <FormField control={form.control} name="openingWeightManual" render={({field}) => (
                                <FormItem>
                                    <FormLabel className="text-primary font-black uppercase text-xs">Quantit├á Iniziale (PESO NETTO {selectedMaterial.unitOfMeasure.toUpperCase()})</FormLabel>
                                    <FormControl>
                                        <Input 
                                            type="number"
                                            step="any"
                                            className="bg-background font-mono text-xl font-black h-12 border-2 border-primary/30" 
                                            {...field}
                                            value={field.value ?? ''}
                                        />
                                    </FormControl>
                                    <p className="text-[10px] text-muted-foreground italic">Inserire il peso netto attuale del rocchetto prima di iniziare.</p>
                                </FormItem>
                            )}/>
                        ) : (
                            <>
                                <div className="flex items-center space-x-2 rounded-lg border p-3 justify-center bg-muted/20">
                                    <Label htmlFor="unit-switch-assoc" className="text-xs font-bold">{selectedMaterial.unitOfMeasure.toUpperCase()}</Label>
                                    <Switch
                                        id="unit-switch-assoc"
                                        checked={inputUnit === 'kg'}
                                        onCheckedChange={(checked) => setInputUnit(checked ? 'kg' : 'primary')}
                                    />
                                    <Label htmlFor="unit-switch-assoc" className="text-xs font-bold">KG</Label>
                                </div>
                                <FormField control={form.control} name="quantityToWithdraw" render={({field}) => (
                                    <FormItem>
                                        <FormLabel className="text-primary font-black uppercase text-xs">Quantit├á da prelevare ({inputUnit === 'primary' ? selectedMaterial.unitOfMeasure.toUpperCase() : 'KG'})</FormLabel>
                                        <FormControl><Input type="number" step="any" {...field} value={field.value ?? ''} className="font-mono text-lg font-bold" /></FormControl>
                                        <FormMessage/>
                                    </FormItem>
                                )}/>
                            </>
                        )}

                        {isBobina && (
                            <FormField control={form.control} name="packagingId" render={({field}) => (
                                <FormItem>
                                    <FormLabel className="flex items-center gap-2 text-xs font-bold uppercase text-muted-foreground"><Archive className="h-3 w-3" />Tara Imballo Applicata</FormLabel>
                                    <Select onValueChange={(val) => field.onChange(val || 'none')} value={field.value || 'none'}>
                                        <FormControl><SelectTrigger className="text-xs h-8"><SelectValue placeholder="Seleziona..." /></SelectTrigger></FormControl>
                                        <SelectContent>
                                            <SelectItem value="none">Nessuna Tara (0.00 kg)</SelectItem>
                                            {packagingItems.filter(p => !selectedMaterial || (p.associatedTypes && p.associatedTypes.includes(selectedMaterial.type))).map(item => (
                                                <SelectItem key={item.id} value={item.id} className="text-xs">{item.name} ({item.weightKg.toFixed(3)} kg)</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </FormItem>
                            )} />
                        )}
                    </div>
                </div>
              )}
            </div>
          </ScrollArea>
          <DialogFooter className="flex-col sm:flex-col gap-2 p-6 pt-4 border-t sticky bottom-0 bg-background">
              {isBobina ? (
                <Button type="button" onClick={onAvviaSessione} disabled={!selectedMaterial || isProcessing} className="w-full h-14 text-lg font-black uppercase tracking-tighter">
                    {isProcessing ? <Loader2 className="mr-2 h-5 w-5 animate-spin"/> : <Play className="mr-2 h-5 w-5 fill-current" />} 
                    Avvia Sessione Bobina
                </Button>
              ) : (
                <Button type="button" onClick={form.handleSubmit(onPrelevaMateriale)} disabled={!selectedMaterial || isProcessing || !form.watch('quantityToWithdraw')} className="w-full h-14 text-lg font-black uppercase tracking-tighter">
                    {isProcessing ? <Loader2 className="mr-2 h-5 w-5 animate-spin"/> : <Send className="mr-2 h-5 w-5" />}
                    Registra Scarico
                </Button>
              )}
          </DialogFooter>
        </form>
      </Form>
    );
  }

  return (
    <Dialog open={isOpen} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md h-[90vh] flex flex-col p-0 overflow-hidden">
        <DialogHeader className="p-6 pb-2 border-b bg-muted/10">
          <DialogTitle className="text-lg font-bold">Associa Materiale: {phase.name}</DialogTitle>
        </DialogHeader>
        {scanType ? <div className="p-6 pt-0">{renderScanView()}</div> : renderForm()}
      </DialogContent>
    </Dialog>
  );
}

"use client";

import React, { useState, useEffect } from 'react';
import { Button } from './ui/button';
import { Download, RefreshCw } from 'lucide-react';
import { Tooltip, TooltipProvider, TooltipContent, TooltipTrigger } from './ui/tooltip';
import { useToast } from '@/hooks/use-toast';
import { ToastAction } from './ui/toast';

// Add type for the install prompt event
interface BeforeInstallPromptEvent extends Event {
    readonly platforms: Array<string>;
    readonly userChoice: Promise<{
        outcome: 'accepted' | 'dismissed';
        platform: string;
    }>;
    prompt(): Promise<void>;
}

const PwaInstaller = () => {
    const [installPrompt, setInstallPrompt] = useState<BeforeInstallPromptEvent | null>(null);
    const { toast } = useToast();

    useEffect(() => {
        const handleBeforeInstallPrompt = (e: Event) => {
            e.preventDefault();
            setInstallPrompt(e as BeforeInstallPromptEvent);
        };

        const setupServiceWorker = () => {
            if ('serviceWorker' in navigator && process.env.NODE_ENV === 'production' && (window as any).Workbox) {
                const wb = new (window as any).Workbox('/sw.js');

                // This listener will fire when a new service worker has finished installing
                // and is waiting to take control.
                wb.addEventListener('waiting', (event: any) => {
                    const promptUserToUpdate = () => {
                         toast({
                            title: "Aggiornamento Disponibile",
                            description: "├ê disponibile una nuova versione dell'app. Clicca per aggiornare.",
                            duration: Infinity,
                            action: (
                                <ToastAction altText="Aggiorna" onClick={() => {
                                    // This will send a message to the waiting service worker to activate itself
                                    wb.messageSkipWaiting();
                                }}>
                                    <RefreshCw className="mr-2 h-4 w-4" />
                                    Aggiorna
                                </ToastAction>
                            ),
                        });
                    };
                    promptUserToUpdate();
                });
                
                // This listener will fire when the new service worker has taken control
                wb.addEventListener('controlling', () => {
                    // At this point, the old service worker has been replaced. We can now
                    // safely reload the page to ensure all content is from the new version.
                    window.location.reload();
                });

                wb.register();
            }
        };

        window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
        window.addEventListener('load', setupServiceWorker);


        return () => {
            window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
            window.removeEventListener('load', setupServiceWorker);
        };
    }, [toast]);

    const handleInstallClick = async () => {
        if (!installPrompt) {
            toast({
                title: "Installazione non disponibile",
                description: "L'app potrebbe essere gi├á installata o il tuo browser non supporta questa funzionalit├á.",
                variant: "default",
            });
            return;
        }
        await installPrompt.prompt();
        const { outcome } = await installPrompt.userChoice;
        if (outcome === 'accepted') {
            toast({ title: "Installazione Avviata", description: "L'app verr├á aggiunta alla tua schermata principale." });
        }
        setInstallPrompt(null);
    };

    if (!installPrompt) {
        return null; // Do not render the install button if not applicable
    }

    return (
        <div className="fixed bottom-16 right-4 z-50">
            <TooltipProvider>
                <Tooltip>
                    <TooltipTrigger asChild>
                        <Button
                            onClick={handleInstallClick}
                            variant="default"
                            size="icon"
                            className="h-12 w-12 rounded-full bg-green-600 hover:bg-green-700 text-white shadow-lg"
                        >
                            <Download className="h-6 w-6" />
                        </Button>
                    </TooltipTrigger>
                    <TooltipContent>
                        <p>Installa l'app sul tuo dispositivo</p>
                    </TooltipContent>
                </Tooltip>
            </TooltipProvider>
        </div>
    );
};

export default PwaInstaller;

