                            <div className="flex items-center justify-between gap-2">
                                <div className="flex items-center gap-2">
                                    {getPhaseIcon(phase.status)}
                                    <span className={cn("text-xs font-semibold uppercase tracking-wider", phase.status === 'skipped' && 'line-through text-muted-foreground')}>{phase.name}</span>
                                </div>
                                {phase.status === 'completed' && overallStatus !== 'Completata' && !isPartOfGroup && (
                                    <AlertDialog>
                                        <AlertDialogTrigger asChild>
                                            <Button variant="ghost" size="icon" className="h-6 w-6 text-muted-foreground hover:text-destructive">
                                                <Undo2 className="h-4 w-4" />
                                            </Button>
                                        </AlertDialogTrigger>
                                        <AlertDialogContent>
                                            <AlertDialogHeader><AlertDialogTitle>Ripristinare la fase?</AlertDialogTitle><AlertDialogDescription>Questa azione riporter├á la fase "{phase.name}" allo stato di pausa, conservando il tempo di lavoro gi├á registrato. Sei sicuro?</AlertDialogDescription></AlertDialogHeader>
                                            <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onRevertPhaseClick(jobOrder.id, phase.id)}>S├¼, ripristina</AlertDialogAction></AlertDialogFooter>
