import { getOverallStatus } from '@/lib/types';
import { dissolveWorkGroup } from '@/app/admin/work-group-management/actions';
import { useAuth } from '@/components/auth/AuthProvider';
import { Input } from '@/components/ui/input';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar } from '@/components/ui/calendar';
import { format, isSameDay, isPast, parseISO, startOfWeek, endOfWeek, getWeek, isValid } from 'date-fns';
import { it } from 'date-fns/locale';
import { Label } from '@/components/ui/label';
import { Switch } from '@/components/ui/switch';
import { Checkbox } from '@/components/ui/checkbox';
import { cn } from '@/lib/utils';
import { Badge } from '@/components/ui/badge';
import { getWorkingHoursConfig } from '@/app/admin/working-hours/actions';

type FilterStatus = OverallStatus | 'all' | 'LIVE';

interface WeeklyGroup {
    weekNumber: number;
    weekLabel: string;
    items: (JobOrder | WorkGroup)[];
    totalPcs: number;
}

export default function ProductionConsoleClientPage() {
  const [jobOrders, setJobOrders] = useState<JobOrder[]>([]);
  const [workGroups, setWorkGroups] = useState<WorkGroup[]>([]);
  const [allOperators, setAllOperators] = useState<Operator[]>([]);
  const [allRawMaterials, setAllRawMaterials] = useState<RawMaterial[]>([]);
  const [workingHours, setWorkingHours] = useState<WorkingHoursConfig | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [activeFilter, setActiveFilter] = useState<FilterStatus>('all');
  const [problemJob, setProblemJob] = useState<JobOrder | WorkGroup | null>(null);
  const [phaseManagedItem, setPhaseManagedItem] = useState<JobOrder | WorkGroup | null>(null);
  const [materialManagedItem, setMaterialManagedItem] = useState<JobOrder | WorkGroup | null>(null);
  const [analysisDataMap, setAnalysisDataMap] = useState<Map<string, ProductionTimeData | null>>(new Map());
  const [jobsWithLoadingAnalysis, setJobsWithLoadingAnalysis] = useState<Set<string>>(new Set());

  const searchParams = useSearchParams();
  const groupIdFromUrl = searchParams.get('groupId');
  const [searchTerm, setSearchTerm] = useState(groupIdFromUrl || '');
  const [completedDateFilter, setCompletedDateFilter] = useState<Date | undefined>(new Date());
  const [isDateFilterActive, setIsDateFilterActive] = useState(false);
  const [showOnlyOverdue, setShowOnlyOverdue] = useState(false);
  const [showCompleted, setShowCompleted] = useState(false);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  
  const [editablePhases, setEditablePhases] = useState<JobPhase[]>([]);
  const [isOrderChanged, setIsOrderChanged] = useState(false);

  const { toast } = useToast();
  const { user, operator } = useAuth();
  const router = useRouter();
  
  const jobsLoadedRef = useRef(false);
  const groupsLoadedRef = useRef(false);

  const isJobLive = useCallback((item: JobOrder | WorkGroup): boolean => {
      return (item.phases || []).some(p => p.status === 'in-progress');
  }, []);
  
  const isOverdueItem = (item: JobOrder | WorkGroup) => {
    const deliveryDateString = item.dataConsegnaFinale;
    if (!deliveryDateString || !/^\d{4}-\d{2}-\d{2}$/.test(deliveryDateString)) return false;
    const deliveryDate = parseISO(deliveryDateString);
    return isPast(deliveryDate) && getOverallStatus(item) !== 'Completata';
  };

  useEffect(() => {
    setIsLoading(true);
    getWorkingHoursConfig().then(setWorkingHours);

    const unsubscribeJobs = onSnapshot(query(collection(db, "jobOrders"), where("status", "in", ["production", "suspended", "completed", "paused"])), (snap) => {
        const jobs = snap.docs.map(doc => JSON.parse(JSON.stringify(doc.data()), (key, value) => {
            if ((['start', 'end', 'overallStartTime', 'overallEndTime', 'odlCreationDate', 'createdAt']).includes(key) && value && typeof value === 'object' && value.seconds !== undefined) return new Date(value.seconds * 1000);
            return value;
        }) as JobOrder);
        setJobOrders(jobs); jobsLoadedRef.current = true; if (groupsLoadedRef.current) setIsLoading(false);
    });
    const unsubscribeGroups = onSnapshot(collection(db, "workGroups"), (snap) => {
        const groups = snap.docs.map(doc => JSON.parse(JSON.stringify(doc.data()), (key, value) => {
            if ((['createdAt', 'overallStartTime', 'overallEndTime']).includes(key) && value && typeof value === 'object' && value.seconds !== undefined) return new Date(value.seconds * 1000);
            return value;
        }) as WorkGroup);
        setWorkGroups(groups); groupsLoadedRef.current = true; if (jobsLoadedRef.current) setIsLoading(false);
    });
    onSnapshot(collection(db, "operators"), (snap) => setAllOperators(snap.docs.map(d => d.data() as Operator)));
    onSnapshot(collection(db, "rawMaterials"), (snap) => setAllRawMaterials(snap.docs.map(d => ({id: d.id, ...d.data()} as RawMaterial))));
    return () => { unsubscribeJobs(); unsubscribeGroups(); };
  }, [toast]);
  
  const workGroupsMap = useMemo(() => new Map(workGroups.map(g => [g.id, g])), [workGroups]);
  
  const { standaloneJobs, jobsByGroupId } = useMemo(() => {
    const grouped = new Map<string, JobOrder[]>();
    const standalone: JobOrder[] = [];
    jobOrders.forEach(job => {
      if (job.workGroupId && workGroupsMap.has(job.workGroupId)) {
        if (!grouped.has(job.workGroupId)) grouped.set(job.workGroupId, []);
        grouped.get(job.workGroupId)!.push(job);
      } else standalone.push(job);
    });
    return { standaloneJobs: standalone, jobsByGroupId: grouped };
  }, [jobOrders, workGroupsMap]);

  const applyFilters = <T extends JobOrder | WorkGroup>(items: T[]): T[] => {
      let f = items;
      if (showCompleted) {
          f = f.filter(i => getOverallStatus(i) === 'Completata');
          if (isDateFilterActive && completedDateFilter) f = f.filter(i => i.overallEndTime && isSameDay(new Date(i.overallEndTime), completedDateFilter));
      } else {
          f = f.filter(i => getOverallStatus(i) !== 'Completata');
          if (activeFilter !== 'all') f = activeFilter === 'LIVE' ? f.filter(isJobLive) : f.filter(i => getOverallStatus(i) === activeFilter);
      }
      if (showOnlyOverdue) f = f.filter(isOverdueItem);
      if (searchTerm) {
          const l = searchTerm.toLowerCase();
          f = f.filter(i => {
              const isG = 'jobOrderIds' in i;
              if (isG) return (i as WorkGroup).id.toLowerCase().includes(l) || (i as WorkGroup).details.toLowerCase().includes(l) || (jobsByGroupId.get(i.id) || []).some(j => j.ordinePF.toLowerCase().includes(l));
              return (i as JobOrder).ordinePF.toLowerCase().includes(l) || (i as JobOrder).details.toLowerCase().includes(l) || (i as JobOrder).cliente.toLowerCase().includes(l);
          });
      }
      return f;
  };

  const filteredItems = useMemo(() => {
      const filteredStandalone = applyFilters(standaloneJobs);
      const filteredGroups = applyFilters(Array.from(workGroupsMap.values()));
      return [...filteredStandalone, ...filteredGroups];
  }, [standaloneJobs, workGroupsMap, activeFilter, searchTerm, showCompleted, isDateFilterActive, completedDateFilter, showOnlyOverdue, isJobLive, jobsByGroupId]);

  const { weeklyGroups, daVerificare } = useMemo(() => {
      const weeksMap = new Map<string, WeeklyGroup>();
      const daVerificare: (JobOrder | WorkGroup)[] = [];

      filteredItems.forEach(item => {
          const dateStr = item.dataConsegnaFinale;
          if (!dateStr || dateStr === 'N/D' || !isValid(parseISO(dateStr))) {
              daVerificare.push(item);
              return;
          }

          const date = parseISO(dateStr);
          const weekNum = getWeek(date, { weekStartsOn: 1 });
          const weekStart = startOfWeek(date, { weekStartsOn: 1 });
          const weekEnd = endOfWeek(date, { weekStartsOn: 1 });
          const year = format(date, 'yyyy');
          const key = `${year}-W${String(weekNum).padStart(2, '0')}`;

          if (!weeksMap.has(key)) {
              weeksMap.set(key, {
                  weekNumber: weekNum,
                  weekLabel: `Settimana ${weekNum} (${format(weekStart, 'dd/MM')} - ${format(weekEnd, 'dd/MM')})`,
                  items: [],
                  totalPcs: 0
              });
          }

          const group = weeksMap.get(key)!;
          group.items.push(item);
          group.totalPcs += ('totalQuantity' in item) ? (item.totalQuantity || 0) : (item.qta || 0);
      });

      const sortedWeeks = Array.from(weeksMap.entries())
          .sort((a, b) => a[0].localeCompare(b[0]))
          .map(([_, group]) => group);

      return { weeklyGroups: sortedWeeks, daVerificare };
  }, [filteredItems]);

  const handleSelectAll = () => {
    if (selectedIds.length === filteredItems.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredItems.map(i => i.id));
    }
  };
  
  const handleSelectItem = (itemId: string) => {
    setSelectedIds(prev =>
      prev.includes(itemId) ? prev.filter(selectedId => selectedId !== itemId) : [...prev, itemId]
    );
  };
  
  const handleBulkForceFinish = async () => {
    if (!user || selectedIds.length === 0) return;
    const result = await forceFinishMultiple(selectedIds, user.uid);
    toast({ title: result.success ? "Operazione Riuscita" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) setSelectedIds([]);
  };

  const handleBulkForceComplete = async () => {
    if (!user || selectedIds.length === 0) return;
    const result = await forceCompleteMultiple(selectedIds, user.uid);
    toast({ title: result.success ? "Operazione Riuscita" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    if (result.success) setSelectedIds([]);
  };
  
  const handleBulkReset = async () => {
     if (selectedIds.length === 0 || !user) return;
     setIsLoading(true);
     for (const id of selectedIds) { await resetSingleCompletedJobOrder(id, user.uid); }
     toast({ title: "Reset Completato" });
     setSelectedIds([]); setIsLoading(false);
  };

  const handleResolveProblem = async () => {
    if (!problemJob || !user) return;
    const result = await resolveJobProblem(problemJob.id, user.uid);
    toast({ title: result.success ? "Problema Risolto" : "Errore", description: result.message, variant: result.success ? "default" : "destructive" });
    setProblemJob(null);
  };

  const handleFilterClick = (filter: FilterStatus) => {
    setActiveFilter(filter);
    setShowCompleted(false);
  };

  const handleForceFinish = async (jobId: string) => { if (!user) return; await forceFinishProduction(jobId, user.uid); };
  const handleRevertForceFinish = async (jobId: string) => { if (!user) return; await revertForceFinish(jobId, user.uid); };
  const handleForceComplete = async (jobId: string) => { if (!user) return; await forceCompleteJob(jobId, user.uid); };
  const handleToggleGuaina = async (jobId: string, phaseId: string, currentState: 'default' | 'postponed') => { if (!user) return; await toggleGuainaPhasePosition(jobId, phaseId, currentState); };
  const handleRevertPhase = async (jobId: string, phaseId: string) => { if (!user) return; await revertPhaseCompletion(jobId, phaseId, user.uid); };
  const handleRevertCompletion = async (itemId: string) => { if (!user) return; await revertCompletion(itemId, user.uid); };
  const handleForcePause = async (jobId: string, ops: string[]) => { if (!user) return; await forcePauseOperators(jobId, ops, user.uid); };
  const onResetJobOrderClick = async (jobId: string) => { if (!user) return; await resetSingleCompletedJobOrder(jobId, user.uid); };
  const handleUpdateDeliveryDate = async (itemId: string, newDate: string) => { if (!user) return; await updateJobDeliveryDate(itemId, newDate, user.uid); };
  const handleDissolveGroup = async (groupId: string) => { await dissolveWorkGroup(groupId); };

  const handleOpenPhaseManager = (item: JobOrder | WorkGroup) => {
    setPhaseManagedItem(item);
    setEditablePhases([...item.phases].sort((a,b) => a.sequence - b.sequence));
    setIsOrderChanged(false);
  };
  
  const handlePhaseStatusToggle = (phaseId: string) => {
    setEditablePhases(prev => {
      const news = prev.map(p => {
        if (p.id === phaseId) {
          if (p.status === 'pending') return { ...p, status: 'skipped' as const };
          if (p.status === 'skipped') return { ...p, status: 'pending' as const };
        }
        return p;
      });
      setIsOrderChanged(true); return news;
    });
  };

  const handleMovePhase = (index: number, direction: 'up' | 'down') => {
    setEditablePhases(prev => {
        const news = [...prev];
        const targetIndex = direction === 'up' ? index - 1 : index + 1;
        if (targetIndex >= 0 && targetIndex < news.length) {
            const temp = news[index];
            news[index] = news[targetIndex];
            news[targetIndex] = temp;
        }
        setIsOrderChanged(true); return news;
    });
  };
  
  const handleSaveChanges = async () => {
    if (!user || !phaseManagedItem) return;
    const res = await updatePhasesForJob(phaseManagedItem.id, editablePhases, user.uid);
    if (res.success) {
        toast({ title: "Fasi aggiornate" });
        setPhaseManagedItem(null);
    } else {
        toast({ variant: "destructive", title: "Errore", description: res.message });
    }
  };

  const handleFetchAnalysis = async (job: JobOrder) => {
    if (!job.id) return;
    setJobsWithLoadingAnalysis(prev => new Set(prev).add(job.id));
    try {
        const map = await getProductionTimeAnalysisMap();
        setAnalysisDataMap(prev => new Map(prev).set(job.id, map.get(job.details) || null));
    } catch (e) { toast({ variant: "destructive", title: "Errore Analisi" }); }
    finally { setJobsWithLoadingAnalysis(prev => { const n = new Set(prev); n.delete(job.id); return n; }); }
  };

  const handleNavigateToAnalysis = (articleCode: string) => {
    router.push(`/admin/production-time-analysis?articleCode=${encodeURIComponent(articleCode)}`);
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    toast({ title: "Copiato!" });
  };

  const handleMaterialStatusToggle = async (itemId: string, phaseId: string, currentStatus?: string) => {
      if (!user) return;
      if (currentStatus === 'missing') {
          await resolveMaterialMissing(itemId, phaseId, user.uid);
      } else {
          await reportMaterialMissing(itemId, phaseId, user.uid);
      }
  };

  function getPhaseIconLocal(status: JobPhase['status']) {
    switch (status) {
      case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
      case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
      case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
      case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
      case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
      default: return <Circle className="h-4 w-4 text-muted-foreground" />;
    }
  }

  const renderItem = (item: JobOrder | WorkGroup) => {
      const isGroup = 'jobOrderIds' in item;
      if (isGroup) {
          return (
            <WorkGroupCard 
                key={item.id} 
                group={item as WorkGroup} 
                jobsInGroup={jobsByGroupId.get(item.id) || []} 
                allOperators={allOperators} 
                allRawMaterials={allRawMaterials} 
                onProblemClick={() => setProblemJob(item as WorkGroup)} 
                onForceFinishClick={handleForceFinish} 
                onForcePauseClick={handleForcePause} 
                onForceCompleteClick={handleForceComplete} 
                onDissolveGroupClick={handleDissolveGroup} 
                onOpenPhaseManager={handleOpenPhaseManager} 
                onOpenMaterialManager={() => setMaterialManagedItem(item as WorkGroup)} 
                onToggleGuainaClick={handleToggleGuaina} 
                onUpdateDeliveryDate={handleUpdateDeliveryDate} 
                isSelected={selectedIds.includes(item.id)} 
                onSelect={handleSelectItem} 
                overallStatus={getOverallStatus(item as WorkGroup)} 
                getOverallStatus={getOverallStatus} 
                onNavigateToAnalysis={handleNavigateToAnalysis} 
                onCopyArticleCode={handleCopy}
            />
          );
      }
      return (
        <JobOrderCard 
            key={item.id} 
            jobOrder={item as JobOrder} 
            allOperators={allOperators} 
            allRawMaterials={allRawMaterials} 
            analysisData={analysisDataMap.get(item.id)} 
            onFetchAnalysis={() => handleFetchAnalysis(item as JobOrder)} 
            isAnalysisLoading={jobsWithLoadingAnalysis.has(item.id)} 
            onProblemClick={() => setProblemJob(item as JobOrder)} 
            onForceFinishClick={handleForceFinish} 
            onRevertForceFinishClick={handleRevertForceFinish} 
            onToggleGuainaClick={handleToggleGuaina} 
            onRevertPhaseClick={handleRevertPhase} 
            onRevertCompletionClick={handleRevertCompletion} 
            onForcePauseClick={handleForcePause} 
            onForceCompleteClick={handleForceComplete} 
            onResetJobOrderClick={onResetJobOrderClick} 
            onOpenPhaseManager={handleOpenPhaseManager} 
            onOpenMaterialManager={() => setMaterialManagedItem(item as JobOrder)} 
            onUpdateDeliveryDate={handleUpdateDeliveryDate} 
            isSelected={selectedIds.includes(item.id)} 
            onSelect={handleSelectItem} 
            overallStatus={getOverallStatus(item as JobOrder)} 
            onNavigateToAnalysis={handleNavigateToAnalysis} 
            onCopyArticleCode={handleCopy}
        />
      );
  };

  return (
    <>
      <div className="space-y-6">
        <header className="flex flex-col sm:flex-row justify-between items-start gap-4">
            <div><h1 className="text-3xl font-bold font-headline flex items-center gap-3"><Briefcase className="h-8 w-8 text-primary" /> Console Controllo Produzione</h1></div>
            <div className="relative w-full sm:max-w-xs"><Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" /><Input placeholder="Cerca..." className="pl-9" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
        </header>
        
        <Card className="p-2 space-y-2">
          <div className="flex flex-wrap items-center justify-center gap-1">
              {[
                { label: 'Tutte', value: 'all', icon: Briefcase },
                { label: 'In Corso (Live)', value: 'LIVE', icon: Activity },
                { label: 'In Lavorazione', value: 'In Lavorazione', icon: Hourglass },
                { label: 'Sospesa', value: 'Sospesa', icon: PauseCircle },
                { label: 'Problema', value: 'Problema', icon: ShieldAlert },
                { label: 'Manca Materiale', value: 'Manca Materiale', icon: PackageX },
              ].map(f => (
                <Button key={f.value} variant={activeFilter === f.value && !showCompleted ? 'secondary' : 'ghost'} onClick={() => handleFilterClick(f.value as any)} className="text-xs sm:text-sm">
                  <f.icon className={cn("mr-2 h-4 w-4", f.value === 'LIVE' && "text-red-400 animate-pulse")} /> {f.label}
                </Button>
              ))}
          </div>
           <div className="border-t pt-2 flex items-center justify-center gap-4 flex-wrap">
                  <div className="flex items-center space-x-2"><Switch id="over-sw" checked={showOnlyOverdue} onCheckedChange={setShowOnlyOverdue} /><Label htmlFor="over-sw" className="text-destructive">Filtra Ritardi</Label></div>
                  <div className="flex items-center space-x-2"><Switch id="comp-sw" checked={showCompleted} onCheckedChange={setShowCompleted} /><Label htmlFor="comp-sw">Mostra Completate</Label></div>
                  {showCompleted && (
                    <div className="flex items-center gap-2">
                      <Switch id="dt-sw" checked={isDateFilterActive} onCheckedChange={setIsDateFilterActive} /><Label htmlFor="dt-sw">Filtra Data</Label>
                      <Popover><PopoverTrigger asChild><Button variant="outline" className={cn("w-[200px] justify-start", !isDateFilterActive && "opacity-50")} disabled={!isDateFilterActive}><CalendarIcon className="mr-2 h-4 w-4" />{completedDateFilter ? format(completedDateFilter, "PPP", { locale: it }) : "Data"}</Button></PopoverTrigger>
                      <PopoverContent className="w-auto p-0"><Calendar mode="single" selected={completedDateFilter} onSelect={setCompletedDateFilter} initialFocus /></PopoverContent></Popover>
                    </div>
                  )}
           </div>
        </Card>
        
         {filteredItems.length > 0 && (
          <div className="flex items-center gap-4">
              <div className="flex items-center gap-2">
                  <Checkbox id="sel-all" checked={selectedIds.length > 0 && selectedIds.length === filteredItems.length} onCheckedChange={handleSelectAll} />
                  <Label htmlFor="sel-all">Seleziona Tutte ({filteredItems.length})</Label>
              </div>
              {selectedIds.length > 0 && (
                  <DropdownMenu>
                    <DropdownMenuTrigger asChild><Button variant="outline" size="sm">Azioni di Gruppo ({selectedIds.length}) <MoreVertical className="ml-2 h-4 w-4" /></Button></DropdownMenuTrigger>
                     <DropdownMenuContent align="start">
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()}><FastForward className="mr-2 h-4 w-4" /> Forza a Finitura</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Confermi l'avanzamento forzato?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkForceFinish}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                        
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()}><PowerOff className="mr-2 h-4 w-4" /> Chiudi Item</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Confermi la chiusura forzata?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkForceComplete}>Conferma</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                        
                        <DropdownMenuSeparator />
                        <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()} className="text-destructive"><RefreshCcw className="mr-2 h-4 w-4" /> Annulla e Resetta</DropdownMenuItem></AlertDialogTrigger>
                        <AlertDialogContent><AlertDialogHeader><AlertDialogTitle>Sei sicuro di voler resettare?</AlertDialogTitle></AlertDialogHeader><AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={handleBulkReset} className="bg-destructive">S├¼, Resetta</AlertDialogAction></AlertDialogFooter></AlertDialogContent></AlertDialog>
                    </DropdownMenuContent>
                  </DropdownMenu>
              )}
          </div>
        )}

        {isLoading ? (
            <div className="flex flex-col items-center justify-center py-20"><Loader2 className="h-12 w-12 animate-spin text-primary" /><p className="mt-4 text-muted-foreground">Aggiornamento...</p></div>
        ) : filteredItems.length > 0 ? (
          <div className="space-y-12">
            
            {daVerificare.length > 0 && (
                <section className="space-y-4">
                    <div className="flex items-center gap-3 border-b-2 border-destructive/20 pb-2">
                        <AlertCircle className="h-6 w-6 text-destructive" />
                        <h2 className="text-xl font-black uppercase tracking-tight text-destructive">Da Gestire e Verificare (N/D)</h2>
                        <Badge variant="destructive">{daVerificare.length}</Badge>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {daVerificare.map(renderItem)}
                    </div>
                </section>
            )}

            {weeklyGroups.map((group) => (
                <section key={group.weekLabel} className="space-y-4">
                    <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-4 border-b-2 border-primary/20 pb-2">
                        <div className="flex items-center gap-3">
                            <CalendarDays className="h-6 w-6 text-primary" />
                            <h2 className="text-xl font-black uppercase tracking-tight text-primary">{group.weekLabel}</h2>
                            <Badge variant="outline" className="border-primary text-primary">{group.items.length} Item</Badge>
                        </div>
                        <div className="flex items-center gap-4 text-sm font-bold text-muted-foreground">
                            <div className="flex items-center gap-1.5"><Package2 className="h-4 w-4"/> {group.totalPcs} pz totali</div>
                            <div className="flex items-center gap-1.5"><Clock className="h-4 w-4"/> Capacit├á: -- / -- h</div>
                        </div>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                        {group.items.map(renderItem)}
                    </div>
                </section>
            ))}

          </div>
        ) : (
          <div className="flex flex-col items-center justify-center py-20 border-2 border-dashed rounded-lg mt-8"><Package2 className="h-16 w-16 text-muted-foreground mb-4" /><h2 className="text-xl font-semibold text-muted-foreground">Nessuna Commessa Trovata</h2></div>
        )}
      </div>
      
      <Dialog open={!!phaseManagedItem} onOpenChange={o => !o && setPhaseManagedItem(null)}>
        <DialogContent className="max-w-xl"><DialogHeader><DialogTitle>Gestione Fasi: {phaseManagedItem?.id}</DialogTitle></DialogHeader>
           <div className="py-4 space-y-2 max-h-[60vh] overflow-y-auto">
            {editablePhases.map((phase, index) => (
                <div key={phase.id} className={cn("flex items-center justify-between p-3 rounded-md", (phase.status !== 'pending' && phase.status !== 'skipped') && 'bg-muted/50 opacity-70')}>
                  <div className="flex items-center gap-3">{getPhaseIconLocal(phase.status)}<span className={cn('font-medium', phase.status === 'skipped' && 'line-through text-muted-foreground')}>{phase.name}</span></div>
                  <div className="flex items-center gap-1">
                    {(phase.status === 'pending' || phase.status === 'skipped') ? (
                      <>
                        <Button size="icon" variant="ghost" onClick={() => handleMovePhase(index, 'up')} disabled={index === 0}><ArrowUp className="h-4 w-4" /></Button>
                        <Button size="icon" variant="ghost" onClick={() => handleMovePhase(index, 'down')} disabled={index === editablePhases.length - 1}><ArrowDown className="h-4 w-4" /></Button>
                        <Button size="sm" variant="outline" onClick={() => handlePhaseStatusToggle(phase.id)}>{phase.status === 'pending' ? <EyeOff className="mr-2 h-4 w-4" /> : <Undo2 className="mr-2 h-4 w-4" />}{phase.status === 'pending' ? 'Bypassa' : 'Ripristina'}</Button>
                      </>
                    ) : <Badge variant="secondary">{phase.status}</Badge>}
                  </div>
                </div>
            ))}
          </div>
          <DialogFooter><Button variant="outline" onClick={() => setPhaseManagedItem(null)}>Annulla</Button><Button onClick={handleSaveChanges} className={cn(isOrderChanged && 'bg-amber-500 animate-pulse')}>Salva Modifiche</Button></DialogFooter>
        </DialogContent>
      </Dialog>
      
      <Dialog open={!!materialManagedItem} onOpenChange={o => !o && setMaterialManagedItem(null)}>
        <DialogContent className="max-w-xl"><DialogHeader><DialogTitle>Mancanza Materiale: {materialManagedItem?.id}</DialogTitle></DialogHeader>
           <div className="py-4 space-y-2">
            {(materialManagedItem?.phases || []).filter(p => p.type === 'preparation').map(phase => (
                <div key={phase.id} className="flex items-center justify-between p-3 rounded-md">
                  <div className="flex items-center gap-3">{phase.materialStatus === 'missing' ? <PackageX className="h-5 w-5 text-destructive" /> : <PackageCheck className="h-5 w-5 text-green-500" />}<span>{phase.name}</span></div>
                  <Button size="sm" variant={phase.materialStatus === 'missing' ? 'secondary' : 'destructive'} onClick={() => handleMaterialStatusToggle(materialManagedItem!.id, phase.id, phase.materialStatus)}>{phase.materialStatus === 'missing' ? <Unlock className="mr-2 h-4 w-4" /> : <PlayCircle className="mr-2 h-4 w-4" />}{phase.materialStatus === 'missing' ? 'Risolvi' : 'Segnala'}</Button>
                </div>
            ))}
          </div>
        </DialogContent>
      </Dialog>

       <Dialog open={!!problemJob} onOpenChange={o => !o && setProblemJob(null)}>
        <DialogContent><DialogHeader><DialogTitle>Dettaglio Problema: {problemJob?.id}</DialogTitle></DialogHeader>
            <div className="space-y-4 text-sm pt-4">
                {problemJob?.problemType === 'MANCA_MATERIALE' && (
                    <ul className="list-disc pl-5 text-destructive">{(problemJob?.phases || []).filter(p => p.materialStatus === 'missing').map(p => <li key={p.id}>{p.name}</li>)}</ul>
                )}
                {problemJob?.problemNotes && <p className="text-muted-foreground p-2 bg-muted rounded-md">{problemJob.problemNotes}</p>}
            </div>
            <DialogFooter>
                <Button variant="outline" onClick={() => setProblemJob(null)}>Chiudi</Button>
                { (operator?.role === 'supervisor' || operator?.role === 'admin') && (
                  <Button onClick={handleResolveProblem} className="bg-green-600 hover:bg-green-700">
                     <Unlock className="mr-2 h-4 w-4"/> Sblocca Commessa
                  </Button>
                )}
            </DialogFooter>
        </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import type { JobOrder, JobPhase, Operator, WorkGroup, RawMaterial } from '@/lib/mock-data';
import type { OverallStatus } from '@/lib/types';
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { StatusBadge } from '@/components/production-console/StatusBadge';
import { Building, Circle, Hourglass, CheckCircle2, ShieldAlert, PauseCircle, MoreVertical, FastForward, CornerUpLeft, CornerDownRight, ListOrdered, Boxes, Users, PowerOff, Unlink, View, Combine, User, EyeOff, ChevronDown, ClipboardList, Calendar } from 'lucide-react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { TooltipProvider, Tooltip, TooltipTrigger, TooltipContent } from '@/components/ui/tooltip';
import React, { useState, useMemo } from 'react';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger, DropdownMenuSeparator } from "@/components/ui/dropdown-menu";
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from "@/components/ui/alert-dialog";
import { Checkbox } from '@/components/ui/checkbox';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Separator } from '@/components/ui/separator';
import { ScrollArea } from '@/components/ui/scroll-area';
import BOMDialog from './BOMDialog';
import JobOrderCard from './JobOrderCard';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Calendar as CalendarPicker } from '@/components/ui/calendar';
import { format, parseISO, isPast } from 'date-fns';
import { it } from 'date-fns/locale';

interface ActivePhaseInfo { phaseId: string; phaseName: string; operators: { id: string; name: string }[]; }

function getPhaseIcon(status: JobPhase['status']) {
  switch (status) {
    case 'pending': return <Circle className="h-4 w-4 text-muted-foreground" />;
    case 'in-progress': return <Hourglass className="h-4 w-4 text-blue-500 animate-spin" />;
    case 'paused': return <PauseCircle className="h-4 w-4 text-orange-500" />;
    case 'completed': return <CheckCircle2 className="h-4 w-4 text-primary" />;
    case 'skipped': return <EyeOff className="h-4 w-4 text-muted-foreground" />;
    default: return <Circle className="h-4 w-4 text-muted-foreground" />;
  }
}

export default function WorkGroupCard({ 
    group, jobsInGroup, allOperators, allRawMaterials, onProblemClick, onForceFinishClick, onForcePauseClick, onForceCompleteClick, onDissolveGroupClick, onOpenPhaseManager, onOpenMaterialManager, onToggleGuainaClick, onUpdateDeliveryDate, isSelected, onSelect, overallStatus, getOverallStatus, onNavigateToAnalysis, onCopyArticleCode,
}: { 
    group: WorkGroup; jobsInGroup: JobOrder[]; allOperators: Operator[]; allRawMaterials: RawMaterial[]; onProblemClick: () => void; onForceFinishClick: (groupId: string) => void | Promise<void>; onForcePauseClick: (groupId: string, operatorIds: string[]) => void | Promise<void>; onForceCompleteClick: (groupId: string) => void | Promise<void>; onDissolveGroupClick: (groupId: string) => void | Promise<void>; onOpenPhaseManager: (item: JobOrder | WorkGroup) => void; onOpenMaterialManager: (item: JobOrder | WorkGroup) => void; onToggleGuainaClick: (itemId: string, phaseId: string, currentState: 'default' | 'postponed') => void | Promise<void>; onUpdateDeliveryDate: (itemId: string, newDate: string) => void | Promise<void>; isSelected: boolean; onSelect: (groupId: string) => void; overallStatus: OverallStatus; getOverallStatus: (job: JobOrder) => OverallStatus; onNavigateToAnalysis: (articleCode: string) => void; onCopyArticleCode: (articleCode: string) => void;
}) {
  const [isPauseDialogOpen, setIsPauseDialogOpen] = useState(false);
  const [isExplodeViewOpen, setIsExplodeViewOpen] = useState(false);
  const [isBOMDialogOpen, setIsBOMDialogOpen] = useState(false);
  const [selectedOperators, setSelectedOperators] = useState<string[]>([]);
  const hasMatMissing = group.phases.some(p => p.materialStatus === 'missing');

  const syntheticJob: JobOrder = useMemo(() => {
    const firstJob = jobsInGroup[0];
    const baseBOM = firstJob?.billOfMaterials || [];
    
    return { 
        ...group, 
        billOfMaterials: baseBOM,
        qta: group.totalQuantity || 1,
        ordinePF: group.jobOrderPFs?.join(', ') || 'Gruppo',
        postazioneLavoro: 'Multi-Commessa',
        details: group.details || 'Lavorazione Gruppo',
        department: group.department,
        cliente: group.cliente,
        phases: group.phases,
        status: group.status,
        id: group.id,
    } as unknown as JobOrder;
  }, [group, jobsInGroup]);

  const activePhases = useMemo((): ActivePhaseInfo[] => {
    const map = new Map<string, ActivePhaseInfo>();
    group.phases?.forEach(p => {
        if (p.status === 'in-progress') {
            const ops = Array.from(new Map((p.workPeriods || []).filter(wp => wp.end === null).map(wp => { const o = allOperators.find(o => o.id === wp.operatorId); return o ? [o.id, { id: o.id, name: o.nome }] : null; }).filter(Boolean) as any).values()) as any;
            if (ops.length > 0) map.set(p.id, { phaseId: p.id, phaseName: p.name, operators: ops });
        }
    });
    return Array.from(map.values());
  }, [group, allOperators]);

  const progress = group.phases.length > 0 ? (group.phases.filter(p => p.status === 'completed' || p.status === 'skipped').length / group.phases.length) * 100 : 0;
  const isLive = group.phases.some(p => p.status === 'in-progress');
  const guaina = group.phases.find(p => p.name === "Taglio Guaina");
  const firstProd = group.phases.filter(p => p.type === 'production').sort((a,b) => a.sequence - b.sequence)[0];
  const isPostponed = guaina && firstProd && guaina.sequence > firstProd.sequence;

  const deliveryDateString = group.dataConsegnaFinale;
  const deliveryDate = deliveryDateString && /^\d{4}-\d{2}-\d{2}$/.test(deliveryDateString)
    ? parseISO(deliveryDateString)
    : null;
  const isOverdue = deliveryDate && isPast(new Date(deliveryDate.toDateString())) && overallStatus !== 'Completata';

  const validJobsInGroup = useMemo(() => {
      return jobsInGroup.filter(job => !job.id.startsWith('group-'));
  }, [jobsInGroup]);

  return (
    <>
    <Collapsible asChild>
      <Card className={cn("relative flex flex-col h-full bg-card hover:bg-card/90 transition-all duration-300 border-2 border-teal-500/70", (group.isProblemReported || hasMatMissing) && "border-destructive/50", isSelected && "ring-2 ring-primary/50")}>
        <div className="flex-grow">
            <CardHeader className="pb-3 space-y-2">
                <div className="flex justify-between items-center gap-4">
                    <div className="flex items-center gap-3">
                        <Checkbox checked={isSelected} onCheckedChange={() => onSelect(group.id)} />
                        <TooltipProvider><Tooltip><TooltipTrigger><Combine className="h-5 w-5 text-teal-400" /></TooltipTrigger><TooltipContent><p>Gruppo: {group.id}</p></TooltipContent></Tooltip></TooltipProvider>
                        <CollapsibleTrigger asChild><div className="flex items-center gap-2 cursor-pointer group"><CardTitle className="font-headline text-base font-mono">{group.id}</CardTitle><ChevronDown className="h-5 w-5 text-muted-foreground transition-transform duration-200 group-data-[state=open]:-rotate-180" /></div></CollapsibleTrigger>
                    </div>
                    <StatusBadge status={overallStatus} />
                </div>
                <div className="flex justify-between items-center gap-4">
                    <CardDescription className="flex items-center gap-2"><Building className="h-4 w-4 text-muted-foreground" />{group.cliente}</CardDescription>
                    <div className="flex items-center gap-1">
                        <Button variant="ghost" size="icon" className="h-8 w-8" onClick={(e) => { e.stopPropagation(); setIsBOMDialogOpen(true); }}><ClipboardList className="h-4 w-4" /></Button>
                        <DropdownMenu><DropdownMenuTrigger asChild><Button variant="ghost" size="icon" className="h-8 w-8"><MoreVertical className="h-4 w-4" /></Button></DropdownMenuTrigger>
                            <DropdownMenuContent align="end">
                                <DropdownMenuItem onSelect={() => onOpenPhaseManager(group)}><ListOrdered className="mr-2 h-4 w-4" /> Fasi</DropdownMenuItem>
                                <DropdownMenuItem onSelect={() => onOpenMaterialManager(group)}><Boxes className="mr-2 h-4 w-4" /> Materiali</DropdownMenuItem>
                                {guaina && (guaina.status === 'pending' || guaina.status === 'paused') && !group.phases.some(p => p.status === 'in-progress' || p.status === 'paused') && (
                                    <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()}>{isPostponed ? <CornerUpLeft className="mr-2 h-4 w-4" /> : <CornerDownRight className="mr-2 h-4 w-4" />} Sposta Guaina</DropdownMenuItem></AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader><AlertDialogTitle>Conferma Spostamento</AlertDialogTitle></AlertDialogHeader>
                                        <AlertDialogDescription>Spostare la guaina scioglier├á il gruppo. Vuoi continuare?</AlertDialogDescription>
                                        <AlertDialogFooter><AlertDialogCancel>Annulla</AlertDialogCancel><AlertDialogAction onClick={() => onToggleGuainaClick(group.id, guaina.id, isPostponed ? 'postponed' : 'default')}>Conferma</AlertDialogAction></AlertDialogFooter>
                                    </AlertDialogContent></AlertDialog>
                                )}
                                <DropdownMenuSeparator />
                                <DropdownMenuItem onSelect={() => { setSelectedOperators([]); setIsPauseDialogOpen(true); }} disabled={!isLive}><Users className="mr-2 h-4 w-4" /> Forza Pausa</DropdownMenuItem>
                                
                                <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                        <DropdownMenuItem onSelect={e => e.preventDefault()} disabled={!['In Preparazione', 'Pronto per Produzione', 'In Lavorazione'].includes(overallStatus)}>
                                            <FastForward className="mr-2 h-4 w-4" /> Forza Finitura
                                        </DropdownMenuItem>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader><AlertDialogTitle>Confermi l'avanzamento?</AlertDialogTitle></AlertDialogHeader>
                                        <AlertDialogFooter>
                                            <AlertDialogCancel>Annulla</AlertDialogCancel>
                                            <AlertDialogAction onClick={() => onForceFinishClick(group.id)}>Conferma</AlertDialogAction>
                                        </AlertDialogFooter>
                                    </AlertDialogContent>
                                </AlertDialog>

                                <AlertDialog>
                                    <AlertDialogTrigger asChild>
                                        <DropdownMenuItem onSelect={e => e.preventDefault()} disabled={isLive || overallStatus === 'Completata'}>
                                            <PowerOff className="mr-2 h-4 w-4" /> Forza Chiusura
                                        </DropdownMenuItem>
                                    </AlertDialogTrigger>
                                    <AlertDialogContent>
                                        <AlertDialogHeader><AlertDialogTitle>Confermi la chiusura?</AlertDialogTitle></AlertDialogHeader>
                                        <AlertDialogFooter>
                                            <AlertDialogCancel>Annulla</AlertDialogCancel>
                                            <AlertDialogAction onClick={() => onForceCompleteClick(group.id)}>Conferma</AlertDialogAction>
                                        </AlertDialogFooter>
                                    </AlertDialogContent>
                                </AlertDialog>

                                <DropdownMenuSeparator />
                                <AlertDialog><AlertDialogTrigger asChild><DropdownMenuItem onSelect={e => e.preventDefault()} className="text-destructive"><Unlink className="mr-2 h-4 w-4" /> Annulla Gruppo</DropdownMenuItem></AlertDialogTrigger>
                                <AlertDialogContent>
                                    <AlertDialogHeader><AlertDialogTitle>Sei sicuro?</AlertDialogTitle></AlertDialogHeader>
                                    <AlertDialogDescription>Le commesse torneranno individuali.</AlertDialogDescription>
                                    <AlertDialogFooter><AlertDialogCancel>Chiudi</AlertDialogCancel><AlertDialogAction onClick={() => onDissolveGroupClick(group.id)} className="bg-destructive hover:bg-destructive/90">S├¼, annulla</AlertDialogAction></AlertDialogFooter>
                                </AlertDialogContent></AlertDialog>
                            </DropdownMenuContent></DropdownMenu>
                    </div>
                </div>
            </CardHeader>
            <CardContent className="flex-grow space-y-4 pt-0">
                <div className="flex justify-between items-start gap-4 text-sm">
                    <div className="space-y-1">
                        <p className="flex items-center gap-2 text-muted-foreground"><Boxes className="h-4 w-4" />{group.details}</p>
                        
                        <Popover>
                            <PopoverTrigger asChild>
                                <button 
                                    className={cn(
                                        "flex items-center gap-2 font-medium hover:text-primary transition-colors", 
                                        isOverdue ? "text-destructive" : "text-muted-foreground"
                                    )}
                                    onClick={(e) => e.stopPropagation()}
                                >
                                    <Calendar className="h-4 w-4" />
                                    <span>Consegna: {deliveryDate ? format(deliveryDate, 'dd MMM yyyy', { locale: it }) : 'N/D'}</span>
                                </button>
                            </PopoverTrigger>
                            <PopoverContent className="w-auto p-0" align="start">
                                <CalendarPicker
                                    mode="single"
                                    selected={deliveryDate || undefined}
                                    onSelect={(date) => {
                                        if (date) {
                                            onUpdateDeliveryDate(group.id, format(date, 'yyyy-MM-dd'));
                                        }
                                    }}
                                    initialFocus
                                />
                            </PopoverContent>
                        </Popover>
                    </div>
                    <div className="text-right"><span className="font-bold">{group.totalQuantity}</span><span className="text-muted-foreground text-xs ml-1">pz totali</span></div>
                </div>
                {activePhases.length > 0 && (
                  <div className="rounded-lg border-2 border-cyan-400/50 bg-cyan-900/20 p-3 space-y-2 animate-pulse">
                      {activePhases.map(info => (
                          <div key={info.phaseId}><p className="text-xs font-bold text-primary">{info.phaseName}:</p>
                            <div className="flex flex-wrap gap-1 mt-1">{info.operators.map(op => <Badge key={op.id} variant="outline" className="text-[10px] py-0 bg-background"><User className="h-2 w-2 mr-1" />{op.name}</Badge>)}</div>
                          </div>
                      ))}
                  </div>
                )}
            </CardContent>
        </div>
        <CardFooter className="flex-col items-start gap-2 pt-4">
          <div className="w-full"><div className="flex justify-between text-xs text-muted-foreground mb-1"><span>Progresso</span><span>{Math.round(progress)}%</span></div><Progress value={progress} className="h-2" /></div>
        </CardFooter>
        <CollapsibleContent><div className="space-y-2 p-4"><Separator /><h4 className="text-sm font-semibold text-foreground/80 pt-2">Avanzamento Fasi</h4>
            {group.phases?.sort((a,b) => a.sequence - b.sequence).map(p => (
                <div key={p.id} className="flex items-center gap-3 text-sm text-muted-foreground">{getPhaseIcon(p.status)}<span className={cn(p.status === 'skipped' && 'line-through')}>{p.name}</span></div>
            ))}
            <Button variant="secondary" size="sm" className="w-full mt-4" onClick={() => setIsExplodeViewOpen(true)}><View className="mr-2 h-4 w-4" /> Esplodi Commesse ({validJobsInGroup.length})</Button>
        </div></CollapsibleContent>
      </Card></Collapsible>
      
      {isBOMDialogOpen && <BOMDialog isOpen={isBOMDialogOpen} onOpenChange={setIsBOMDialogOpen} job={syntheticJob} allRawMaterials={allRawMaterials} />}

      <Dialog open={isPauseDialogOpen} onOpenChange={setIsPauseDialogOpen}>
          <DialogContent><DialogHeader><DialogTitle>Forza Pausa Operatori</DialogTitle></DialogHeader>
              <div className="py-4 space-y-2">
                  {activePhases.flatMap(p => p.operators).map(op => (
                      <div key={op.id} className="flex items-center space-x-2 p-2 border rounded-md">
                           <Checkbox checked={selectedOperators.includes(op.id)} onCheckedChange={c => setSelectedOperators(prev => c ? [...prev, op.id] : prev.filter(i => i !== op.id))} />
                           <Label className="flex-1 font-semibold">{op.name}</Label>
                      </div>
                  ))}
              </div>
              <DialogFooter><Button variant="outline" onClick={() => setIsPauseDialogOpen(false)}>Annulla</Button><Button onClick={() => { const res = onForcePauseClick(group.id, selectedOperators); if (res instanceof Promise) res.then(() => setIsPauseDialogOpen(false)); else setIsPauseDialogOpen(false); }} disabled={selectedOperators.length === 0}>Conferma</Button></DialogFooter>
          </DialogContent>
      </Dialog>
      
      <Dialog open={isExplodeViewOpen} onOpenChange={setIsExplodeViewOpen}>
          <DialogContent className="max-w-7xl h-[90vh]"><DialogHeader><DialogTitle>Dettaglio Commesse nel Gruppo</DialogTitle></DialogHeader>
              <ScrollArea className="h-full mt-4"><div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                  {validJobsInGroup.map(j => <JobOrderCard key={j.id} jobOrder={j} allRawMaterials={allRawMaterials} groupPhases={group.phases} allOperators={allOperators} onProblemClick={() => {}} onFetchAnalysis={() => {}} isAnalysisLoading={false} onForceFinishClick={() => {}} onRevertForceFinishClick={() => {}} onToggleGuainaClick={() => {}} onRevertPhaseClick={() => {}} onRevertCompletionClick={() => {}} onForcePauseClick={() => {}} onForceCompleteClick={() => {}} onResetJobOrderClick={() => {}} onOpenPhaseManager={() => {}} onOpenMaterialManager={() => {}} onUpdateDeliveryDate={onUpdateDeliveryDate} isSelected={false} onSelect={() => {}} overallStatus={getOverallStatus(j)} onNavigateToAnalysis={onNavigateToAnalysis} onCopyArticleCode={onCopyArticleCode} />)}
              </div></ScrollArea>
          </DialogContent>
      </Dialog>
    </>
  );
}

"use client";

import React, { createContext, useContext, useCallback, ReactNode } from 'react';
import type { ActiveMaterialSessionData, RawMaterialType } from '@/lib/mock-data';
import { useAuth } from '@/components/auth/AuthProvider';
import { updateOperatorMaterialSessions } from '@/app/scan-job/actions';

type MaterialSessionCategory = 'TRECCIA' | 'TUBI' | 'GUAINA';

interface ActiveMaterialSessionContextType {
  activeSessions: ActiveMaterialSessionData[];
  startSession: (sessionData: Omit<ActiveMaterialSessionData, 'category'>, type: RawMaterialType) => void;
  addJobToSession: (materialId: string, lotto: string | null | undefined, job: { jobId: string; jobOrderPF: string }) => void;
  closeSession: (materialId: string, lotto?: string | null) => void;
  getSessionByMaterialId: (materialId: string) => ActiveMaterialSessionData | undefined;
  isLoading: boolean;
}

const ActiveMaterialSessionContext = createContext<ActiveMaterialSessionContextType | undefined>(undefined);

function getMaterialCategory(type: RawMaterialType): MaterialSessionCategory {
  if (type === 'BOB' || type === 'PF3V0') return 'TRECCIA';
  if (type === 'TUBI') return 'TUBI';
  if (type === 'GUAINA') return 'GUAINA';
  console.warn(`Unknown material type received for session category: ${type}`);
  return 'TRECCIA';
}

export const ActiveMaterialSessionProvider = ({ children }: { children: ReactNode }) => {
  const { operator, loading: authLoading } = useAuth();

  // The source of truth for active sessions is now the operator object from AuthProvider
  const activeSessions = operator?.activeMaterialSessions || [];
  const isLoading = authLoading;

  const getSessionByMaterialId = useCallback((materialId: string): ActiveMaterialSessionData | undefined => {
    return activeSessions.find(s => s.materialId === materialId);
  }, [activeSessions]);
  
  const updateSessionsOnServer = useCallback(async (newSessions: ActiveMaterialSessionData[]) => {
      if (!operator) return;
      await updateOperatorMaterialSessions(operator.id, newSessions);
  }, [operator]);

  const startSession = useCallback((sessionData: Omit<ActiveMaterialSessionData, 'category'>, type: RawMaterialType) => {
    const category = getMaterialCategory(type);
    const newSession: ActiveMaterialSessionData = { ...sessionData, category };

    // Blocca solo se esiste gi├á una sessione con STESSO materiale E STESSO lotto per questo operatore.
    if (activeSessions.some(s => s.materialId === newSession.materialId && (s.lotto === newSession.lotto || (!s.lotto && !newSession.lotto)))) {
      console.warn(`Tentativo di avviare una sessione duplicata per materiale ${newSession.materialId} lotto ${newSession.lotto}.`);
      return;
    }

    const updatedSessions = [...activeSessions, newSession];
    updateSessionsOnServer(updatedSessions);
  }, [activeSessions, updateSessionsOnServer]);

  const addJobToSession = useCallback((materialId: string, lotto: string | null | undefined, job: { jobId: string; jobOrderPF: string }) => {
    let hasChanged = false;
    const updatedSessions = activeSessions.map(session => {
        // Identifica la sessione corretta tramite Materiale + Lotto
        if (session.materialId === materialId && (session.lotto === lotto || (!session.lotto && !lotto))) {
            if (session.associatedJobs.some(j => j.jobId === job.jobId)) {
                return session; 
            }
            hasChanged = true;
            return {
                ...session,
                associatedJobs: [...session.associatedJobs, job],
            };
        }
        return session;
    });

    if (hasChanged) {
      updateSessionsOnServer(updatedSessions);
    }
  }, [activeSessions, updateSessionsOnServer]);

  const closeSession = useCallback((materialId: string, lotto?: string | null) => {
    // BUG FIX: Rimuovi solo la sessione che corrisponde a ID E LOTTO
    const updatedSessions = activeSessions.filter(s => 
        !(s.materialId === materialId && (s.lotto === lotto || (!s.lotto && !lotto)))
    );
    updateSessionsOnServer(updatedSessions);
  }, [activeSessions, updateSessionsOnServer]);


  return (
    <ActiveMaterialSessionContext.Provider value={{ activeSessions, startSession, addJobToSession, closeSession, getSessionByMaterialId, isLoading }}>
      {children}
    </ActiveMaterialSessionContext.Provider>
  );
};

export const useActiveMaterialSession = (): ActiveMaterialSessionContextType => {
  const context = useContext(ActiveMaterialSessionContext);
  if (context === undefined) {
    throw new Error('useActiveMaterialSession must be used within an ActiveMaterialSessionProvider');
  }
  return context;
};
